from __future__ import annotations

import re
from pathlib import Path
from typing import Any
from urllib.parse import quote

from fastapi import FastAPI
from fastapi import HTTPException
from fastapi import Request
from fastapi.responses import FileResponse
from fastapi.responses import HTMLResponse
from fastapi.staticfiles import StaticFiles
from fastapi.templating import Jinja2Templates

from app.schemas import EvaluationJobRequest
from app.schemas import FastTextTrainingRequest
from app.schemas import URLRequest
from app.service import AppService


PROJECT_ROOT = Path(__file__).resolve().parents[1]
TEMPLATES_DIR = PROJECT_ROOT / "templates"
STATIC_DIR = PROJECT_ROOT / "static"

service = AppService()
scan_service = service
app = FastAPI(
    title="Fake Brand Login Detector API",
    description="Dataset-first fake brand login detection with FastText scoring and explanation signals.",
)
app.mount("/static", StaticFiles(directory=str(STATIC_DIR)), name="static")
templates = Jinja2Templates(directory=str(TEMPLATES_DIR))


def page_context(request: Request, *, title: str, active_page: str) -> dict[str, Any]:
    return {
        "request": request,
        "title": title,
        "active_page": active_page,
        "nav_items": [
            {"href": "/", "label": "Scan Demo", "id": "scan"},
            {"href": "/dataset", "label": "Dataset & Analysis", "id": "dataset"},
            {"href": "/results", "label": "Results", "id": "results"},
        ],
    }


@app.get("/", response_class=HTMLResponse)
async def home(request: Request):
    return templates.TemplateResponse(
        request,
        "index.html",
        page_context(request, title="Fake Brand Login Detector", active_page="scan"),
    )


@app.get("/dataset", response_class=HTMLResponse)
async def dataset_page(request: Request):
    return templates.TemplateResponse(
        request,
        "dataset.html",
        {
            **page_context(request, title="Dataset & Analysis", active_page="dataset"),
            "dataset_summary": service.dataset_summary(),
            "dataset_recent_rows": service.dataset_recent(limit=10),
        },
    )


@app.get("/evaluate", response_class=HTMLResponse)
async def evaluate_page(request: Request):
    return await dataset_page(request)


@app.get("/results", response_class=HTMLResponse)
async def results_page(request: Request):
    return templates.TemplateResponse(
        request,
        "results.html",
        {
            **page_context(request, title="Results", active_page="results"),
            "model_overview": service.model_overview(),
            "latest_evaluation_report": service.latest_evaluation_report,
        },
    )


@app.get("/ml", response_class=HTMLResponse)
async def ml_page(request: Request):
    return await results_page(request)


@app.post("/scan/combined")
async def scan_combined(request: URLRequest):
    if not request.url.strip():
        raise HTTPException(status_code=400, detail="URL is required.")
    return scan_service.scan_combined(request.url)


@app.get("/dataset/summary")
async def dataset_summary():
    return service.dataset_summary()


@app.get("/dataset/recent")
async def dataset_recent(limit: int = 25):
    return service.dataset_recent(limit=limit)


@app.get("/models/overview")
async def models_overview():
    return service.model_overview()


@app.post("/evaluate")
async def evaluate(request: EvaluationJobRequest):
    if not request.csv_content.strip():
        raise HTTPException(status_code=400, detail="CSV content is required.")
    tmp_dir = service.config.evaluation_dir / "ad_hoc"
    tmp_dir.mkdir(parents=True, exist_ok=True)
    input_path = tmp_dir / f"{Path(request.filename or 'evaluation.csv').stem}_input.csv"
    output_path = tmp_dir / f"{Path(request.filename or 'evaluation.csv').stem}_scored.csv"
    input_path.write_text(request.csv_content, encoding="utf-8")
    report = service.evaluate_csv(input_csv=input_path, output_csv=output_path, threshold=request.threshold)
    eval_root = service.config.evaluation_dir.resolve()
    try:
        output_path.resolve().relative_to(eval_root)
    except ValueError as exc:
        raise HTTPException(
            status_code=500,
            detail="Evaluation output path is outside the configured evaluation directory.",
        ) from exc
    return {
        "report": report,
        "download_url": f"/evaluate/download?file={quote(output_path.name)}",
    }


_EVAL_DOWNLOAD_NAME = re.compile(r"^[A-Za-z0-9._-]+\.csv$")


@app.get("/evaluate/download")
async def evaluate_download(file: str):
    if not file or not _EVAL_DOWNLOAD_NAME.fullmatch(file):
        raise HTTPException(status_code=400, detail="Invalid file name.")
    ad_hoc = (service.config.evaluation_dir / "ad_hoc").resolve()
    file_path = (ad_hoc / file).resolve()
    try:
        if not file_path.is_relative_to(ad_hoc):
            raise HTTPException(status_code=400, detail="Invalid download path.")
    except (ValueError, OSError) as exc:
        raise HTTPException(status_code=400, detail="Invalid download path.") from exc
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="Scored CSV file was not found.")
    if file_path.suffix.lower() != ".csv":
        raise HTTPException(status_code=400, detail="Only CSV downloads are allowed.")
    return FileResponse(file_path, media_type="text/csv", filename=file_path.name)


@app.post("/train/fasttext")
async def train_fasttext(request: FastTextTrainingRequest):
    if not request.csv_content.strip():
        raise HTTPException(status_code=400, detail="CSV content is required.")
    tmp_dir = service.config.evaluation_dir / "training"
    tmp_dir.mkdir(parents=True, exist_ok=True)
    input_path = tmp_dir / f"{Path(request.filename or 'training.csv').stem}_input.csv"
    input_path.write_text(request.csv_content, encoding="utf-8")
    report = service.train_fasttext_from_csv(
        input_csv=input_path,
        run_dir=tmp_dir / "run",
        activate_after_training=request.activate_after_training,
    )
    return report

from __future__ import annotations
from dataclasses import asdict from datetime import datetime, timezone import csv import json from pathlib import Path from typing import Any
from pipeline.evaluation.compare_models import confusion_counts from pipeline.evaluation.compare_models import metrics_from_counts from pipeline.evaluation.rules_baseline import score_rules from pipeline.extraction.html_parser import extract_page_snapshot from pipeline.modeling.fasttext_dataset import corpus_dedup_key from pipeline.modeling.fasttext_dataset import serialize_labeled_snapshot from pipeline.modeling.fasttext_dataset import serialize_snapshot from pipeline.modeling.fasttext_train import FastTextTrainingConfig from pipeline.modeling.fasttext_train import default_training_config from pipeline.modeling.fasttext_train import train_fasttext_model from pipeline.modeling.inference import FastTextDetector from pipeline.shared.config import CapstoneConfig from scanner.dataset_store import BrandLoginDatasetStore from scanner.dataset_store import SnapshotRecord from scanner.domain_age import DomainAgeScanner from scanner.feed_ingest import ThreatFeedCache from scanner.heuristics import URLHeuristics from scanner.ml_features import extract_features from scanner.ml_model import MLScanner from scanner.normalization import normalize_input_url from scanner.settings import ScannerSettings from scanner.ssl_check import SSLValidator from scanner.threat_intel import ThreatIntelScanner
PIPELINE_VERSION = "unified_pipeline_v1"
class AppService: def __init__(self, config: CapstoneConfig | None = None): self.config = config or CapstoneConfig.from_env() self.scanner_settings = ScannerSettings.from_env() self.dataset_store = BrandLoginDatasetStore(self.config.dataset_db_path) self.feed_cache = ThreatFeedCache(self.scanner_settings) self.detector = FastTextDetector(self.config.fasttext_model_path, threshold=self.config.fasttext_threshold) self.structured_ml = MLScanner(self.scanner_settings) self.latest_evaluation_report: dict[str, Any] | None = None
def scan_url(self, raw_url: str, *, persist: bool = True, source: str = "live_scan") -> dict[str, Any]: snapshot = extract_page_snapshot(raw_url, self.scanner_settings) target = normalize_input_url(raw_url) rules = score_rules(snapshot) fasttext_prediction = self.detector.predict_text(serialize_snapshot(snapshot)) legacy_checks = self._run_legacy_checks(target, snapshot) structured_ml = self._run_structured_ml(target, legacy_checks) scores = self._score_components(rules, fasttext_prediction, legacy_checks, structured_ml) verdict = self._build_verdict(scores, rules, fasttext_prediction, structured_ml) override_brand = self._official_domain_override(snapshot) override_applied = False override_reason = "" if override_brand: override_applied = True override_reason = f"official domain match for {override_brand}" scores["final"] = 0.0 verdict = { "status": "ok", "label": "clean", "threshold": float(self.config.final_score_threshold), "final_score": 0.0, "reason": override_reason, "signals": ["official_domain_match"], } elif snapshot.get("free_host") and snapshot.get("brand_mismatch"): override_applied = True override_reason = "free host with brand mismatch" scores["final"] = 100.0 verdict = { "status": "ok", "label": "phishing", "threshold": float(self.config.final_score_threshold), "final_score": 100.0, "reason": override_reason, "signals": ["free_host", "brand_mismatch"], }
fasttext_payload = self._fasttext_payload(fasttext_prediction) checks = self._build_check_map(snapshot, legacy_checks, rules, fasttext_payload, structured_ml) contributing_checks = self._contributing_checks(snapshot, rules, fasttext_payload, legacy_checks, structured_ml) unknown_checks = self._unknown_checks(snapshot, fasttext_payload, legacy_checks, structured_ml)
final_score = float(scores["final"]) result = { "url": snapshot["normalized_url"], "risk_score": round(final_score, 2), "hybrid_score": round(final_score, 2), "prediction": verdict["label"], "verdict": verdict, "scores": scores, "rules": rules, "fasttext": fasttext_payload, "brand_impersonation": snapshot["brand_impersonation"], "details": { **snapshot, "checks": checks, "scores": scores, "verdict": verdict, "rules": rules, "fasttext": fasttext_payload, }, "checks": checks, "contributing_checks": contributing_checks, "unknown_checks": unknown_checks, "feed_freshness": self._feed_freshness(), "override_applied": override_applied, "override_reason": override_reason, "artifacts": { "persisted": False, "record_id": None, "source": source, "pipeline_version": PIPELINE_VERSION, }, }
if persist: record_id = self._persist_scan(snapshot=snapshot, result=result, source=source) result["artifacts"]["persisted"] = True result["artifacts"]["record_id"] = record_id
return result
def scan_combined(self, raw_url: str, *, persist: bool = True) -> dict[str, Any]: return self.scan_url(raw_url, persist=persist, source="api_scan")
def _contributing_checks( self, snapshot: dict[str, Any], rules: dict[str, Any], prediction: dict[str, Any], legacy_checks: dict[str, dict[str, Any]], structured_ml: dict[str, Any], ) -> list[str]: checks: list[str] = [] if snapshot.get("free_host"): checks.append("free_host") if snapshot.get("brand_mismatch"): checks.append("brand_mismatch") if snapshot.get("login_form_present"): checks.append("login_form") if snapshot.get("suspicious_phrase_hits"): checks.append("suspicious_phrases") if float(rules.get("risk_score") or 0) > 0: checks.append("rules") if prediction and prediction.get("status") == "ok": checks.append("fasttext") if structured_ml.get("status") == "ok" and float(structured_ml.get("risk_score") or 0) > 0: checks.append("structured_ml") for name, result in legacy_checks.items(): if result.get("status", "ok") == "ok" and float(result.get("risk_score") or 0) > 0: checks.append(name) return list(dict.fromkeys(checks))
def _unknown_checks( self, snapshot: dict[str, Any], prediction: dict[str, Any], legacy_checks: dict[str, dict[str, Any]], structured_ml: dict[str, Any], ) -> list[str]: unknown: list[str] = [] if not snapshot.get("content", {}).get("content_fetched", True): unknown.append("content") if prediction.get("status") != "ok": unknown.append("fasttext") if structured_ml.get("status") != "ok": unknown.append("structured_ml") for name, result in legacy_checks.items(): if result.get("status", "ok") != "ok": unknown.append(name) return list(dict.fromkeys(unknown))
def _run_legacy_checks(self, target, snapshot: dict[str, Any]) -> dict[str, dict[str, Any]]: content = snapshot.get("content") or {} return { "heuristics": URLHeuristics(target).run_checks(), "content": content, "ssl": SSLValidator(target, self.scanner_settings).run_checks(), "domain_age": DomainAgeScanner(target).run_checks(), "threat_intel": ThreatIntelScanner(target, self.feed_cache).run_checks(), }
def _run_structured_ml(self, target, legacy_checks: dict[str, dict[str, Any]]) -> dict[str, Any]: try: features = extract_features(target, legacy_checks) return self.structured_ml.scan(features) except Exception as exc: return { "status": "unknown", "unknown_reason": "structured_ml_unavailable", "error": str(exc), "risk_score": 0.0, "prediction": "unknown", }
def _score_components( self, rules: dict[str, Any], fasttext_prediction: Any, legacy_checks: dict[str, dict[str, Any]], structured_ml: dict[str, Any], ) -> dict[str, Any]: rules_score = float(rules.get("risk_score") or 0) fasttext_score = self._safe_prediction_score(fasttext_prediction) legacy_score, legacy_contributing, legacy_unknown = self._weighted_legacy_score(legacy_checks) structured_score = float(structured_ml.get("risk_score") or 0) if structured_ml.get("status") == "ok" else None component_values = { "rules": rules_score, "fasttext": fasttext_score, "legacy": legacy_score, "structured_ml": structured_score, } numerator = 0.0 denominator = 0.0 available_components: list[str] = [] weights = { "rules": 0.35, "fasttext": 0.35, "legacy": 0.20, "structured_ml": 0.10, } for name, score in component_values.items(): if score is None: continue available_components.append(name) weight = weights.get(name, 0.0) numerator += float(score) * float(weight) denominator += float(weight) final_score = round(numerator / denominator, 2) if denominator else 0.0 return { "final": final_score, "rules": round(rules_score, 2), "fasttext": round(float(fasttext_score), 2) if fasttext_score is not None else None, "legacy": round(float(legacy_score), 2), "structured_ml": round(float(structured_score), 2) if structured_score is not None else None, "available_components": available_components, "legacy_contributing_checks": legacy_contributing, "legacy_unknown_checks": legacy_unknown, }
def _build_verdict( self, scores: dict[str, Any], rules: dict[str, Any], fasttext_prediction: Any, structured_ml: dict[str, Any], ) -> dict[str, Any]: signals = list(rules.get("reasons") or []) if fasttext_prediction is not None: signals.append(f"FastText score {scores['fasttext']:.2f}") if structured_ml.get("status") == "ok": signals.append(f"Structured ML score {scores['structured_ml']:.2f}") if scores.get("legacy_contributing_checks"): signals.extend(scores["legacy_contributing_checks"]) label = "phishing" if float(scores["final"]) >= float(self.config.final_score_threshold) else "clean" return { "status": "ok" if scores.get("available_components") else "unknown", "label": label, "threshold": float(self.config.final_score_threshold), "final_score": float(scores["final"]), "reason": "; ".join(dict.fromkeys(signals[:8])) or "Composite score", "signals": list(dict.fromkeys(signals[:12])), }
def _build_check_map( self, snapshot: dict[str, Any], legacy_checks: dict[str, dict[str, Any]], rules: dict[str, Any], fasttext_prediction: dict[str, Any], structured_ml: dict[str, Any], ) -> dict[str, dict[str, Any]]: checks = dict(legacy_checks) checks["rules"] = rules checks["fasttext"] = fasttext_prediction checks["structured_ml"] = structured_ml checks["brand_impersonation"] = snapshot.get("brand_impersonation") or {} return checks
def _persist_scan(self, *, snapshot: dict[str, Any], result: dict[str, Any], source: str) -> int: record = SnapshotRecord.create( url=snapshot.get("url") or snapshot.get("normalized_url") or "", normalized_url=snapshot.get("normalized_url") or snapshot.get("url") or "", host=snapshot.get("host") or "", source_feed=source, source_label=str(result.get("prediction") or "unknown"), source_pipeline="app_service", pipeline_version=PIPELINE_VERSION, raw_html=snapshot.get("raw_html", ""), visible_text=snapshot.get("visible_text", ""), page_title=snapshot.get("page_title", ""), detected_brand=snapshot.get("detected_brand", ""), host_provider=snapshot.get("host_provider", ""), risk_score=float(result.get("risk_score") or 0), prediction=str(result.get("prediction") or "unknown"), extraction={ "rules": result.get("rules"), "scores": result.get("scores"), "brand_impersonation": result.get("brand_impersonation"), "checks": result.get("checks"), "feed_freshness": result.get("feed_freshness"), "override_applied": result.get("override_applied"), "override_reason": result.get("override_reason"), }, label=1 if result.get("prediction") == "phishing" else 0 if result.get("prediction") == "clean" else None, notes=str(result.get("verdict", {}).get("reason") or ""), ) return self.dataset_store.add_snapshot(record)
def _fasttext_payload(self, fasttext_prediction: Any) -> dict[str, Any]: if fasttext_prediction is None: return { "status": "unknown", "unknown_reason": "model_unavailable", "risk_score": 0.0, "prediction": "unknown", "probability": 0.0, } return {"status": "ok", **fasttext_prediction.as_dict()}
def _safe_prediction_score(self, fasttext_prediction: Any) -> float | None: if fasttext_prediction is None: return None return float(getattr(fasttext_prediction, "score", 0.0) or 0.0)
def _weighted_legacy_score(self, legacy_checks: dict[str, dict[str, Any]]) -> tuple[float, list[str], list[str]]: weights = { "heuristics": self.scanner_settings.weights_heuristics, "content": self.scanner_settings.weights_content, "ssl": self.scanner_settings.weights_ssl, "domain_age": self.scanner_settings.weights_domain_age, "threat_intel": self.scanner_settings.weights_threat_intel, } numerator = 0.0 denominator = 0.0 contributing: list[str] = [] unknown: list[str] = [] for name, result in legacy_checks.items(): status = result.get("status", "ok") if status != "ok": unknown.append(name) continue weight = float(weights.get(name, 0.0)) if weight <= 0: continue numerator += float(result.get("risk_score") or 0) * weight denominator += weight contributing.append(name) if denominator == 0: return 0.0, contributing, unknown return numerator / denominator, contributing, unknown
def _official_domain_override(self, snapshot: dict[str, Any]) -> str: brand_summary = snapshot.get("brand_impersonation") or {} candidates = brand_summary.get("brand_candidates") or [] for candidate in candidates: if candidate.get("official_domain_match"): return str(candidate.get("brand") or "official_brand") return ""
def _feed_freshness(self) -> dict[str, Any]: metadata = self.feed_cache.metadata() return { "last_refresh_utc": metadata.get("last_refresh_utc"), "refresh_error": metadata.get("refresh_error"), "stale_cache": bool(metadata.get("stale_cache", False)), "refresh_in_progress": bool(metadata.get("refresh_in_progress", False)), "cache_dir": metadata.get("cache_dir"), }
def dataset_summary(self) -> dict[str, Any]: return self.dataset_store.summary()
def dataset_recent(self, limit: int = 25) -> list[dict[str, Any]]: return self.dataset_store.iter_recent(limit=limit)
def export_fasttext_corpus_from_csv(self, input_csv: str | Path, output_path: str | Path) -> dict[str, Any]: input_path = Path(input_csv) rows = self._read_labeled_rows(input_path) lines: list[str] = [] seen_rows: set[str] = set() unique_rows = 0 for row in rows: snapshot = extract_page_snapshot(row["url"], self.scanner_settings) label = "phishing" if row["is_phishing"] else "clean" row_key = corpus_dedup_key(snapshot, label) if row_key in seen_rows: continue seen_rows.add(row_key) lines.append(serialize_labeled_snapshot(snapshot, label)) unique_rows += 1 corpus_path = self.config.fasttext_corpus_path if output_path is None else Path(output_path) corpus_path.parent.mkdir(parents=True, exist_ok=True) corpus_path.write_text("\n".join(lines) + ("\n" if lines else ""), encoding="utf-8") return { "rows": len(rows), "unique_rows": unique_rows, "duplicate_rows": max(len(rows) - unique_rows, 0), "corpus_path": str(corpus_path), }
def train_fasttext_from_csv( self, *, input_csv: str | Path, run_dir: str | Path, activate_after_training: bool = True, ) -> dict[str, Any]: input_path = Path(input_csv) run_path = Path(run_dir) run_path.mkdir(parents=True, exist_ok=True) rows = self._read_labeled_rows(input_path) feature_rows: list[dict[str, Any]] = [] corpus_lines: list[str] = [] seen_rows: set[str] = set() for row in rows: snapshot = extract_page_snapshot(row["url"], self.scanner_settings) label = "phishing" if row["is_phishing"] else "clean" row_key = corpus_dedup_key(snapshot, label) if row_key in seen_rows: continue seen_rows.add(row_key) feature_rows.append( { "url": snapshot["normalized_url"], "label": label, "snapshot": snapshot, } ) corpus_lines.append(serialize_labeled_snapshot(snapshot, label))
corpus_path = run_path / "fasttext_corpus.txt" corpus_path.write_text("\n".join(corpus_lines) + ("\n" if corpus_lines else ""), encoding="utf-8") train_config = default_training_config(self.config) metadata = train_fasttext_model( corpus_path=corpus_path, model_path=run_path / "brand_login.bin", metadata_path=run_path / "brand_login.json", config=train_config, ) if activate_after_training: self.config.fasttext_model_path.parent.mkdir(parents=True, exist_ok=True) self.config.fasttext_metadata_path.parent.mkdir(parents=True, exist_ok=True) self.config.fasttext_model_path.write_bytes((run_path / "brand_login.bin").read_bytes()) self.config.fasttext_metadata_path.write_text((run_path / "brand_login.json").read_text(encoding="utf-8"), encoding="utf-8") self.detector = FastTextDetector(self.config.fasttext_model_path, threshold=self.config.fasttext_threshold)
counts = self._compute_label_counts(feature_rows) return { "summary": { "created_at": utc_now_iso(), "completed_at": utc_now_iso(), "input_rows": len(rows), "usable_rows": len(feature_rows), "duplicate_rows": max(len(rows) - len(feature_rows), 0), "positive_rows": counts["phishing"], "negative_rows": counts["clean"], "model_type": "fasttext", "model_version": metadata["model_version"], "feature_version": metadata["feature_version"], "activated": bool(activate_after_training), }, "artifacts": { "corpus_path": str(corpus_path), "model_path": metadata["model_path"], "metadata_path": str(self.config.fasttext_metadata_path if activate_after_training else run_path / "brand_login.json"), }, "hyperparameters": metadata["hyperparameters"], }
def evaluate_csv(self, *, input_csv: str | Path, output_csv: str | Path, threshold: float | None = None) -> dict[str, Any]: from pipeline.evaluation.evaluate import evaluate_csv, build_report_payload
def scorer(url: str, progress_callback=None): del progress_callback return self.scan_url(url)
result = evaluate_csv( input_csv=input_csv, output_csv=output_csv, scorer=scorer, threshold=float(self.config.final_score_threshold if threshold is None else threshold), ) report = build_report_payload(result) self.latest_evaluation_report = report return report
def model_overview(self) -> dict[str, Any]: available = self.detector.available() metadata = {} if self.config.fasttext_metadata_path.exists(): try: metadata = json.loads(self.config.fasttext_metadata_path.read_text(encoding="utf-8")) except Exception: metadata = {} return { "available": available, "model_path": str(self.config.fasttext_model_path), "metadata_path": str(self.config.fasttext_metadata_path), "metadata": metadata, "threshold": self.config.final_score_threshold, "fasttext_threshold": self.config.fasttext_threshold, "structured_ml": self.structured_ml.analytics(), }
def _read_labeled_rows(self, input_path: Path) -> list[dict[str, Any]]: with input_path.open("r", newline="", encoding="utf-8") as handle: reader = csv.DictReader(handle) rows = [] for row in reader: url = (row.get("url") or "").strip() label_value = str(row.get("is_phishing") or "").strip().lower() if not url: continue rows.append( { "url": url, "is_phishing": label_value in {"1", "true", "t", "yes", "y", "phishing"}, } ) return rows
def _compute_label_counts(self, rows: list[dict[str, Any]]) -> dict[str, int]: counts = {"phishing": 0, "clean": 0} for row in rows: counts[row["label"]] += 1 return counts
def utc_now_iso() -> str: return datetime.now(timezone.utc).isoformat()

from __future__ import annotations
import argparse import csv from collections import Counter from dataclasses import dataclass from dataclasses import field from pathlib import Path from typing import Any from typing import Callable
import requests
DEFAULT_ENDPOINT = "http://localhost:8000/scan/combined" DEFAULT_THRESHOLD = 50.0 DEFAULT_TIMEOUT = 15 CHECK_NAMES = ("heuristics", "content", "ssl", "domain_age", "threat_intel", "ml")
TRUTHY_VALUES = {"1", "true", "t", "yes", "y"} FALSY_VALUES = {"0", "false", "f", "no", "n"}
ProgressCallback = Callable[[dict[str, Any]], None] ScoreFunction = Callable[[str, ProgressCallback | None], dict[str, Any]]
@dataclass class RowEvaluation: index: int url: str actual_is_phishing: bool | None scanned_url: str risk_score: float | None predicted_is_phishing: bool | None matched_ground_truth: bool | None api_error: str = "" contributing_checks: list[str] = field(default_factory=list) unknown_checks: list[str] = field(default_factory=list) details: dict[str, Any] = field(default_factory=dict)
def as_dict(self) -> dict[str, Any]: return { "index": self.index, "url": self.url, "actual_is_phishing": self.actual_is_phishing, "scanned_url": self.scanned_url, "risk_score": self.risk_score, "predicted_is_phishing": self.predicted_is_phishing, "matched_ground_truth": self.matched_ground_truth, "api_error": self.api_error, "contributing_checks": list(self.contributing_checks), "unknown_checks": list(self.unknown_checks), "details": self.details, }
@dataclass class EvaluationResult: total_rows: int scored_rows: int error_rows: int tp: int tn: int fp: int fn: int threshold: float = DEFAULT_THRESHOLD output_csv: str | None = None rows: list[RowEvaluation] = field(default_factory=list)
@property def accuracy(self) -> float: total = self.tp + self.tn + self.fp + self.fn if total == 0: return 0.0 return (self.tp + self.tn) / total
@property def precision(self) -> float: predicted_positive = self.tp + self.fp if predicted_positive == 0: return 0.0 return self.tp / predicted_positive
@property def recall(self) -> float: actual_positive = self.tp + self.fn if actual_positive == 0: return 0.0 return self.tp / actual_positive
@property def f1(self) -> float: precision = self.precision recall = self.recall if precision + recall == 0: return 0.0 return 2 * precision * recall / (precision + recall)
def parse_label(value: Any) -> bool: normalized = str(value).strip().lower() if normalized in TRUTHY_VALUES: return True if normalized in FALSY_VALUES: return False raise ValueError( "Unsupported is_phishing value " f"{value!r}. Expected one of: {sorted(TRUTHY_VALUES | FALSY_VALUES)}" )
def classify_score(risk_score: float, threshold: float) -> bool: return risk_score >= threshold
def build_check_states(default_state: str = "pending") -> dict[str, str]: return {name: default_state for name in CHECK_NAMES}
def score_url( url: str, endpoint: str, timeout: int, session: requests.Session, progress_callback: ProgressCallback | None = None, ) -> dict[str, Any]: del progress_callback response = session.post(endpoint, json={"url": url}, timeout=timeout) response.raise_for_status() payload = response.json() if "risk_score" not in payload: raise ValueError("API response missing 'risk_score'") return payload
def _blank_output_row(source_row: dict[str, Any], threshold: float) -> dict[str, Any]: row_output = dict(source_row) row_output.update( { "api_scanned_url": "", "risk_score": "", "score_threshold": threshold, "predicted_is_phishing": "", "matched_ground_truth": "", "api_error": "", } ) return row_output
def _build_progress_event( *, event_type: str, row_index: int, total_rows: int, processed_rows: int, scored_rows: int, error_rows: int, threshold: float, url: str, check_states: dict[str, str] | None = None, row: RowEvaluation | None = None, **extra: Any, ) -> dict[str, Any]: payload = { "type": event_type, "row_index": row_index, "total_rows": total_rows, "processed_rows": processed_rows, "scored_rows": scored_rows, "error_rows": error_rows, "threshold": threshold, "url": url, "check_states": dict(check_states or {}), } if row is not None: payload["row"] = row.as_dict() payload.update(extra) return payload
def evaluate_csv( input_csv: str | Path, output_csv: str | Path, endpoint: str = DEFAULT_ENDPOINT, threshold: float = DEFAULT_THRESHOLD, timeout: int = DEFAULT_TIMEOUT, session: requests.Session | None = None, scorer: ScoreFunction | None = None, progress_callback: ProgressCallback | None = None, ) -> EvaluationResult: input_path = Path(input_csv) output_path = Path(output_csv)
with input_path.open("r", newline="", encoding="utf-8") as source: reader = csv.DictReader(source) if not reader.fieldnames: raise ValueError("Input CSV is missing a header row")
fieldnames = list(reader.fieldnames) required_columns = {"url", "is_phishing"} missing_columns = required_columns.difference(fieldnames) if missing_columns: missing = ", ".join(sorted(missing_columns)) raise ValueError(f"Input CSV missing required columns: {missing}") input_rows = list(reader)
extra_columns = [ "api_scanned_url", "risk_score", "score_threshold", "predicted_is_phishing", "matched_ground_truth", "api_error", ] output_fieldnames = fieldnames + extra_columns output_path.parent.mkdir(parents=True, exist_ok=True)
client = session or requests.Session() should_close = session is None score_fn = scorer or ( lambda url, row_progress: score_url( url=url, endpoint=endpoint, timeout=timeout, session=client, progress_callback=row_progress, ) )
total_rows = len(input_rows) scored_rows = 0 error_rows = 0 tp = tn = fp = fn = 0 evaluated_rows: list[RowEvaluation] = []
if progress_callback: progress_callback( { "type": "job_started", "total_rows": total_rows, "processed_rows": 0, "scored_rows": 0, "error_rows": 0, "threshold": threshold, } )
try: with output_path.open("w", newline="", encoding="utf-8") as destination: writer = csv.DictWriter(destination, fieldnames=output_fieldnames) writer.writeheader()
for index, row in enumerate(input_rows, start=1): url = (row.get("url") or "").strip() row_output = _blank_output_row(row, threshold) check_states = build_check_states()
if progress_callback: progress_callback( _build_progress_event( event_type="row_started", row_index=index, total_rows=total_rows, processed_rows=len(evaluated_rows), scored_rows=scored_rows, error_rows=error_rows, threshold=threshold, url=url, check_states=check_states, ) )
actual_is_phishing: bool | None = None row_result = RowEvaluation( index=index, url=url, actual_is_phishing=None, scanned_url=url, risk_score=None, predicted_is_phishing=None, matched_ground_truth=None, )
try: if not url: raise ValueError("Missing URL value")
actual_is_phishing = parse_label(row.get("is_phishing"))
def emit_row_progress(event: dict[str, Any]) -> None: event_type = str(event.get("type", "row_progress")) check_name = event.get("check") if event_type == "check_started" and check_name in check_states: check_states[str(check_name)] = "running" elif event_type == "check_completed" and check_name in check_states: result_status = str(event.get("status", "ok")) check_states[str(check_name)] = ( "completed" if result_status == "ok" else "unknown" )
if progress_callback: progress_callback( _build_progress_event( event_type=event_type, row_index=index, total_rows=total_rows, processed_rows=len(evaluated_rows), scored_rows=scored_rows, error_rows=error_rows, threshold=threshold, url=url, check_states=check_states, **{key: value for key, value in event.items() if key != "type"}, ) )
payload = score_fn(url, emit_row_progress) risk_score = float(payload["risk_score"]) predicted_is_phishing = classify_score(risk_score, threshold) matched_ground_truth = predicted_is_phishing == actual_is_phishing contributing_checks = list(payload.get("contributing_checks") or []) unknown_checks = list(payload.get("unknown_checks") or []) details = dict(payload.get("details") or {}) brand_impersonation = payload.get("brand_impersonation") if isinstance(brand_impersonation, dict) and brand_impersonation: details["brand_impersonation"] = brand_impersonation
row_output.update( { "api_scanned_url": payload.get("url", url), "risk_score": f"{risk_score:.2f}", "predicted_is_phishing": str(predicted_is_phishing).lower(), "matched_ground_truth": str(matched_ground_truth).lower(), } )
row_result = RowEvaluation( index=index, url=url, actual_is_phishing=actual_is_phishing, scanned_url=payload.get("url", url), risk_score=risk_score, predicted_is_phishing=predicted_is_phishing, matched_ground_truth=matched_ground_truth, contributing_checks=contributing_checks, unknown_checks=unknown_checks, details=details, )
scored_rows += 1 if predicted_is_phishing and actual_is_phishing: tp += 1 elif not predicted_is_phishing and not actual_is_phishing: tn += 1 elif predicted_is_phishing and not actual_is_phishing: fp += 1 else: fn += 1 except Exception as exc: error_rows += 1 row_output["api_error"] = str(exc) row_result = RowEvaluation( index=index, url=url, actual_is_phishing=actual_is_phishing, scanned_url=url, risk_score=None, predicted_is_phishing=None, matched_ground_truth=None, api_error=str(exc), )
writer.writerow(row_output) evaluated_rows.append(row_result)
if progress_callback: progress_callback( _build_progress_event( event_type="row_completed", row_index=index, total_rows=total_rows, processed_rows=len(evaluated_rows), scored_rows=scored_rows, error_rows=error_rows, threshold=threshold, url=url, check_states=check_states, row=row_result, ) ) finally: if should_close: client.close()
result = EvaluationResult( total_rows=total_rows, scored_rows=scored_rows, error_rows=error_rows, tp=tp, tn=tn, fp=fp, fn=fn, threshold=threshold, output_csv=str(output_path), rows=evaluated_rows, ) if progress_callback: progress_callback( { "type": "job_completed", "total_rows": result.total_rows, "processed_rows": result.total_rows, "scored_rows": result.scored_rows, "error_rows": result.error_rows, "threshold": result.threshold, } ) return result
def build_report_payload(result: EvaluationResult, row_limit: int = 250) -> dict[str, Any]: interesting_rows = sorted( result.rows, key=lambda row: ( 0 if row.api_error else 1, 0 if row.matched_ground_truth is False else 1, -(row.risk_score or 0), row.index, ), )[:row_limit]
score_bins = [ { "label": f"{start}-{start + 9}" if start < 90 else "90-100", "range_start": start, "range_end": 100 if start == 90 else start + 9, "total": 0, "phishing": 0, "legitimate": 0, } for start in range(0, 100, 10) ] unknown_counts: Counter[str] = Counter() contributing_counts: Counter[str] = Counter() error_counts: Counter[str] = Counter()
for row in result.rows: if row.risk_score is not None: bin_index = min(int(row.risk_score // 10), len(score_bins) - 1) bucket = score_bins[bin_index] bucket["total"] += 1 if row.actual_is_phishing is True: bucket["phishing"] += 1 elif row.actual_is_phishing is False: bucket["legitimate"] += 1
contributing_counts.update(row.contributing_checks) unknown_counts.update(row.unknown_checks) if row.api_error: error_counts[row.api_error] += 1
return { "summary": { "total_rows": result.total_rows, "scored_rows": result.scored_rows, "error_rows": result.error_rows, "threshold": result.threshold, "accuracy": round(result.accuracy, 4), "precision": round(result.precision, 4), "recall": round(result.recall, 4), "f1": round(result.f1, 4), }, "confusion_matrix": { "tp": result.tp, "tn": result.tn, "fp": result.fp, "fn": result.fn, }, "score_distribution": score_bins, "check_activity": { "contributing": [ {"check": name, "count": count} for name, count in contributing_counts.most_common() ], "unknown": [ {"check": name, "count": count} for name, count in unknown_counts.most_common() ], }, "errors": [ {"message": message, "count": count} for message, count in error_counts.most_common(8) ], "rows": [row.as_dict() for row in interesting_rows], }
def build_argument_parser() -> argparse.ArgumentParser: parser = argparse.ArgumentParser( description="Evaluate baseline phishing labels against the scanner API." ) parser.add_argument( "input_csv", help="Path to the baseline CSV containing 'url' and 'is_phishing' columns.", ) parser.add_argument( "output_csv", help="Path to write the enriched CSV with score and prediction columns.", ) parser.add_argument( "--endpoint", default=DEFAULT_ENDPOINT, help=f"Combined scan endpoint to call. Default: {DEFAULT_ENDPOINT}", ) parser.add_argument( "--threshold", type=float, default=DEFAULT_THRESHOLD, help=f"Predict phishing when risk_score >= threshold. Default: {DEFAULT_THRESHOLD}", ) parser.add_argument( "--timeout", type=int, default=DEFAULT_TIMEOUT, help=f"Per-request timeout in seconds. Default: {DEFAULT_TIMEOUT}", ) return parser
def print_summary(result: EvaluationResult) -> None: print("Evaluation complete") print(f"total_rows: {result.total_rows}") print(f"scored_rows: {result.scored_rows}") print(f"error_rows: {result.error_rows}") print(f"TP: {result.tp}") print(f"TN: {result.tn}") print(f"FP: {result.fp}") print(f"FN: {result.fn}") print(f"accuracy: {result.accuracy:.4f}") print(f"precision: {result.precision:.4f}") print(f"recall: {result.recall:.4f}") print(f"f1: {result.f1:.4f}")
def main() -> int: args = build_argument_parser().parse_args() result = evaluate_csv( input_csv=args.input_csv, output_csv=args.output_csv, endpoint=args.endpoint, threshold=args.threshold, timeout=args.timeout, ) print_summary(result) return 0
if __name__ == "__main__": raise SystemExit(main())

#!/usr/bin/env bash # # install.sh -- Install The Agency agents into your local agentic tool(s). # # Reads converted files from integrations/ and copies them to the appropriate # config directory for each tool. Run scripts/convert.sh first if integrations/ # is missing or stale. # # Usage: # ./scripts/install.sh [--tool <name>] [--interactive] [--no-interactive] [--parallel] [--jobs N] [--help] # # Tools: # claude-code -- Copy agents to ~/.claude/agents/ # copilot -- Copy agents to ~/.github/agents/ and ~/.copilot/agents/ # antigravity -- Copy skills to ~/.gemini/antigravity/skills/ # gemini-cli -- Install extension to ~/.gemini/extensions/agency-agents/ # opencode -- Copy agents to .opencode/agent/ in current directory # cursor -- Copy rules to .cursor/rules/ in current directory # aider -- Copy CONVENTIONS.md to current directory # windsurf -- Copy .windsurfrules to current directory # openclaw -- Copy workspaces to ~/.openclaw/agency-agents/ # qwen -- Copy SubAgents to ~/.qwen/agents/ (user-wide) or .qwen/agents/ (project) # all -- Install for all detected tools (default) # # Flags: # --tool <name> Install only the specified tool # --interactive Show interactive selector (default when run in a terminal) # --no-interactive Skip interactive selector, install all detected tools # --parallel Run install for each selected tool in parallel (output order may vary) # --jobs N Max parallel jobs when using --parallel (default: nproc or 4) # --help Show this help # # Platform support: # Linux, macOS (requires bash 3.2+), Windows Git Bash / WSL
set -euo pipefail
# --------------------------------------------------------------------------- # Colours -- only when stdout supports color # --------------------------------------------------------------------------- if [[ -t 1 && -z "${NO_COLOR:-}" && "${TERM:-}" != "dumb" ]]; then C_GREEN=$'\033[0;32m' C_YELLOW=$'\033[1;33m' C_RED=$'\033[0;31m' C_CYAN=$'\033[0;36m' C_BOLD=$'\033[1m' C_DIM=$'\033[2m' C_RESET=$'\033[0m' else C_GREEN=''; C_YELLOW=''; C_RED=''; C_CYAN=''; C_BOLD=''; C_DIM=''; C_RESET='' fi
ok() { printf "${C_GREEN}[OK]${C_RESET} %s\n" "$*"; } warn() { printf "${C_YELLOW}[!!]${C_RESET} %s\n" "$*"; } err() { printf "${C_RED}[ERR]${C_RESET} %s\n" "$*" >&2; } header() { printf "\n${C_BOLD}%s${C_RESET}\n" "$*"; } dim() { printf "${C_DIM}%s${C_RESET}\n" "$*"; }
# Progress bar: [=======> ] 3/8 (tqdm-style) progress_bar() { local current="$1" total="$2" width="${3:-20}" i filled empty (( total > 0 )) || return filled=$(( width * current / total )) empty=$(( width - filled )) printf "\r [" for (( i=0; i<filled; i++ )); do printf "="; done if (( filled < width )); then printf ">"; (( empty-- )); fi for (( i=0; i<empty; i++ )); do printf " "; done printf "] %s/%s" "$current" "$total" [[ -t 1 ]] || printf "\n" }
# --------------------------------------------------------------------------- # Box drawing -- pure ASCII, fixed 52-char wide # box_top / box_mid / box_bot -- structural lines # box_row <text> -- content row, right-padded to fit # --------------------------------------------------------------------------- BOX_INNER=48 # chars between the two | walls
box_top() { printf " +"; printf '%0.s-' $(seq 1 $BOX_INNER); printf "+\n"; } box_bot() { box_top; } box_sep() { printf " |"; printf '%0.s-' $(seq 1 $BOX_INNER); printf "|\n"; } strip_ansi() { awk '{ gsub(/\033\[[0-9;]*m/, ""); print }' <<< "$1" } box_row() { # Strip ANSI escapes when measuring visible length local raw="$1" local visible visible="$(strip_ansi "$raw")" local pad=$(( BOX_INNER - 2 - ${#visible} )) if (( pad < 0 )); then pad=0; fi printf " | %s%*s |\n" "$raw" "$pad" '' } box_blank() { printf " |%*s|\n" $BOX_INNER ''; }
# --------------------------------------------------------------------------- # Paths # --------------------------------------------------------------------------- SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)" REPO_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)" INTEGRATIONS="$REPO_ROOT/integrations"
ALL_TOOLS=(claude-code copilot antigravity gemini-cli opencode openclaw cursor aider windsurf qwen)
# --------------------------------------------------------------------------- # Usage # --------------------------------------------------------------------------- usage() { sed -n '3,32p' "$0" | sed 's/^# \{0,1\}//' exit 0 }
# Default parallel job count (nproc on Linux; sysctl on macOS when nproc missing) parallel_jobs_default() { local n n=$(nproc 2>/dev/null) && [[ -n "$n" ]] && echo "$n" && return n=$(sysctl -n hw.ncpu 2>/dev/null) && [[ -n "$n" ]] && echo "$n" && return echo 4 }
# --------------------------------------------------------------------------- # Preflight # --------------------------------------------------------------------------- check_integrations() { if [[ ! -d "$INTEGRATIONS" ]]; then err "integrations/ not found. Run ./scripts/convert.sh first." exit 1 fi }
# --------------------------------------------------------------------------- # Tool detection # --------------------------------------------------------------------------- detect_claude_code() { [[ -d "${HOME}/.claude" ]]; } detect_copilot() { command -v code >/dev/null 2>&1 || [[ -d "${HOME}/.github" || -d "${HOME}/.copilot" ]]; } detect_antigravity() { [[ -d "${HOME}/.gemini/antigravity/skills" ]]; } detect_gemini_cli() { command -v gemini >/dev/null 2>&1 || [[ -d "${HOME}/.gemini" ]]; } detect_cursor() { command -v cursor >/dev/null 2>&1 || [[ -d "${HOME}/.cursor" ]]; } detect_opencode() { command -v opencode >/dev/null 2>&1 || [[ -d "${HOME}/.config/opencode" ]]; } detect_aider() { command -v aider >/dev/null 2>&1; } detect_openclaw() { command -v openclaw >/dev/null 2>&1 || [[ -d "${HOME}/.openclaw" ]]; } detect_windsurf() { command -v windsurf >/dev/null 2>&1 || [[ -d "${HOME}/.codeium" ]]; } detect_qwen() { command -v qwen >/dev/null 2>&1 || [[ -d "${HOME}/.qwen" ]]; }
is_detected() { case "$1" in claude-code) detect_claude_code ;; copilot) detect_copilot ;; antigravity) detect_antigravity ;; gemini-cli) detect_gemini_cli ;; opencode) detect_opencode ;; openclaw) detect_openclaw ;; cursor) detect_cursor ;; aider) detect_aider ;; windsurf) detect_windsurf ;; qwen) detect_qwen ;; *) return 1 ;; esac }
# Fixed-width labels: name (14) + detail (24) = 38 visible chars tool_label() { case "$1" in claude-code) printf "%-14s %s" "Claude Code" "(claude.ai/code)" ;; copilot) printf "%-14s %s" "Copilot" "(~/.github + ~/.copilot)" ;; antigravity) printf "%-14s %s" "Antigravity" "(~/.gemini/antigravity)" ;; gemini-cli) printf "%-14s %s" "Gemini CLI" "(gemini extension)" ;; opencode) printf "%-14s %s" "OpenCode" "(opencode.ai)" ;; openclaw) printf "%-14s %s" "OpenClaw" "(~/.openclaw)" ;; cursor) printf "%-14s %s" "Cursor" "(.cursor/rules)" ;; aider) printf "%-14s %s" "Aider" "(CONVENTIONS.md)" ;; windsurf) printf "%-14s %s" "Windsurf" "(.windsurfrules)" ;; qwen) printf "%-14s %s" "Qwen Code" "(~/.qwen/agents)" ;; esac }
# --------------------------------------------------------------------------- # Interactive selector # --------------------------------------------------------------------------- interactive_select() { # bash 3-compatible arrays declare -a selected=() declare -a detected_map=()
local t for t in "${ALL_TOOLS[@]}"; do if is_detected "$t" 2>/dev/null; then selected+=(1); detected_map+=(1) else selected+=(0); detected_map+=(0) fi done
while true; do # --- header --- printf "\n" box_top box_row "${C_BOLD} The Agency -- Tool Installer${C_RESET}" box_bot printf "\n" printf " ${C_DIM}System scan: [*] = detected on this machine${C_RESET}\n" printf "\n"
# --- tool rows --- local i=0 for t in "${ALL_TOOLS[@]}"; do local num=$(( i + 1 )) local label label="$(tool_label "$t")" local dot if [[ "${detected_map[$i]}" == "1" ]]; then dot="${C_GREEN}[*]${C_RESET}" else dot="${C_DIM}[ ]${C_RESET}" fi local chk if [[ "${selected[$i]}" == "1" ]]; then chk="${C_GREEN}[x]${C_RESET}" else chk="${C_DIM}[ ]${C_RESET}" fi printf " %s %s) %s %s\n" "$chk" "$num" "$dot" "$label" (( i++ )) || true done
# --- controls --- printf "\n" printf " ------------------------------------------------\n" printf " ${C_CYAN}[1-%s]${C_RESET} toggle ${C_CYAN}[a]${C_RESET} all ${C_CYAN}[n]${C_RESET} none ${C_CYAN}[d]${C_RESET} detected\n" "${#ALL_TOOLS[@]}" printf " ${C_GREEN}[Enter]${C_RESET} install ${C_RED}[q]${C_RESET} quit\n" printf "\n" printf " >> " read -r input </dev/tty
case "$input" in q|Q) printf "\n"; ok "Aborted."; exit 0 ;; a|A) for (( j=0; j<${#ALL_TOOLS[@]}; j++ )); do selected[$j]=1; done ;; n|N) for (( j=0; j<${#ALL_TOOLS[@]}; j++ )); do selected[$j]=0; done ;; d|D) for (( j=0; j<${#ALL_TOOLS[@]}; j++ )); do selected[$j]="${detected_map[$j]}"; done ;; "") local any=false local s for s in "${selected[@]}"; do [[ "$s" == "1" ]] && any=true && break; done if $any; then break else printf " ${C_YELLOW}Nothing selected -- pick a tool or press q to quit.${C_RESET}\n" sleep 1 fi ;; *) local toggled=false local num for num in $input; do if [[ "$num" =~ ^[0-9]+$ ]]; then local idx=$(( num - 1 )) if (( idx >= 0 && idx < ${#ALL_TOOLS[@]} )); then if [[ "${selected[$idx]}" == "1" ]]; then selected[$idx]=0 else selected[$idx]=1 fi toggled=true fi fi done if ! $toggled; then printf " ${C_RED}Invalid. Enter a number 1-%s, or a command.${C_RESET}\n" "${#ALL_TOOLS[@]}" sleep 1 fi ;; esac
# Clear UI for redraw local lines=$(( ${#ALL_TOOLS[@]} + 14 )) local l for (( l=0; l<lines; l++ )); do printf '\033[1A\033[2K'; done done
# Build output array SELECTED_TOOLS=() local i=0 for t in "${ALL_TOOLS[@]}"; do [[ "${selected[$i]}" == "1" ]] && SELECTED_TOOLS+=("$t") (( i++ )) || true done }
# --------------------------------------------------------------------------- # Installers # ---------------------------------------------------------------------------
install_claude_code() { local dest="${HOME}/.claude/agents" local count=0 mkdir -p "$dest" local dir f first_line for dir in academic design engineering game-development marketing paid-media sales product project-management \ testing support spatial-computing specialized; do [[ -d "$REPO_ROOT/$dir" ]] || continue while IFS= read -r -d '' f; do first_line="$(head -1 "$f")" [[ "$first_line" == "---" ]] || continue cp "$f" "$dest/" (( count++ )) || true done < <(find "$REPO_ROOT/$dir" -name "*.md" -type f -print0) done ok "Claude Code: $count agents -> $dest" }
install_copilot() { local dest_github="${HOME}/.github/agents" local dest_copilot="${HOME}/.copilot/agents" local count=0 mkdir -p "$dest_github" "$dest_copilot" local dir f first_line for dir in academic design engineering game-development marketing paid-media sales product project-management \ testing support spatial-computing specialized; do [[ -d "$REPO_ROOT/$dir" ]] || continue while IFS= read -r -d '' f; do first_line="$(head -1 "$f")" [[ "$first_line" == "---" ]] || continue cp "$f" "$dest_github/" cp "$f" "$dest_copilot/" (( count++ )) || true done < <(find "$REPO_ROOT/$dir" -name "*.md" -type f -print0) done ok "Copilot: $count agents -> $dest_github" ok "Copilot: $count agents -> $dest_copilot" }
install_antigravity() { local src="$INTEGRATIONS/antigravity" local dest="${HOME}/.gemini/antigravity/skills" local count=0 [[ -d "$src" ]] || { err "integrations/antigravity missing. Run convert.sh first."; return 1; } mkdir -p "$dest" local d while IFS= read -r -d '' d; do local name; name="$(basename "$d")" mkdir -p "$dest/$name" cp "$d/SKILL.md" "$dest/$name/SKILL.md" (( count++ )) || true done < <(find "$src" -mindepth 1 -maxdepth 1 -type d -print0) ok "Antigravity: $count skills -> $dest" }
install_gemini_cli() { local src="$INTEGRATIONS/gemini-cli" local dest="${HOME}/.gemini/extensions/agency-agents" local count=0 local manifest="$src/gemini-extension.json" local skills_dir="$src/skills" [[ -d "$src" ]] || { err "integrations/gemini-cli missing. Run ./scripts/convert.sh --tool gemini-cli first."; return 1; } [[ -f "$manifest" ]] || { err "integrations/gemini-cli/gemini-extension.json missing. Run ./scripts/convert.sh --tool gemini-cli first."; return 1; } [[ -d "$skills_dir" ]] || { err "integrations/gemini-cli/skills missing. Run ./scripts/convert.sh --tool gemini-cli first."; return 1; } mkdir -p "$dest/skills" cp "$manifest" "$dest/gemini-extension.json" local d while IFS= read -r -d '' d; do local name; name="$(basename "$d")" mkdir -p "$dest/skills/$name" cp "$d/SKILL.md" "$dest/skills/$name/SKILL.md" (( count++ )) || true done < <(find "$skills_dir" -mindepth 1 -maxdepth 1 -type d -print0) ok "Gemini CLI: $count skills -> $dest" }
install_opencode() { local src="$INTEGRATIONS/opencode/agents" local dest="${PWD}/.opencode/agents" local count=0 [[ -d "$src" ]] || { err "integrations/opencode missing. Run convert.sh first."; return 1; } mkdir -p "$dest" local f while IFS= read -r -d '' f; do cp "$f" "$dest/"; (( count++ )) || true done < <(find "$src" -maxdepth 1 -name "*.md" -print0) ok "OpenCode: $count agents -> $dest" warn "OpenCode: project-scoped. Run from your project root to install there." }
install_openclaw() { local src="$INTEGRATIONS/openclaw" local dest="${HOME}/.openclaw/agency-agents" local count=0 [[ -d "$src" ]] || { err "integrations/openclaw missing. Run convert.sh first."; return 1; } mkdir -p "$dest" local d while IFS= read -r -d '' d; do local name; name="$(basename "$d")" mkdir -p "$dest/$name" cp "$d/SOUL.md" "$dest/$name/SOUL.md" cp "$d/AGENTS.md" "$dest/$name/AGENTS.md" cp "$d/IDENTITY.md" "$dest/$name/IDENTITY.md" # Register with OpenClaw so agents are usable by agentId immediately if command -v openclaw >/dev/null 2>&1; then openclaw agents add "$name" --workspace "$dest/$name" --non-interactive || true fi (( count++ )) || true done < <(find "$src" -mindepth 1 -maxdepth 1 -type d -print0) ok "OpenClaw: $count workspaces -> $dest" if command -v openclaw >/dev/null 2>&1; then warn "OpenClaw: run 'openclaw gateway restart' to activate new agents" fi }
install_cursor() { local src="$INTEGRATIONS/cursor/rules" local dest="${PWD}/.cursor/rules" local count=0 [[ -d "$src" ]] || { err "integrations/cursor missing. Run convert.sh first."; return 1; } mkdir -p "$dest" local f while IFS= read -r -d '' f; do cp "$f" "$dest/"; (( count++ )) || true done < <(find "$src" -maxdepth 1 -name "*.mdc" -print0) ok "Cursor: $count rules -> $dest" warn "Cursor: project-scoped. Run from your project root to install there." }
install_aider() { local src="$INTEGRATIONS/aider/CONVENTIONS.md" local dest="${PWD}/CONVENTIONS.md" [[ -f "$src" ]] || { err "integrations/aider/CONVENTIONS.md missing. Run convert.sh first."; return 1; } if [[ -f "$dest" ]]; then warn "Aider: CONVENTIONS.md already exists at $dest (remove to reinstall)." return 0 fi cp "$src" "$dest" ok "Aider: installed -> $dest" warn "Aider: project-scoped. Run from your project root to install there." }
install_windsurf() { local src="$INTEGRATIONS/windsurf/.windsurfrules" local dest="${PWD}/.windsurfrules" [[ -f "$src" ]] || { err "integrations/windsurf/.windsurfrules missing. Run convert.sh first."; return 1; } if [[ -f "$dest" ]]; then warn "Windsurf: .windsurfrules already exists at $dest (remove to reinstall)." return 0 fi cp "$src" "$dest" ok "Windsurf: installed -> $dest" warn "Windsurf: project-scoped. Run from your project root to install there." }
install_qwen() { local src="$INTEGRATIONS/qwen/agents" local dest="${PWD}/.qwen/agents" local count=0
[[ -d "$src" ]] || { err "integrations/qwen missing. Run convert.sh first."; return 1; }
mkdir -p "$dest"
local f while IFS= read -r -d '' f; do cp "$f" "$dest/" (( count++ )) || true done < <(find "$src" -maxdepth 1 -name "*.md" -print0)
ok "Qwen Code: installed $count agents to $dest" warn "Qwen Code: project-scoped. Run from your project root to install there." warn "Tip: Run '/agents manage' in Qwen Code to refresh, or restart session" }
install_tool() { case "$1" in claude-code) install_claude_code ;; copilot) install_copilot ;; antigravity) install_antigravity ;; gemini-cli) install_gemini_cli ;; opencode) install_opencode ;; openclaw) install_openclaw ;; cursor) install_cursor ;; aider) install_aider ;; windsurf) install_windsurf ;; qwen) install_qwen ;; esac }
# --------------------------------------------------------------------------- # Entry point # --------------------------------------------------------------------------- main() { local tool="all" local interactive_mode="auto" local use_parallel=false local parallel_jobs parallel_jobs="$(parallel_jobs_default)"
while [[ $# -gt 0 ]]; do case "$1" in --tool) tool="${2:?'--tool requires a value'}"; shift 2; interactive_mode="no" ;; --interactive) interactive_mode="yes"; shift ;; --no-interactive) interactive_mode="no"; shift ;; --parallel) use_parallel=true; shift ;; --jobs) parallel_jobs="${2:?'--jobs requires a value'}"; shift 2 ;; --help|-h) usage ;; *) err "Unknown option: $1"; usage ;; esac done
check_integrations
# Validate explicit tool if [[ "$tool" != "all" ]]; then local valid=false t for t in "${ALL_TOOLS[@]}"; do [[ "$t" == "$tool" ]] && valid=true && break; done if ! $valid; then err "Unknown tool '$tool'. Valid: ${ALL_TOOLS[*]}" exit 1 fi fi
# Decide whether to show interactive UI local use_interactive=false if [[ "$interactive_mode" == "yes" ]]; then use_interactive=true elif [[ "$interactive_mode" == "auto" && -t 0 && -t 1 && "$tool" == "all" ]]; then use_interactive=true fi
SELECTED_TOOLS=()
if $use_interactive; then interactive_select
elif [[ "$tool" != "all" ]]; then SELECTED_TOOLS=("$tool")
else # Non-interactive: auto-detect header "The Agency -- Scanning for installed tools..." printf "\n" local t for t in "${ALL_TOOLS[@]}"; do if is_detected "$t" 2>/dev/null; then SELECTED_TOOLS+=("$t") printf " ${C_GREEN}[*]${C_RESET} %s ${C_DIM}detected${C_RESET}\n" "$(tool_label "$t")" else printf " ${C_DIM}[ ] %s not found${C_RESET}\n" "$(tool_label "$t")" fi done fi
if [[ ${#SELECTED_TOOLS[@]} -eq 0 ]]; then warn "No tools selected or detected. Nothing to install." printf "\n" dim " Tip: use --tool <name> to force-install a specific tool." dim " Available: ${ALL_TOOLS[*]}" exit 0 fi
# When parent runs install.sh --parallel, it spawns workers with AGENCY_INSTALL_WORKER=1 # so each worker only runs install_tool(s) and skips header/done box (avoids duplicate output). if [[ -n "${AGENCY_INSTALL_WORKER:-}" ]]; then local t for t in "${SELECTED_TOOLS[@]}"; do install_tool "$t" done return 0 fi
printf "\n" header "The Agency -- Installing agents" printf " Repo: %s\n" "$REPO_ROOT" local n_selected=${#SELECTED_TOOLS[@]} printf " Installing: %s\n" "${SELECTED_TOOLS[*]}" if $use_parallel; then ok "Installing $n_selected tools in parallel (output buffered per tool)." fi printf "\n"
local installed=0 t i=0 if $use_parallel; then local install_out_dir install_out_dir="$(mktemp -d)" export AGENCY_INSTALL_OUT_DIR="$install_out_dir" export AGENCY_INSTALL_SCRIPT="$SCRIPT_DIR/install.sh" printf '%s\n' "${SELECTED_TOOLS[@]}" | xargs -P "$parallel_jobs" -I {} sh -c 'AGENCY_INSTALL_WORKER=1 "$AGENCY_INSTALL_SCRIPT" --tool "{}" --no-interactive > "$AGENCY_INSTALL_OUT_DIR/{}" 2>&1' for t in "${SELECTED_TOOLS[@]}"; do [[ -f "$install_out_dir/$t" ]] && cat "$install_out_dir/$t" done rm -rf "$install_out_dir" installed=$n_selected else for t in "${SELECTED_TOOLS[@]}"; do (( i++ )) || true progress_bar "$i" "$n_selected" printf "\n" printf " ${C_DIM}[%s/%s]${C_RESET} %s\n" "$i" "$n_selected" "$t" install_tool "$t" (( installed++ )) || true done fi
# Done box local msg=" Done! Installed $installed tool(s)." printf "\n" box_top box_row "${C_GREEN}${C_BOLD}${msg}${C_RESET}" box_bot printf "\n" dim " Run ./scripts/convert.sh to regenerate after adding or editing agents." printf "\n" }
main "$@"

from __future__ import annotations

from typing import Any


def confusion_counts(rows: list[dict[str, Any]], *, actual_key: str, predicted_key: str) -> dict[str, int]:
    tp = tn = fp = fn = 0
    for row in rows:
        actual = str(row.get(actual_key)).strip().lower() in {"1", "true", "phishing", "yes"}
        predicted = str(row.get(predicted_key)).strip().lower() in {"1", "true", "phishing", "yes"}
        if actual and predicted:
            tp += 1
        elif not actual and not predicted:
            tn += 1
        elif predicted and not actual:
            fp += 1
        else:
            fn += 1
    return {"tp": tp, "tn": tn, "fp": fp, "fn": fn}


def metrics_from_counts(counts: dict[str, int]) -> dict[str, float]:
    tp = counts["tp"]
    tn = counts["tn"]
    fp = counts["fp"]
    fn = counts["fn"]
    total = tp + tn + fp + fn
    precision = tp / (tp + fp) if tp + fp else 0.0
    recall = tp / (tp + fn) if tp + fn else 0.0
    f1 = (2 * precision * recall / (precision + recall)) if precision + recall else 0.0
    accuracy = (tp + tn) / total if total else 0.0
    return {
        "accuracy": round(accuracy, 4),
        "precision": round(precision, 4),
        "recall": round(recall, 4),
        "f1": round(f1, 4),
    }

from __future__ import annotations
import csv from dataclasses import dataclass, field from pathlib import Path from typing import Any from typing import Callable
ProgressCallback = Callable[[dict[str, Any]], None] ScoreFunction = Callable[[str, ProgressCallback | None], dict[str, Any]]
@dataclass class EvaluationRow: index: int url: str actual_is_phishing: bool | None scanned_url: str risk_score: float | None predicted_is_phishing: bool | None matched_ground_truth: bool | None prediction_label: str = "" score_breakdown: dict[str, Any] = field(default_factory=dict) api_error: str = "" details: dict[str, Any] = field(default_factory=dict)
@dataclass class EvaluationResult: total_rows: int scored_rows: int error_rows: int tp: int tn: int fp: int fn: int rows: list[EvaluationRow] = field(default_factory=list)
@property def accuracy(self) -> float: total = self.tp + self.tn + self.fp + self.fn return (self.tp + self.tn) / total if total else 0.0
@property def precision(self) -> float: denom = self.tp + self.fp return self.tp / denom if denom else 0.0
@property def recall(self) -> float: denom = self.tp + self.fn return self.tp / denom if denom else 0.0
@property def f1(self) -> float: precision = self.precision recall = self.recall return (2 * precision * recall / (precision + recall)) if precision + recall else 0.0
def parse_label(value: Any) -> bool: normalized = str(value).strip().lower() if normalized in {"1", "true", "t", "yes", "y", "phishing"}: return True if normalized in {"0", "false", "f", "no", "n", "clean"}: return False raise ValueError(f"Unsupported label value: {value!r}")
def evaluate_csv( input_csv: str | Path, output_csv: str | Path, *, scorer: ScoreFunction, threshold: float = 30.0, progress_callback: ProgressCallback | None = None, ) -> EvaluationResult: input_path = Path(input_csv) output_path = Path(output_csv) with input_path.open("r", newline="", encoding="utf-8") as handle: reader = csv.DictReader(handle) if not reader.fieldnames: raise ValueError("Input CSV is missing a header row") if "url" not in reader.fieldnames or "is_phishing" not in reader.fieldnames: raise ValueError("Input CSV missing required columns: url, is_phishing") rows = list(reader)
output_path.parent.mkdir(parents=True, exist_ok=True) fieldnames = list(reader.fieldnames) + [ "risk_score", "final_score", "rules_score", "fasttext_score", "legacy_score", "structured_ml_score", "prediction", "verdict", "predicted_is_phishing", "matched_ground_truth", "api_error", ] total_rows = len(rows) scored_rows = 0 error_rows = 0 tp = tn = fp = fn = 0 output_rows: list[EvaluationRow] = [] with output_path.open("w", newline="", encoding="utf-8") as handle: writer = csv.DictWriter(handle, fieldnames=fieldnames) writer.writeheader() for index, row in enumerate(rows, start=1): url = (row.get("url") or "").strip() actual = parse_label(row.get("is_phishing")) row_output = dict(row) try: payload = scorer(url, progress_callback) scores = dict(payload.get("scores") or {}) final_value = scores.get("final") if final_value is None: final_value = payload.get("risk_score") final_score = float(final_value or 0) rules_score = scores.get("rules") fasttext_score = scores.get("fasttext") legacy_score = scores.get("legacy") structured_ml_score = scores.get("structured_ml") prediction_label = str(payload.get("prediction") or payload.get("verdict", {}).get("label") or "unknown") predicted = final_score >= threshold matched = predicted == actual row_output.update( { "risk_score": f"{final_score:.2f}", "final_score": f"{final_score:.2f}", "rules_score": "" if rules_score is None else f"{float(rules_score):.2f}", "fasttext_score": "" if fasttext_score is None else f"{float(fasttext_score):.2f}", "legacy_score": "" if legacy_score is None else f"{float(legacy_score):.2f}", "structured_ml_score": "" if structured_ml_score is None else f"{float(structured_ml_score):.2f}", "prediction": prediction_label, "verdict": str((payload.get("verdict") or {}).get("status") or ""), "predicted_is_phishing": str(predicted).lower(), "matched_ground_truth": str(matched).lower(), "api_error": "", } ) output_rows.append( EvaluationRow( index=index, url=url, actual_is_phishing=actual, scanned_url=str(payload.get("url") or url), risk_score=final_score, predicted_is_phishing=predicted, matched_ground_truth=matched, prediction_label=prediction_label, score_breakdown={ "final": final_score, "rules": rules_score, "fasttext": fasttext_score, "legacy": legacy_score, "structured_ml": structured_ml_score, }, details=payload, ) ) scored_rows += 1 if actual and predicted: tp += 1 elif not actual and not predicted: tn += 1 elif predicted and not actual: fp += 1 else: fn += 1 except Exception as exc: error_rows += 1 row_output.update( { "risk_score": "", "final_score": "", "rules_score": "", "fasttext_score": "", "legacy_score": "", "structured_ml_score": "", "prediction": "", "verdict": "", "predicted_is_phishing": "", "matched_ground_truth": "", "api_error": str(exc), } ) output_rows.append( EvaluationRow( index=index, url=url, actual_is_phishing=actual, scanned_url=url, risk_score=None, predicted_is_phishing=None, matched_ground_truth=None, api_error=str(exc), ) ) writer.writerow(row_output)
return EvaluationResult( total_rows=total_rows, scored_rows=scored_rows, error_rows=error_rows, tp=tp, tn=tn, fp=fp, fn=fn, rows=output_rows, )
def build_report_payload(result: EvaluationResult) -> dict[str, Any]: false_positives = [ { "url": row.url, "risk_score": row.risk_score, "prediction": row.prediction_label, "score_breakdown": row.score_breakdown, "details": row.details, } for row in result.rows if row.predicted_is_phishing is True and row.actual_is_phishing is False ][:5] false_negatives = [ { "url": row.url, "risk_score": row.risk_score, "prediction": row.prediction_label, "score_breakdown": row.score_breakdown, "details": row.details, } for row in result.rows if row.predicted_is_phishing is False and row.actual_is_phishing is True ][:5] return { "summary": { "total_rows": result.total_rows, "scored_rows": result.scored_rows, "error_rows": result.error_rows, "accuracy": round(result.accuracy, 4), "precision": round(result.precision, 4), "recall": round(result.recall, 4), "f1": round(result.f1, 4), }, "confusion_matrix": { "tp": result.tp, "tn": result.tn, "fp": result.fp, "fn": result.fn, }, "threshold_sweep": build_threshold_sweep_payload(result), "false_positives": false_positives, "false_negatives": false_negatives, }
def build_threshold_sweep_payload( result: EvaluationResult, thresholds: list[float] | None = None, ) -> list[dict[str, Any]]: sweep_thresholds = thresholds or [5, 10, 15, 20, 25, 30, 35, 40, 45, 50, 60, 70, 80, 90] rows = [row for row in result.rows if row.risk_score is not None and row.actual_is_phishing is not None] sweep: list[dict[str, Any]] = [] for threshold in sweep_thresholds: tp = tn = fp = fn = 0 for row in rows: predicted = float(row.risk_score or 0) >= float(threshold) actual = bool(row.actual_is_phishing) if actual and predicted: tp += 1 elif not actual and not predicted: tn += 1 elif predicted and not actual: fp += 1 else: fn += 1 counts = {"tp": tp, "tn": tn, "fp": fp, "fn": fn} metrics = { "accuracy": round((tp + tn) / (tp + tn + fp + fn), 4) if (tp + tn + fp + fn) else 0.0, "precision": round(tp / (tp + fp), 4) if tp + fp else 0.0, "recall": round(tp / (tp + fn), 4) if tp + fn else 0.0, "f1": round((2 * (tp / (tp + fp) if tp + fp else 0.0) * (tp / (tp + fn) if tp + fn else 0.0)) / ((tp / (tp + fp) if tp + fp else 0.0) + (tp / (tp + fn) if tp + fn else 0.0)), 4) if (tp + fp) and (tp + fn) and ((tp / (tp + fp)) + (tp / (tp + fn))) else 0.0, } sweep.append( { "threshold": float(threshold), **counts, **metrics, } ) return sweep

from __future__ import annotations

from typing import Any


def score_rules(snapshot: dict[str, Any]) -> dict[str, Any]:
    content = snapshot.get("content") or {}
    score = 0
    reasons: list[str] = []

    def value(name: str, default: Any = None) -> Any:
        if name in content:
            return content.get(name)
        return snapshot.get(name, default)

    if value("login_form_present"):
        score += 10
        reasons.append("login form present")
    if int(value("password_field_count") or 0) > 0:
        score += min(20, 8 + int(value("password_field_count") or 0) * 5)
        reasons.append("password field found")
    if bool(value("free_host")):
        score += 20
        reasons.append("free host detected")
    if bool(value("brand_mismatch")):
        score += 25
        reasons.append("brand mismatch")
    if bool(value("brand_path_match")):
        score += 10
        reasons.append("brand in URL path")
    if bool(value("form_action_mismatch")):
        score += 12
        reasons.append("form action mismatch")
    if len(value("suspicious_phrase_hits") or []) > 0:
        score += min(20, len(value("suspicious_phrase_hits") or []) * 5)
        reasons.append("suspicious login phrases")
    if bool(value("no_navigation_menu")):
        score += 8
        reasons.append("no navigation menu")
    if bool(value("password_on_http")):
        score += 20
        reasons.append("password field on HTTP")

    score = min(score, 100)
    return {
        "status": "ok",
        "risk_score": float(score),
        "reasons": reasons,
        "prediction": "phishing" if score >= 50 else "clean",
    }

from __future__ import annotations
from collections.abc import Iterable from typing import Any
from scanner.brand_profiles import BrandProfile from scanner.brand_profiles import build_brand_lookup from scanner.brand_profiles import host_matches_brand from scanner.brand_profiles import load_brand_profiles from scanner.brand_profiles import normalize_brand_token
def edit_distance(a: str, b: str, max_distance: int | None = None) -> int: left = normalize_brand_token(a) right = normalize_brand_token(b) if left == right: return 0 if not left: return len(right) if not right: return len(left)
previous = list(range(len(right) + 1)) for i, char_a in enumerate(left, start=1): current = [i] row_min = i for j, char_b in enumerate(right, start=1): cost = 0 if char_a == char_b else 1 current.append( min( previous[j] + 1, current[j - 1] + 1, previous[j - 1] + cost, ) ) row_min = min(row_min, current[-1]) previous = current if max_distance is not None and row_min > max_distance: return max_distance + 1 return previous[-1]
def brand_tokens() -> tuple[str, ...]: tokens = set() for profile in load_brand_profiles(): tokens.update(profile.normalized_keywords()) return tuple(sorted(token for token in tokens if token))
def detect_brand_candidates( *, host: str, page_title: str = "", visible_text: str = "", headings: Iterable[str] | None = None, path: str = "", image_domains: Iterable[str] | None = None, form_action_domains: Iterable[str] | None = None, ) -> list[dict[str, Any]]: headings = list(headings or []) image_domains = list(image_domains or []) form_action_domains = list(form_action_domains or []) corpus = " ".join([page_title, visible_text, " ".join(headings), path, " ".join(image_domains), " ".join(form_action_domains)]).lower() lookup = build_brand_lookup() candidates: list[dict[str, Any]] = [] for profile in load_brand_profiles(): score = 0 matched_fields: list[str] = [] matched_phrases: list[str] = [] profile_tokens = profile.normalized_keywords() if any(token and token in normalize_brand_token(host) for token in profile_tokens): score += 15 matched_fields.append("host") for token in profile_tokens: if not token: continue if token in normalize_brand_token(page_title): score += 8 matched_fields.append("title") if token in normalize_brand_token(visible_text): score += 5 matched_fields.append("body") if token in normalize_brand_token(" ".join(headings)): score += 5 matched_fields.append("heading") if token in normalize_brand_token(path): score += 6 matched_fields.append("path") if token in normalize_brand_token(" ".join(image_domains)): score += 4 matched_fields.append("image") if token in normalize_brand_token(" ".join(form_action_domains)): score += 4 matched_fields.append("form_action") for phrase in (*profile.login_phrases, *profile.suspicious_phrases): lowered = phrase.lower() if lowered and lowered in corpus: matched_phrases.append(phrase) score += 4 if phrase in profile.login_phrases else 6 official_match = host_matches_brand(host, profile) if official_match: score += 10 matched_fields.append("official_domain") if score <= 0: continue candidates.append( { "brand": profile.name, "score": score, "matched_fields": sorted(set(matched_fields)), "matched_phrases": sorted(set(matched_phrases)), "official_domain_match": official_match, } ) candidates.sort(key=lambda item: (int(item.get("score") or 0), len(item.get("matched_fields") or [])), reverse=True) return candidates[:5]
def summarize_brand_impersonation( *, host: str, path: str, content_result: dict[str, Any], ) -> dict[str, Any]: brand_candidates = list(content_result.get("brand_candidates") or []) detected_brand = content_result.get("detected_brand") or "" free_host_provider = content_result.get("host_provider") or "" if not free_host_provider and content_result.get("free_host"): free_host_provider = content_result.get("host_provider") or "" reasons = list(content_result.get("impersonation_reasons") or []) return { "detected_brand": detected_brand, "free_host_provider": free_host_provider, "brand_mismatch": bool(content_result.get("brand_mismatch")), "brand_path_match": bool(content_result.get("brand_path_match")), "brand_path_distance": min( [edit_distance(path, candidate.get("brand", ""), max_distance=2) for candidate in brand_candidates] or [99] ), "login_form_present": bool(content_result.get("login_form_present")), "password_field_count": int(content_result.get("password_field_count") or 0), "form_action_mismatch": bool(content_result.get("form_action_mismatch")), "suspicious_phrase_hits": list(content_result.get("suspicious_phrase_hits") or []), "brand_candidates": brand_candidates[:3], "reasons": reasons[:8], "target_host": host, }

from __future__ import annotations

import re
from pathlib import Path
from typing import Any


LABEL_PREFIX = "__label__"


def clean_text(value: str) -> str:
    text = str(value or "")
    text = re.sub(r"<[^>]+>", " ", text)
    text = re.sub(r"\s+", " ", text)
    return text.strip()


def normalize_token(value: Any) -> str:
    text = clean_text(str(value or "")).lower()
    text = re.sub(r"[^a-z0-9]+", "_", text)
    return text.strip("_")


def snapshot_text_key(snapshot: dict[str, Any]) -> str:
    content = snapshot.get("content") or {}
    visible_text = clean_text(snapshot.get("visible_text") or content.get("visible_text") or "")
    title = clean_text(snapshot.get("page_title") or content.get("page_title") or "")
    fallback = clean_text(snapshot.get("normalized_url") or snapshot.get("url") or "")
    return normalize_token(visible_text or title or fallback)


def corpus_dedup_key(snapshot: dict[str, Any], label: str) -> str:
    normalized_label = normalize_token(label) or "unknown"
    return f"{normalized_label}:{snapshot_text_key(snapshot)}"


def serialize_snapshot(snapshot: dict[str, Any]) -> str:
    content = snapshot.get("content") or {}
    brand_candidates = list(snapshot.get("brand_candidates") or content.get("brand_candidates") or [])
    title = clean_text(snapshot.get("page_title") or content.get("page_title") or "")
    visible_text = clean_text(snapshot.get("visible_text") or content.get("visible_text") or "")
    headings = " ".join(
        clean_text(value)
        for value in (snapshot.get("heading_texts") or content.get("heading_texts") or [])
        if clean_text(value)
    )
    phrase_hits = [normalize_token(item) for item in (snapshot.get("suspicious_phrase_hits") or content.get("suspicious_phrase_hits") or [])]
    matched_phrases = []
    for candidate in brand_candidates:
        matched_phrases.extend(candidate.get("matched_phrases") or [])
    body = " ".join(
        part
        for part in [
            title,
            visible_text,
            headings,
            " ".join(phrase_hits),
            " ".join(clean_text(value) for value in matched_phrases if clean_text(value)),
        ]
        if part
    )
    return clean_text(body)


def serialize_labeled_snapshot(snapshot: dict[str, Any], label: str) -> str:
    normalized_label = label.strip().lower()
    if normalized_label not in {"phishing", "clean"}:
        raise ValueError("label must be 'phishing' or 'clean'")
    return f"{LABEL_PREFIX}{normalized_label} {serialize_snapshot(snapshot)}"


def build_corpus_lines(rows: list[dict[str, Any]], *, dedupe_visible_text: bool = True) -> list[str]:
    lines = []
    seen: set[str] = set()
    for row in rows:
        label = row.get("label") or row.get("is_phishing")
        if label in {1, "1", True, "true", "True"}:
            label_text = "phishing"
        elif label in {0, "0", False, "false", "False"}:
            label_text = "clean"
        else:
            continue
        if dedupe_visible_text:
            dedup_key = corpus_dedup_key(row, label_text)
            if dedup_key in seen:
                continue
            seen.add(dedup_key)
        lines.append(serialize_labeled_snapshot(row, label_text))
    return lines


def write_corpus_file(lines: list[str], output_path: str | Path) -> Path:
    path = Path(output_path)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text("\n".join(lines) + ("\n" if lines else ""), encoding="utf-8")
    return path

