metadata = { "model_version": f"fasttext_{datetime.now(timezone.utc).strftime('%Y%m%d_%H%M%S')}", "model_type": "fasttext", "trained_at": datetime.now(timezone.utc).isoformat(), "corpus_path": str(corpus), "model_path": str(model_file), "feature_version": "fasttext_brand_login_v1", "hyperparameters": asdict(config), } metadata_file.write_text(json.dumps(metadata, indent=2), encoding="utf-8") return metadata
