from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Any

import numpy as np

from pipeline.modeling.fasttext_dataset import serialize_snapshot
from pipeline.modeling.fasttext_train import load_fasttext_model


@dataclass
class FastTextPrediction:
    label: str
    probability: float
    score: float
    raw_label: str
    raw_probability: float

    def as_dict(self) -> dict[str, Any]:
        return {
            "label": self.label,
            "probability": self.probability,
            "score": self.score,
            "raw_label": self.raw_label,
            "raw_probability": self.raw_probability,
        }


class FastTextDetector:
    def __init__(self, model_path: str | Path, threshold: float = 0.5):
        self.model_path = Path(model_path)
        self.threshold = threshold
        self._model = None

    def _ensure_model(self):
        if self._model is not None:
            return self._model
        if not self.model_path.exists():
            return None
        self._patch_fasttext_numpy_compat()
        self._model = load_fasttext_model(self.model_path)
        return self._model

    def _patch_fasttext_numpy_compat(self) -> None:
        try:
            import fasttext.FastText as fasttext_fasttext  # type: ignore
        except Exception:
            return

        def _array_compat(obj, dtype=None, copy=None, order=None, subok=False, ndmin=0):
            del copy, subok, ndmin
            return np.asarray(obj, dtype=dtype, order=order)

        if getattr(fasttext_fasttext.np.array, "__name__", "") != "_array_compat":
            fasttext_fasttext.np.array = _array_compat  # type: ignore[attr-defined]

    def available(self) -> bool:
        return self._ensure_model() is not None

    def predict_text(self, text: str) -> FastTextPrediction | None:
        model = self._ensure_model()
        if model is None:
            return None
        labels, probabilities = model.predict(text, k=1)
        raw_label = labels[0] if labels else "__label__clean"
        raw_probability = float(probabilities[0]) if probabilities else 0.0
        if raw_label.startswith("__label__"):
            label = raw_label.replace("__label__", "", 1)
        else:
            label = raw_label
        probability = raw_probability
        score = probability * 100.0
        return FastTextPrediction(
            label=label,
            probability=probability,
            score=score,
            raw_label=raw_label,
            raw_probability=raw_probability,
        )

    def predict_snapshot(self, snapshot: dict[str, Any]) -> FastTextPrediction | None:
        text = serialize_snapshot(snapshot)
        return self.predict_text(text)

from __future__ import annotations
from dataclasses import dataclass import os from pathlib import Path
@dataclass(frozen=True) class CapstoneConfig: project_root: Path data_root: Path brand_profiles_path: Path dataset_db_path: Path fasttext_model_path: Path fasttext_metadata_path: Path fasttext_corpus_path: Path evaluation_dir: Path request_timeout_seconds: int = 8 fasttext_dim: int = 100 fasttext_epoch: int = 25 fasttext_lr: float = 0.4 fasttext_word_ngrams: int = 2 fasttext_min_count: int = 1 fasttext_loss: str = "softmax" fasttext_threshold: float = 0.5 final_score_threshold: float = 30.0
@staticmethod def from_env() -> "CapstoneConfig": project_root = Path(__file__).resolve().parents[2] data_root = Path(os.getenv("CAPSTONE_DATA_ROOT", str(project_root / "data"))) brand_profiles_path = Path( os.getenv("BRAND_PROFILES_PATH", str(project_root / "scanner" / "brand_profiles.json")) ) dataset_db_path = Path( os.getenv("CAPSTONE_DATASET_DB", str(project_root / ".cache" / "brand-login-dataset.sqlite3")) ) fasttext_model_path = Path( os.getenv("FASTTEXT_MODEL_PATH", str(project_root / ".cache" / "fasttext" / "brand-login.bin")) ) fasttext_metadata_path = Path( os.getenv("FASTTEXT_METADATA_PATH", str(project_root / ".cache" / "fasttext" / "brand-login.json")) ) fasttext_corpus_path = Path( os.getenv("FASTTEXT_CORPUS_PATH", str(data_root / "processed" / "fasttext_corpus.txt")) ) evaluation_dir = Path( os.getenv("CAPSTONE_EVALUATION_DIR", str(project_root / ".cache" / "evaluations")) ) return CapstoneConfig( project_root=project_root, data_root=data_root, brand_profiles_path=brand_profiles_path, dataset_db_path=dataset_db_path, fasttext_model_path=fasttext_model_path, fasttext_metadata_path=fasttext_metadata_path, fasttext_corpus_path=fasttext_corpus_path, evaluation_dir=evaluation_dir, request_timeout_seconds=_int_env("REQUEST_TIMEOUT_SECONDS", 8), fasttext_dim=_int_env("FASTTEXT_DIM", 100), fasttext_epoch=_int_env("FASTTEXT_EPOCH", 25), fasttext_lr=_float_env("FASTTEXT_LR", 0.4), fasttext_word_ngrams=_int_env("FASTTEXT_WORD_NGRAMS", 2), fasttext_min_count=_int_env("FASTTEXT_MIN_COUNT", 1), fasttext_loss=os.getenv("FASTTEXT_LOSS", "softmax"), fasttext_threshold=_float_env("FASTTEXT_THRESHOLD", 0.5), final_score_threshold=_float_env("FINAL_SCORE_THRESHOLD", 30.0), )
def _int_env(name: str, default: int) -> int: value = os.getenv(name) if value is None: return default try: return int(value) except ValueError: return default
def _float_env(name: str, default: float) -> float: value = os.getenv(name) if value is None: return default try: return float(value) except ValueError: return default

from __future__ import annotations

from dataclasses import dataclass
import json
from functools import lru_cache
from collections.abc import Iterable
from pathlib import Path
import re
from typing import Any

BRAND_PROFILE_VERSION = "brand_profiles_v1"
BRAND_PROFILE_PATH = Path(__file__).with_name("brand_profiles.json")


@dataclass(frozen=True)
class BrandProfile:
    name: str
    aliases: tuple[str, ...]
    official_domains: tuple[str, ...]
    logo_keywords: tuple[str, ...]
    login_phrases: tuple[str, ...]
    suspicious_phrases: tuple[str, ...]

    def normalized_keywords(self) -> tuple[str, ...]:
        values = {normalize_brand_token(self.name)}
        values.update(normalize_brand_token(alias) for alias in self.aliases)
        values.update(normalize_brand_token(keyword) for keyword in self.logo_keywords)
        return tuple(sorted(value for value in values if value))


def normalize_brand_token(value: str) -> str:
    cleaned = re.sub(r"[^a-z0-9]+", "", str(value or "").lower())
    return cleaned.strip()


def _coerce_str_tuple(values: Any) -> tuple[str, ...]:
    if not isinstance(values, Iterable) or isinstance(values, (str, bytes)):
        return ()
    return tuple(str(item).strip() for item in values if str(item).strip())


def _default_brand_records() -> list[dict[str, Any]]:
    if not BRAND_PROFILE_PATH.exists():
        return []
    try:
        payload = json.loads(BRAND_PROFILE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return []
    brands = payload.get("brands", [])
    return [item for item in brands if isinstance(item, dict)]


@lru_cache(maxsize=1)
def load_brand_profiles(path: str | Path | None = None) -> tuple[BrandProfile, ...]:
    source_path = Path(path) if path else BRAND_PROFILE_PATH
    if source_path.exists():
        try:
            payload = json.loads(source_path.read_text(encoding="utf-8"))
        except Exception:
            payload = {"brands": _default_brand_records()}
    else:
        payload = {"brands": _default_brand_records()}

    brands = payload.get("brands", [])
    profiles: list[BrandProfile] = []
    for item in brands:
        if not isinstance(item, dict):
            continue
        profiles.append(
            BrandProfile(
                name=str(item.get("name") or "").strip(),
                aliases=_coerce_str_tuple(item.get("aliases")),
                official_domains=_coerce_str_tuple(item.get("official_domains")),
                logo_keywords=_coerce_str_tuple(item.get("logo_keywords")),
                login_phrases=_coerce_str_tuple(item.get("login_phrases")),
                suspicious_phrases=_coerce_str_tuple(item.get("suspicious_phrases")),
            )
        )
    return tuple(profile for profile in profiles if profile.name)


def all_brand_tokens(profiles: Iterable[BrandProfile] | None = None) -> tuple[str, ...]:
    tokens: set[str] = set()
    for profile in profiles or load_brand_profiles():
        tokens.update(profile.normalized_keywords())
    return tuple(sorted(token for token in tokens if token))


def build_brand_lookup(profiles: Iterable[BrandProfile] | None = None) -> dict[str, BrandProfile]:
    lookup: dict[str, BrandProfile] = {}
    for profile in profiles or load_brand_profiles():
        for token in profile.normalized_keywords():
            lookup[token] = profile
    return lookup


def host_matches_brand(host: str, profile: BrandProfile) -> bool:
    normalized_host = str(host or "").lower()
    if not normalized_host:
        return False
    for domain in profile.official_domains:
        domain = domain.lower().strip()
        if domain and (normalized_host == domain or normalized_host.endswith(f".{domain}")):
            return True
    return False


def guess_host_provider(host: str) -> str | None:
    normalized_host = str(host or "").lower()
    free_host_patterns = {
        "vercel": ".vercel.app",
        "github": ".github.io",
        "netlify": ".netlify.app",
        "glitch": ".glitch.me",
        "render": ".onrender.com",
        "firebase": ".web.app",
        "pages": ".pages.dev",
    }
    for provider, pattern in free_host_patterns.items():
        if normalized_host.endswith(pattern):
            return provider
    return None

from __future__ import annotations
from dataclasses import dataclass import re from typing import Any from urllib.parse import urlparse
import requests from bs4 import BeautifulSoup
from scanner.brand_profiles import BrandProfile from scanner.brand_profiles import guess_host_provider from scanner.brand_profiles import host_matches_brand from scanner.brand_profiles import load_brand_profiles from scanner.brand_profiles import normalize_brand_token from scanner.normalization import NormalizedTarget from scanner.settings import ScannerSettings
FREE_HOST_SUFFIXES = (".vercel.app", ".github.io", ".netlify.app", ".glitch.me", ".onrender.com", ".pages.dev", ".web.app") GENERIC_SUSPICIOUS_PHRASES = ( "verify account", "verify your account", "unusual activity", "security alert", "confirm your identity", "update payment", "password required", "account locked", "urgent action required", "secure your account", )
@dataclass(frozen=True) class BrandCandidate: brand: str score: int matched_fields: tuple[str, ...] matched_phrases: tuple[str, ...] official_domain_match: bool
def as_dict(self) -> dict[str, Any]: return { "brand": self.brand, "score": self.score, "matched_fields": list(self.matched_fields), "matched_phrases": list(self.matched_phrases), "official_domain_match": self.official_domain_match, }
class ContentScanner: def __init__(self, target: NormalizedTarget, settings: ScannerSettings): self.target = target self.settings = settings self.html_content = "" self.soup: BeautifulSoup | None = None self.last_error = "" self.brand_profiles = load_brand_profiles()
def fetch_content(self) -> bool: """Fetch the HTML content of the page.""" try: response = requests.get( self.target.normalized_url, timeout=self.settings.request_timeout_seconds, ) if response.status_code == 200: self.html_content = response.text self.soup = BeautifulSoup(self.html_content, "html.parser") return True self.last_error = f"status_code={response.status_code}" except Exception as exc: self.last_error = str(exc) return False return False
def run_checks(self) -> dict: fetched = self.fetch_content() if not fetched: return { "status": "unknown", "unknown_reason": "content_unavailable", "error": self.last_error, "content_fetched": False, "page_title": "", "visible_text_length": 0, "login_form_present": False, "form_count": 0, "password_field_count": 0, "input_field_count": 0, "nav_link_count": 0, "image_count": 0, "image_domains": [], "free_host": False, "host_provider": "", "brand_candidate_count": 0, "brand_mismatch": False, "brand_path_match": False, "suspicious_keywords": False, "hidden_elements": False, "password_on_http": False, "risk_score": 0, "impersonation_reasons": [], "brand_candidates": [], }
assert self.soup is not None page_title = self._page_title() visible_text = self._visible_text() heading_texts = self._heading_texts() forms = self.soup.find_all("form") form_stats = self._form_stats(forms) image_domains = self._image_domains() form_action_domains = self._form_action_domains(forms) nav_link_count = self._nav_link_count() hidden = self._check_hidden_elements() brand_candidates = self._brand_candidates( page_title=page_title, visible_text=visible_text, heading_texts=heading_texts, image_domains=image_domains, form_action_domains=form_action_domains, ) detected_brand = brand_candidates[0].brand if brand_candidates else "" detected_profile = self._profile_by_name(detected_brand) brand_mismatch = bool( detected_brand and detected_profile and not host_matches_brand(self.target.host, detected_profile) ) brand_path_match = self._brand_path_match() suspicious_hits = self._suspicious_phrase_hits(page_title=page_title, visible_text=visible_text) host_provider = guess_host_provider(self.target.host) or "" free_host = bool(host_provider) login_form_present = form_stats["password_field_count"] > 0 or form_stats["form_count"] > 0 form_action_mismatch = bool(form_action_domains and any( self._domain_mismatch(action_domain, detected_profile) for action_domain in form_action_domains )) no_navigation_menu = nav_link_count == 0 and login_form_present password_on_http = form_stats["password_field_count"] > 0 and self.target.scheme != "https" content_keyword_flag = bool(suspicious_hits) hidden_elements = hidden risk_score, reasons = self._impersonation_score( login_form_present=login_form_present, password_field_count=form_stats["password_field_count"], input_field_count=form_stats["input_field_count"], free_host=free_host, brand_mismatch=brand_mismatch, brand_path_match=brand_path_match, suspicious_hits=suspicious_hits, form_action_mismatch=form_action_mismatch, no_navigation_menu=no_navigation_menu, hidden_elements=hidden_elements, password_on_http=password_on_http, brand_candidates=brand_candidates, )
return { "status": "ok", "content_fetched": True, "page_title": page_title, "heading_texts": heading_texts, "visible_text": visible_text[:2000], "visible_text_length": len(visible_text), "form_count": form_stats["form_count"], "login_form_present": login_form_present, "password_field_count": form_stats["password_field_count"], "input_field_count": form_stats["input_field_count"], "nav_link_count": nav_link_count, "image_count": len(image_domains), "image_domains": image_domains, "external_image_domain_count": len([domain for domain in image_domains if domain and domain != self.target.host]), "form_action_count": len(form_action_domains), "form_action_domains": form_action_domains, "form_action_mismatch": form_action_mismatch, "free_host": free_host, "host_provider": host_provider, "brand_candidate_count": len(brand_candidates), "detected_brand": detected_brand, "brand_candidates": [candidate.as_dict() for candidate in brand_candidates], "brand_mismatch": brand_mismatch, "brand_path_match": brand_path_match, "brand_mention_count": len(brand_candidates), "suspicious_phrase_hits": suspicious_hits, "suspicious_keywords": content_keyword_flag, "hidden_elements": hidden_elements, "password_on_http": password_on_http, "no_navigation_menu": no_navigation_menu, "impersonation_reasons": reasons, "risk_score": risk_score, }
def _page_title(self) -> str: if not self.soup: return "" title_tag = self.soup.find("title") return title_tag.get_text(" ", strip=True) if title_tag else ""
def _visible_text(self) -> str: if not self.soup: return "" text = self.soup.get_text(" ", strip=True) return re.sub(r"\s+", " ", text).strip()
def _heading_texts(self) -> list[str]: if not self.soup: return [] headings = [] for tag_name in ("h1", "h2", "h3"): for tag in self.soup.find_all(tag_name): value = tag.get_text(" ", strip=True) if value: headings.append(value) return headings[:12]
def _form_stats(self, forms) -> dict[str, int]: password_count = 0 input_count = 0 form_count = 0 if not self.soup: return {"form_count": 0, "password_field_count": 0, "input_field_count": 0} for form in forms: form_count += 1 for element in form.find_all("input"): input_count += 1 input_type = str(element.get("type", "")).lower() if input_type == "password": password_count += 1 return { "form_count": form_count, "password_field_count": password_count, "input_field_count": input_count, }
def _nav_link_count(self) -> int: if not self.soup: return 0 nav_links = 0 for nav in self.soup.find_all("nav"): nav_links += len(nav.find_all("a")) return nav_links
def _image_domains(self) -> list[str]: if not self.soup: return [] domains: list[str] = [] for image in self.soup.find_all("img"): src = str(image.get("src") or "").strip() if not src: continue parsed = urlparse(src) domain = parsed.netloc.lower() if not domain and src.startswith("/"): domain = self.target.host if domain: domains.append(domain) return sorted(set(domains))
def _form_action_domains(self, forms) -> list[str]: domains: list[str] = [] for form in forms: action = str(form.get("action") or "").strip() if not action: continue parsed = urlparse(action) domain = parsed.netloc.lower() if not domain and not action.startswith("javascript:"): domain = self.target.host if domain: domains.append(domain) return sorted(set(domains))
def _check_hidden_elements(self) -> bool: if not self.soup: return False for iframe in self.soup.find_all("iframe"): width = str(iframe.get("width", "100")) height = str(iframe.get("height", "100")) style = str(iframe.get("style", "")).lower() if width == "0" or height == "0" or "display: none" in style or "visibility: hidden" in style: return True return False
def _brand_candidates( self, *, page_title: str, visible_text: str, heading_texts: list[str], image_domains: list[str], form_action_domains: list[str], ) -> list[BrandCandidate]: lowered_title = page_title.lower() lowered_text = visible_text.lower() lowered_headings = " ".join(heading_texts).lower() lowered_path = f"{self.target.path} {self.target.query}".lower() image_blob = " ".join(image_domains).lower() action_blob = " ".join(form_action_domains).lower()
candidates: list[BrandCandidate] = [] for profile in self.brand_profiles: matched_fields: list[str] = [] matched_phrases: list[str] = [] score = 0 normalized_name = normalize_brand_token(profile.name) search_tokens = {normalized_name, *(normalize_brand_token(alias) for alias in profile.aliases)} keyword_hits = set()
for token in sorted(token for token in search_tokens if token): if token in normalize_brand_token(self.target.host): matched_fields.append("host") score += 12 if token in normalize_brand_token(lowered_path): matched_fields.append("path") score += 6 if token in normalize_brand_token(lowered_title): matched_fields.append("title") score += 8 if token in normalize_brand_token(lowered_headings): matched_fields.append("heading") score += 8 if token in normalize_brand_token(lowered_text): matched_fields.append("body") score += 5 if token in normalize_brand_token(image_blob): matched_fields.append("image") score += 5 if token in normalize_brand_token(action_blob): matched_fields.append("form_action") score += 5 if token: keyword_hits.add(token)
for phrase in (*profile.login_phrases, *profile.suspicious_phrases): lowered_phrase = phrase.lower() if lowered_phrase and ( lowered_phrase in lowered_title or lowered_phrase in lowered_text or lowered_phrase in lowered_headings or lowered_phrase in lowered_path ): matched_phrases.append(phrase) score += 4 if phrase in profile.login_phrases else 6
if host_matches_brand(self.target.host, profile): matched_fields.append("official_domain") score += 10 if any(keyword and keyword in lowered_path for keyword in profile.normalized_keywords()): matched_fields.append("path_keyword") score += 5
if score > 0: candidates.append( BrandCandidate( brand=profile.name, score=score, matched_fields=tuple(sorted(set(matched_fields))), matched_phrases=tuple(sorted(set(matched_phrases))), official_domain_match=host_matches_brand(self.target.host, profile), ) )
candidates.sort(key=lambda candidate: (candidate.score, len(candidate.matched_fields)), reverse=True) return candidates[:5]
def _profile_by_name(self, name: str) -> BrandProfile | None: for profile in self.brand_profiles: if profile.name == name: return profile return None
def _brand_path_match(self) -> bool: lowered_path = f"{self.target.path} {self.target.query}".lower() return any(token and token in lowered_path for token in self._brand_tokens())
def _brand_tokens(self) -> tuple[str, ...]: tokens = [] for profile in self.brand_profiles: tokens.extend(profile.normalized_keywords()) return tuple(sorted(set(tokens)))
def _suspicious_phrase_hits(self, *, page_title: str, visible_text: str) -> list[str]: corpus = f"{page_title} {visible_text}".lower() hits: list[str] = [] for phrase in GENERIC_SUSPICIOUS_PHRASES: if phrase in corpus: hits.append(phrase) for profile in self.brand_profiles: for phrase in profile.suspicious_phrases: lowered_phrase = phrase.lower() if lowered_phrase in corpus: hits.append(phrase) return sorted(set(hits))
def _domain_mismatch(self, domain: str, profile: BrandProfile | None) -> bool: if not profile: return False normalized_domain = str(domain or "").lower() if not normalized_domain: return False if host_matches_brand(normalized_domain, profile): return False return True
def _impersonation_score( self, *, login_form_present: bool, password_field_count: int, input_field_count: int, free_host: bool, brand_mismatch: bool, brand_path_match: bool, suspicious_hits: list[str], form_action_mismatch: bool, no_navigation_menu: bool, hidden_elements: bool, password_on_http: bool, brand_candidates: list[BrandCandidate], ) -> tuple[int, list[str]]: score = 0 reasons: list[str] = []
if login_form_present: score += 12 reasons.append("login form detected") if password_field_count > 0: score += min(25, 10 + password_field_count * 6) reasons.append(f"{password_field_count} password field(s)") if input_field_count >= 3: score += 8 reasons.append("multiple input fields") if free_host: score += 18 reasons.append(f"free host provider: {guess_host_provider(self.target.host) or 'unknown'}") if brand_mismatch: score += 30 reasons.append("brand text does not match host") if brand_path_match: score += 10 reasons.append("brand keyword appears in the URL path") if suspicious_hits: score += min(20, 4 * len(suspicious_hits)) reasons.append("suspicious login language found") if form_action_mismatch: score += 12 reasons.append("form action points away from the brand host") if no_navigation_menu: score += 8 reasons.append("page has a login form but no navigation") if hidden_elements: score += 10 reasons.append("hidden page elements detected") if password_on_http: score += 20 reasons.append("password field appears on a non-HTTPS page") if brand_candidates: score += min(12, brand_candidates[0].score // 2) if brand_candidates[0].matched_fields: reasons.append(f"brand candidate: {brand_candidates[0].brand}")
if brand_candidates and not brand_candidates[0].official_domain_match: score += 8 reasons.append("brand candidate does not match an official domain")
if score > 100: score = 100 return score, list(dict.fromkeys(reasons))

from __future__ import annotations
from dataclasses import dataclass from datetime import datetime, timezone import hashlib import json import sqlite3 from pathlib import Path from typing import Any
DATASET_SCHEMA_VERSION = "brand_login_dataset_v2"
@dataclass(frozen=True) class SnapshotRecord: url: str normalized_url: str host: str captured_at_utc: str source_feed: str = "" source_label: str = "" source_pipeline: str = "" pipeline_version: str = "" raw_html: str = "" visible_text: str = "" page_title: str = "" detected_brand: str = "" host_provider: str = "" risk_score: float | None = None prediction: str = "" content_hash: str = "" extraction_json: str = "{}" label: int | None = None notes: str = ""
@staticmethod def create( *, url: str, normalized_url: str, host: str, source_feed: str = "", source_label: str = "", source_pipeline: str = "", pipeline_version: str = "", raw_html: str = "", visible_text: str = "", page_title: str = "", detected_brand: str = "", host_provider: str = "", risk_score: float | None = None, prediction: str = "", content_hash: str = "", extraction: dict[str, Any] | None = None, label: int | None = None, notes: str = "", ) -> "SnapshotRecord": normalized_extraction = json.dumps(extraction or {}, ensure_ascii=True, sort_keys=True, separators=(",", ":")) derived_content_hash = content_hash or hashlib.sha256( "|".join( [ normalized_url, raw_html, visible_text, page_title, detected_brand, host_provider, normalized_extraction, ] ).encode("utf-8") ).hexdigest() return SnapshotRecord( url=url, normalized_url=normalized_url, host=host, captured_at_utc=datetime.now(timezone.utc).isoformat(), source_feed=source_feed, source_label=source_label, source_pipeline=source_pipeline, pipeline_version=pipeline_version, raw_html=raw_html, visible_text=visible_text, page_title=page_title, detected_brand=detected_brand, host_provider=host_provider, risk_score=risk_score, prediction=prediction, content_hash=derived_content_hash, extraction_json=normalized_extraction, label=label, notes=notes, )
class BrandLoginDatasetStore: def __init__(self, db_path: str | Path): self.path = Path(db_path) self.path.parent.mkdir(parents=True, exist_ok=True) self._ensure_schema()
def _connect(self) -> sqlite3.Connection: conn = sqlite3.connect(self.path) conn.row_factory = sqlite3.Row return conn
def _ensure_schema(self) -> None: with self._connect() as conn: conn.execute( """ CREATE TABLE IF NOT EXISTS snapshot_records ( id INTEGER PRIMARY KEY AUTOINCREMENT, url TEXT NOT NULL, normalized_url TEXT NOT NULL, host TEXT NOT NULL, captured_at_utc TEXT NOT NULL, source_feed TEXT NOT NULL DEFAULT '', source_label TEXT NOT NULL DEFAULT '', source_pipeline TEXT NOT NULL DEFAULT '', pipeline_version TEXT NOT NULL DEFAULT '', raw_html TEXT NOT NULL DEFAULT '', visible_text TEXT NOT NULL DEFAULT '', page_title TEXT NOT NULL DEFAULT '', detected_brand TEXT NOT NULL DEFAULT '', host_provider TEXT NOT NULL DEFAULT '', risk_score REAL, prediction TEXT NOT NULL DEFAULT '', content_hash TEXT NOT NULL DEFAULT '', extraction_json TEXT NOT NULL DEFAULT '{}', label INTEGER, notes TEXT NOT NULL DEFAULT '', schema_version TEXT NOT NULL DEFAULT 'brand_login_dataset_v2' ) """ ) conn.execute( """ CREATE INDEX IF NOT EXISTS idx_snapshot_records_normalized_url ON snapshot_records(normalized_url) """ ) conn.execute( """ CREATE INDEX IF NOT EXISTS idx_snapshot_records_captured_at ON snapshot_records(captured_at_utc) """ ) self._ensure_columns(conn) conn.execute( """ CREATE INDEX IF NOT EXISTS idx_snapshot_records_content_hash ON snapshot_records(normalized_url, content_hash) """ ) conn.commit()
def _ensure_columns(self, conn: sqlite3.Connection) -> None: existing = { str(row["name"]) for row in conn.execute("PRAGMA table_info(snapshot_records)").fetchall() } additions = { "source_pipeline": "TEXT NOT NULL DEFAULT ''", "pipeline_version": "TEXT NOT NULL DEFAULT ''", "risk_score": "REAL", "prediction": "TEXT NOT NULL DEFAULT ''", "content_hash": "TEXT NOT NULL DEFAULT ''", } for column_name, column_sql in additions.items(): if column_name in existing: continue conn.execute(f"ALTER TABLE snapshot_records ADD COLUMN {column_name} {column_sql}")
def add_snapshot(self, record: SnapshotRecord) -> int: with self._connect() as conn: existing = conn.execute( """ SELECT id FROM snapshot_records WHERE normalized_url = ? AND content_hash = ? ORDER BY id DESC LIMIT 1 """, (record.normalized_url, record.content_hash), ).fetchone() if existing is not None: return int(existing["id"]) cursor = conn.execute( """ INSERT INTO snapshot_records ( url, normalized_url, host, captured_at_utc, source_feed, source_label, source_pipeline, pipeline_version, raw_html, visible_text, page_title, detected_brand, host_provider, risk_score, prediction, content_hash, extraction_json, label, notes, schema_version ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?) """, ( record.url, record.normalized_url, record.host, record.captured_at_utc, record.source_feed, record.source_label, record.source_pipeline, record.pipeline_version, record.raw_html, record.visible_text, record.page_title, record.detected_brand, record.host_provider, record.risk_score, record.prediction, record.content_hash, record.extraction_json, record.label, record.notes, DATASET_SCHEMA_VERSION, ), ) conn.commit() return int(cursor.lastrowid)
def update_label(self, snapshot_id: int, label: int, notes: str = "") -> None: with self._connect() as conn: conn.execute( """ UPDATE snapshot_records SET label = ?, notes = ? WHERE id = ? """, (label, notes, snapshot_id), ) conn.commit()
def iter_recent(self, limit: int = 25) -> list[dict[str, Any]]: with self._connect() as conn: rows = conn.execute( """ SELECT * FROM snapshot_records ORDER BY captured_at_utc DESC, id DESC LIMIT ? """, (limit,), ).fetchall() return [dict(row) for row in rows]
def summary(self) -> dict[str, Any]: with self._connect() as conn: counts = conn.execute( """ SELECT COUNT(*) AS total_rows, SUM(CASE WHEN label = 1 THEN 1 ELSE 0 END) AS phishing_rows, SUM(CASE WHEN label = 0 THEN 1 ELSE 0 END) AS legitimate_rows, COUNT(DISTINCT detected_brand) AS brand_count, COUNT(DISTINCT host_provider) AS host_provider_count, COUNT(DISTINCT source_pipeline) AS source_pipeline_count, COUNT(DISTINCT pipeline_version) AS pipeline_version_count FROM snapshot_records """ ).fetchone() by_brand = conn.execute( """ SELECT detected_brand, COUNT(*) AS row_count FROM snapshot_records WHERE detected_brand != '' GROUP BY detected_brand ORDER BY row_count DESC, detected_brand ASC LIMIT 10 """ ).fetchall() by_host_provider = conn.execute( """ SELECT host_provider, COUNT(*) AS row_count FROM snapshot_records WHERE host_provider != '' GROUP BY host_provider ORDER BY row_count DESC, host_provider ASC LIMIT 10 """ ).fetchall() by_source_pipeline = conn.execute( """ SELECT source_pipeline, COUNT(*) AS row_count FROM snapshot_records WHERE source_pipeline != '' GROUP BY source_pipeline ORDER BY row_count DESC, source_pipeline ASC LIMIT 10 """ ).fetchall() by_pipeline_version = conn.execute( """ SELECT pipeline_version, COUNT(*) AS row_count FROM snapshot_records WHERE pipeline_version != '' GROUP BY pipeline_version ORDER BY row_count DESC, pipeline_version ASC LIMIT 10 """ ).fetchall()
return { "schema_version": DATASET_SCHEMA_VERSION, "db_path": str(self.path), "total_rows": int(counts["total_rows"] or 0), "phishing_rows": int(counts["phishing_rows"] or 0), "legitimate_rows": int(counts["legitimate_rows"] or 0), "brand_count": int(counts["brand_count"] or 0), "host_provider_count": int(counts["host_provider_count"] or 0), "source_pipeline_count": int(counts["source_pipeline_count"] or 0), "pipeline_version_count": int(counts["pipeline_version_count"] or 0), "top_brands": [dict(row) for row in by_brand], "top_host_providers": [dict(row) for row in by_host_provider], "top_source_pipelines": [dict(row) for row in by_source_pipeline], "top_pipeline_versions": [dict(row) for row in by_pipeline_version], }

import whois
import datetime
from scanner.normalization import NormalizedTarget

class DomainAgeScanner:
    def __init__(self, target: NormalizedTarget):
        self.target = target
        self.domain = target.host

    def get_whois_info(self):
        """Query WHOIS database for domain info."""
        try:
            w = whois.whois(self.domain)
            return w
        except Exception:
            return None

    def check_domain_age(self, creation_date: datetime.datetime) -> int:
        """Calculate domain age in days."""
        if not creation_date:
            return 0

        if isinstance(creation_date, list):
            creation_date = creation_date[0]

        if creation_date.tzinfo is not None:
            creation_date = creation_date.replace(tzinfo=None)
        age = (datetime.datetime.utcnow() - creation_date).days
        return age

    def check_registrar(self, registrar: str) -> bool:
        """Check if registrar is known/suspicious (placeholder logic)."""
        # This is hard to generalize without a large database.
        # For now, just return True if we have registrar info.
        return bool(registrar)

    def run_checks(self) -> dict:
        if self.target.is_ip:
            return {
                "status": "unknown",
                "unknown_reason": "whois_skipped_for_ip",
                "domain_age_days": 0,
                "registrar": "Unknown",
                "risk_score": 0,
            }

        w = self.get_whois_info()

        if not w:
            return {
                "status": "unknown",
                "unknown_reason": "whois_unavailable",
                "domain_age_days": 0,
                "registrar": "Unknown",
                "risk_score": 0,
            }

        age_days = self.check_domain_age(w.creation_date)
        registrar = w.registrar

        score = 0
        # New domains (< 30 days) are high risk
        if age_days < 30:
            score += 80
        elif age_days < 180:
            score += 40

        return {
            "status": "ok",
            "domain_age_days": age_days,
            "registrar": str(registrar),
            "risk_score": min(score, 100),
        }

from __future__ import annotations

from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
import gzip
import json
from pathlib import Path
import threading
from typing import Any

import requests

from scanner.normalization import NormalizedTarget, normalize_feed_value
from scanner.settings import ScannerSettings


@dataclass
class FeedIndex:
    urls: dict[str, list[dict[str, Any]]] = field(default_factory=dict)
    hosts: dict[str, list[dict[str, Any]]] = field(default_factory=dict)
    ips: dict[str, list[dict[str, Any]]] = field(default_factory=dict)
    last_refresh_utc: str | None = None
    refresh_error: str | None = None

    def add_entry(self, kind: str, key: str, entry: dict[str, Any]) -> None:
        if kind == "url":
            self.urls.setdefault(key, []).append(entry)
        elif kind == "host":
            self.hosts.setdefault(key, []).append(entry)
        elif kind == "ip":
            self.ips.setdefault(key, []).append(entry)


class ThreatFeedCache:
    def __init__(self, settings: ScannerSettings):
        self.settings = settings
        self._lock = threading.Lock()
        self._index = FeedIndex()
        self._last_refresh_time: datetime | None = None
        self._refresh_in_progress = False
        self._last_refresh_attempt_utc: str | None = None
        self.cache_dir = Path(settings.feed_cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.index_file = self.cache_dir / "index.json"
        self._load_disk_index()

    def metadata(self) -> dict[str, Any]:
        now = datetime.now(timezone.utc)
        max_age = timedelta(minutes=max(self.settings.feed_refresh_minutes, 1))
        with self._lock:
            stale = (
                self._last_refresh_time is None
                or now - self._last_refresh_time >= max_age
            )
        return {
            "last_refresh_utc": self._index.last_refresh_utc,
            "last_refresh_attempt_utc": self._last_refresh_attempt_utc,
            "refresh_error": self._index.refresh_error,
            "refresh_in_progress": self._refresh_in_progress,
            "stale_cache": stale,
            "cache_dir": str(self.cache_dir),
            "vt_pos_file": self.settings.vt_pos_file or None,
            "vt_neg_file": self.settings.vt_neg_file or None,
        }

    def refresh_if_stale(self) -> None:
        if self._is_stale():
            self._trigger_background_refresh()

    def refresh_now(self) -> None:
        with self._lock:
            self._last_refresh_attempt_utc = datetime.now(timezone.utc).isoformat()
        self._apply_refresh(self._build_index())

    def _build_index(self) -> tuple[FeedIndex, datetime]:
        new_index = FeedIndex()
        errors: list[str] = []

        if self.settings.openphish_enabled:
            try:
                self._ingest_openphish(new_index)
            except Exception as exc:
                errors.append(f"openphish: {exc}")

        if self.settings.phishtank_enabled:
            try:
                self._ingest_phishtank(new_index)
            except Exception as exc:
                errors.append(f"phishtank: {exc}")

        if self.settings.vt_enabled:
            try:
                self._ingest_vt_snapshot(
                    new_index,
                    filename=self.settings.vt_pos_file,
                    label="positive",
                    apply_threshold=True,
                )
                self._ingest_vt_snapshot(
                    new_index,
                    filename=self.settings.vt_neg_file,
                    label="negative",
                    apply_threshold=self.settings.vt_apply_min_sources_to_neg,
                )
            except Exception as exc:
                errors.append(f"vt: {exc}")

        finished_at = datetime.now(timezone.utc)
        new_index.last_refresh_utc = finished_at.isoformat()
        new_index.refresh_error = "; ".join(errors) if errors else None
        return new_index, finished_at

    def _apply_refresh(self, refresh_output: tuple[FeedIndex, datetime]) -> None:
        new_index, finished_at = refresh_output
        with self._lock:
            self._index = new_index
            self._last_refresh_time = finished_at
            self._last_refresh_attempt_utc = finished_at.isoformat()
            self._refresh_in_progress = False
        self._save_disk_index()

    def _refresh_worker(self) -> None:
        try:
            result = self._build_index()
            self._apply_refresh(result)
        except Exception as exc:
            with self._lock:
                self._refresh_in_progress = False
                self._last_refresh_attempt_utc = datetime.now(timezone.utc).isoformat()
                self._index.refresh_error = f"background_refresh_failed: {exc}"

    def _trigger_background_refresh(self) -> None:
        with self._lock:
            if self._refresh_in_progress:
                return
            self._refresh_in_progress = True
            self._last_refresh_attempt_utc = datetime.now(timezone.utc).isoformat()
        worker = threading.Thread(target=self._refresh_worker, daemon=True)
        worker.start()

    def _is_stale(self) -> bool:
        with self._lock:
            if self._last_refresh_time is None:
                return True
            max_age = timedelta(minutes=max(self.settings.feed_refresh_minutes, 1))
            return datetime.now(timezone.utc) - self._last_refresh_time >= max_age

    def lookup(self, target: NormalizedTarget) -> dict[str, Any]:
        self.refresh_if_stale()
        with self._lock:
            url_hits = self._index.urls.get(target.normalized_url, [])
            host_hits = self._index.hosts.get(target.host, [])
            ip_hits = self._index.ips.get(target.host, []) if target.is_ip else []

            all_hits = [*url_hits, *host_hits, *ip_hits]
            positives = [h for h in all_hits if h.get("label") == "positive"]
            negatives = [h for h in all_hits if h.get("label") == "negative"]

            score = 0
            if positives:
                score = 100
            elif negatives:
                score = 5

            return {
                "status": "ok",
                "match_found": bool(all_hits),
                "positive_match_count": len(positives),
                "negative_match_count": len(negatives),
                "matches": all_hits[:25],
                "risk_score": score,
                "feed_freshness": {
                    "last_refresh_utc": self._index.last_refresh_utc,
                    "refresh_error": self._index.refresh_error,
                },
            }

    def _ingest_openphish(self, index: FeedIndex) -> None:
        response = requests.get(
            self.settings.openphish_url,
            timeout=self.settings.request_timeout_seconds,
        )
        response.raise_for_status()
        for line in response.text.splitlines():
            parsed = normalize_feed_value(line)
            if not parsed:
                continue
            kind, key = parsed
            index.add_entry(
                kind,
                key,
                {
                    "feed": "openphish",
                    "label": "positive",
                    "source_count": None,
                    "value": line.strip(),
                },
            )

    def _ingest_phishtank(self, index: FeedIndex) -> None:
        request_url = self.settings.phishtank_data_url
        if "{app_key}" in request_url:
            if not self.settings.phishtank_app_key:
                return
            request_url = request_url.format(app_key=self.settings.phishtank_app_key)

        response = requests.get(
            request_url,
            timeout=self.settings.request_timeout_seconds,
            headers={
                "User-Agent": "CapstonePhishingDetector/1.0 (+https://cursor.local)",
                "Accept": "application/json, text/plain;q=0.9, */*;q=0.8",
            },
        )
        response.raise_for_status()
        payload = response.json()
        if isinstance(payload, dict):
            entries = payload.get("results") or payload.get("data") or []
        else:
            entries = payload
        if not isinstance(entries, list):
            return

        for entry in entries:
            if not isinstance(entry, dict):
                continue
            value = str(entry.get("url") or "").strip()
            parsed = normalize_feed_value(value)
            if not parsed:
                continue
            kind, key = parsed
            index.add_entry(
                kind,
                key,
                {
                    "feed": "phishtank",
                    "label": "positive",
                    "source_count": None,
                    "value": value,
                    "phish_detail_url": entry.get("phish_detail_url") or entry.get("phish_detail_page") or "",
                    "submission_time": entry.get("submission_time") or entry.get("submitted_at") or "",
                    "verification_time": entry.get("verification_time") or entry.get("verified_at") or "",
                    "verified": entry.get("verified"),
                    "online": entry.get("online"),
                    "target": entry.get("target") or "",
                },
            )

    def _ingest_vt_snapshot(
        self,
        index: FeedIndex,
        filename: str,
        label: str,
        apply_threshold: bool,
    ) -> None:
        if not filename:
            return
        url = f"{self.settings.vt_base_url.rstrip('/')}/{filename}"
        response = requests.get(url, timeout=self.settings.request_timeout_seconds)
        response.raise_for_status()
        content = gzip.decompress(response.content).decode("utf-8", errors="replace")

        dedupe: dict[tuple[str, str], dict[str, Any]] = {}
        for line in content.splitlines():
            parsed = self._parse_vt_line(line)
            if parsed is None:
                continue
            source_count, value = parsed
            if apply_threshold and source_count < self.settings.vt_min_sources:
                continue
            normalized = normalize_feed_value(value)
            if not normalized:
                continue
            kind, key = normalized
            dedupe_key = (kind, key)
            previous = dedupe.get(dedupe_key)
            if previous is None or source_count > previous["source_count"]:
                dedupe[dedupe_key] = {
                    "feed": "vt",
                    "label": label,
                    "source_count": source_count,
                    "value": value,
                    "snapshot": filename,
                }

        for (kind, key), entry in dedupe.items():
            index.add_entry(kind, key, entry)

    @staticmethod
    def _parse_vt_line(line: str) -> tuple[int, str] | None:
        stripped = line.strip()
        if not stripped:
            return None
        parts = stripped.split(maxsplit=1)
        if len(parts) != 2:
            return None
        count_part, value_part = parts
        try:
            source_count = int(count_part)
        except ValueError:
            return None
        value = value_part.strip()
        if not value:
            return None
        return source_count, value

    def _save_disk_index(self) -> None:
        payload = {
            "urls": self._index.urls,
            "hosts": self._index.hosts,
            "ips": self._index.ips,
            "last_refresh_utc": self._index.last_refresh_utc,
            "refresh_error": self._index.refresh_error,
        }
        self.index_file.write_text(json.dumps(payload), encoding="utf-8")

    def _load_disk_index(self) -> None:
        if not self.index_file.exists():
            return
        try:
            payload = json.loads(self.index_file.read_text(encoding="utf-8"))
        except Exception:
            return
        self._index = FeedIndex(
            urls=payload.get("urls", {}),
            hosts=payload.get("hosts", {}),
            ips=payload.get("ips", {}),
            last_refresh_utc=payload.get("last_refresh_utc"),
            refresh_error=payload.get("refresh_error"),
        )
        if self._index.last_refresh_utc:
            try:
                self._last_refresh_time = datetime.fromisoformat(self._index.last_refresh_utc)
            except ValueError:
                self._last_refresh_time = None

from scanner.normalization import NormalizedTarget


class URLHeuristics:
    def __init__(self, target: NormalizedTarget):
        self.target = target

    def check_ip_address(self) -> bool:
        return self.target.is_ip

    def check_url_length(self, threshold: int = 80) -> bool:
        return len(self.target.normalized_url) > threshold

    def check_suspicious_chars(self) -> bool:
        if "@" in self.target.normalized_url:
            return True
        if self.target.host.count(".") > 4:
            return True
        return False

    def check_keyword_masking(self) -> bool:
        suspicious_keywords = {
            "paypal",
            "apple",
            "google",
            "microsoft",
            "facebook",
            "amazon",
            "bank",
            "login",
            "signin",
            "verify",
            "secure",
        }
        host = self.target.host.lower()
        full_url = self.target.normalized_url.lower()
        for keyword in suspicious_keywords:
            if keyword not in full_url:
                continue
            if keyword not in host:
                return True
            if keyword in self.target.path.lower() or keyword in self.target.query.lower():
                return True
        return False

    def run_checks(self) -> dict:
        is_ip_address = self.check_ip_address()
        excessive_length = self.check_url_length()
        suspicious_chars = self.check_suspicious_chars()
        keyword_masking = self.check_keyword_masking()

        score = 0
        if is_ip_address:
            score += 30
        if excessive_length:
            score += 10
        if suspicious_chars:
            score += 20
        if keyword_masking:
            score += 25

        return {
            "status": "ok",
            "is_ip_address": is_ip_address,
            "excessive_length": excessive_length,
            "suspicious_chars": suspicious_chars,
            "keyword_masking": keyword_masking,
            "risk_score": min(score, 100),
        }

from __future__ import annotations

from datetime import datetime, timezone
import json
from pathlib import Path
import threading
from typing import Any

try:
    import joblib
except ImportError:  # pragma: no cover - handled at runtime.
    joblib = None

try:
    import numpy as np
except ImportError:  # pragma: no cover - handled at runtime.
    np = None

try:
    import tensorflow as tf  # pyright: ignore[reportMissingImports]
except ImportError:  # pragma: no cover - handled at runtime.
    tf = None

from scanner.ml_features import FEATURE_FIELDS
from scanner.ml_features import FEATURE_VERSION
from scanner.ml_features import vectorize_features
from scanner.settings import ScannerSettings


class MLScanner:
    def __init__(self, settings: ScannerSettings):
        self.settings = settings
        self._lock = threading.Lock()
        self._model: Any | None = None
        self._metadata: dict[str, Any] = {}
        self._artifact_signature: tuple[float | None, float | None] | None = None
        self._analytics = {
            "predictions_total": 0,
            "unknown_total": 0,
            "phishing_total": 0,
            "benign_total": 0,
            "probability_sum": 0.0,
            "last_prediction_utc": None,
        }

    def refresh(self) -> None:
        with self._lock:
            self._artifact_signature = None
            self._model = None
            self._metadata = {}

    def analytics(self) -> dict[str, Any]:
        self._ensure_loaded()
        with self._lock:
            predictions_total = int(self._analytics["predictions_total"])
            avg_probability = (
                float(self._analytics["probability_sum"]) / predictions_total
                if predictions_total
                else 0.0
            )
            return {
                "enabled": self.settings.ml_enabled,
                "available": self._model is not None,
                "model_version": self._metadata.get("model_version"),
                "model_type": self._metadata.get("model_type"),
                "feature_version": self._metadata.get("feature_version", FEATURE_VERSION),
                "trained_at": self._metadata.get("trained_at"),
                "model_path": self.settings.ml_model_path,
                "metadata_path": self.settings.ml_metadata_path,
                "predictions_total": predictions_total,
                "unknown_total": int(self._analytics["unknown_total"]),
                "phishing_total": int(self._analytics["phishing_total"]),
                "benign_total": int(self._analytics["benign_total"]),
                "average_probability": round(avg_probability, 4),
                "last_prediction_utc": self._analytics["last_prediction_utc"],
                "top_features": self._top_features(limit=5),
            }

    def scan(self, features: dict[str, Any]) -> dict[str, Any]:
        if not self.settings.ml_enabled:
            return {
                "status": "unknown",
                "unknown_reason": "ml_disabled",
                "risk_score": 0,
                "prediction": "unknown",
                "probability": 0.0,
                "model_version": None,
                "feature_version": FEATURE_VERSION,
                "top_features": [],
            }

        self._ensure_loaded()
        if self._model is None:
            self._record_unknown()
            return {
                "status": "unknown",
                "unknown_reason": "model_unavailable",
                "risk_score": 0,
                "prediction": "unknown",
                "probability": 0.0,
                "model_version": self._metadata.get("model_version"),
                "feature_version": self._metadata.get("feature_version", FEATURE_VERSION),
                "top_features": [],
            }

        try:
            feature_names = self._feature_names()
            vector = [vectorize_features(features, feature_names)]
            if hasattr(self._model, "predict_proba"):
                probability = float(self._model.predict_proba(vector)[0][1])
            elif tf is not None and isinstance(self._model, tf.keras.Model):
                if np is None:
                    raise RuntimeError("numpy_not_installed")
                prediction = self._model.predict(np.asarray(vector, dtype="float32"), verbose=0)
                probability = _extract_probability(prediction)
            else:
                prediction = self._model.predict(vector)[0]
                probability = float(prediction)
            threshold = float(self._metadata.get("classification_threshold", 0.5) or 0.5)
            prediction_label = "phishing" if probability >= threshold else "benign"
            self._record_prediction(probability)
            return {
                "status": "ok",
                "risk_score": round(probability * 100, 2),
                "prediction": prediction_label,
                "probability": round(probability, 6),
                "model_version": self._metadata.get("model_version"),
                "model_type": self._metadata.get("model_type", "tensorflow_dense"),
                "feature_version": self._metadata.get("feature_version", FEATURE_VERSION),
                "top_features": self._top_features(limit=5),
            }
        except Exception as exc:  # pragma: no cover - defensive runtime path.
            self._record_unknown()
            return {
                "status": "unknown",
                "unknown_reason": "inference_failed",
                "error": str(exc),
                "risk_score": 0,
                "prediction": "unknown",
                "probability": 0.0,
                "model_version": self._metadata.get("model_version"),
                "feature_version": self._metadata.get("feature_version", FEATURE_VERSION),
                "top_features": [],
            }

    def _feature_names(self) -> tuple[str, ...]:
        feature_names = self._metadata.get("feature_names")
        if isinstance(feature_names, list) and feature_names:
            return tuple(str(value) for value in feature_names)
        return FEATURE_FIELDS

    def _artifact_state(self) -> tuple[float | None, float | None]:
        model_mtime = None
        metadata_mtime = None
        model_path = Path(self.settings.ml_model_path)
        metadata_path = Path(self.settings.ml_metadata_path)
        if model_path.exists():
            model_mtime = model_path.stat().st_mtime
        if metadata_path.exists():
            metadata_mtime = metadata_path.stat().st_mtime
        return model_mtime, metadata_mtime

    def _ensure_loaded(self) -> None:
        signature = self._artifact_state()
        with self._lock:
            if signature == self._artifact_signature:
                return
            self._artifact_signature = signature
            self._model = None
            self._metadata = {}

            model_path = Path(self.settings.ml_model_path)
            metadata_path = Path(self.settings.ml_metadata_path)
            if metadata_path.exists():
                try:
                    self._metadata = json.loads(metadata_path.read_text(encoding="utf-8"))
                except Exception:
                    self._metadata = {"load_error": "invalid_metadata"}
            if not model_path.exists():
                return
            try:
                if model_path.suffix.lower() == ".joblib":
                    if joblib is None:
                        self._metadata["load_error"] = "joblib_not_installed"
                        self._model = None
                        return
                    self._model = joblib.load(model_path)
                else:
                    if tf is None:
                        self._metadata["load_error"] = "tensorflow_not_installed"
                        self._model = None
                        return
                    self._model = tf.keras.models.load_model(model_path, compile=False)
            except Exception as exc:
                self._metadata["load_error"] = str(exc)
                self._model = None

    def _record_prediction(self, probability: float) -> None:
        with self._lock:
            self._analytics["predictions_total"] += 1
            self._analytics["probability_sum"] += probability
            if probability >= 0.5:
                self._analytics["phishing_total"] += 1
            else:
                self._analytics["benign_total"] += 1
            self._analytics["last_prediction_utc"] = datetime.now(timezone.utc).isoformat()

    def _record_unknown(self) -> None:
        with self._lock:
            self._analytics["unknown_total"] += 1
            self._analytics["last_prediction_utc"] = datetime.now(timezone.utc).isoformat()

    def _top_features(self, limit: int = 5) -> list[dict[str, Any]]:
        metadata_features = self._metadata.get("feature_importance")
        if isinstance(metadata_features, list) and metadata_features:
            return [
                {
                    "feature": str(item.get("feature") or ""),
                    "importance": round(float(item.get("importance") or 0.0), 6),
                }
                for item in metadata_features[:limit]
                if item.get("feature")
            ]
        if self._model is None or not hasattr(self._model, "feature_importances_"):
            return []
        feature_names = self._feature_names()
        importances = list(getattr(self._model, "feature_importances_", []))
        if not importances:
            return []
        ranked = sorted(
            zip(feature_names, importances, strict=False),
            key=lambda item: item[1],
            reverse=True,
        )
        top = [
            {"feature": feature, "importance": round(float(importance), 6)}
            for feature, importance in ranked
            if float(importance) > 0
        ]
        return top[:limit]


def _extract_probability(prediction: Any) -> float:
    if np is not None:
        values = np.asarray(prediction).reshape(-1)
        if values.size == 1:
            return float(values[0])
        if values.size >= 2:
            return float(values[-1])
    if isinstance(prediction, (list, tuple)) and prediction:
        first = prediction[0]
        if isinstance(first, (list, tuple)) and first:
            return float(first[-1])
        return float(first)
    return float(prediction)

from __future__ import annotations

from dataclasses import dataclass
import ipaddress
from urllib.parse import parse_qsl, urlencode, urlparse, urlunparse


@dataclass(frozen=True)
class NormalizedTarget:
    original: str
    normalized_url: str
    scheme: str
    host: str
    port: int | None
    path: str
    query: str
    is_ip: bool


def is_ip_address(value: str) -> bool:
    try:
        ipaddress.ip_address(value)
        return True
    except ValueError:
        return False


def normalize_host(host: str) -> str:
    return host.strip().lower().rstrip(".")


def normalize_input_url(raw_url: str) -> NormalizedTarget:
    value = (raw_url or "").strip()
    if not value:
        raise ValueError("URL is required.")

    if "://" not in value:
        value = f"http://{value}"

    parsed = urlparse(value)
    host = normalize_host(parsed.hostname or "")
    if not host:
        raise ValueError("URL host is missing or invalid.")

    scheme = (parsed.scheme or "http").lower()
    path = parsed.path or "/"
    sorted_query = urlencode(sorted(parse_qsl(parsed.query, keep_blank_values=True)))

    port = parsed.port
    # Remove default ports for canonical comparisons.
    if (scheme == "http" and port == 80) or (scheme == "https" and port == 443):
        port = None

    netloc = host if port is None else f"{host}:{port}"
    normalized_url = urlunparse((scheme, netloc, path, "", sorted_query, ""))

    return NormalizedTarget(
        original=raw_url,
        normalized_url=normalized_url,
        scheme=scheme,
        host=host,
        port=port,
        path=path,
        query=sorted_query,
        is_ip=is_ip_address(host),
    )


def normalize_feed_value(value: str) -> tuple[str, str] | None:
    """
    Normalize feed values into lookup keys.

    Returns tuple(kind, key), where kind is one of:
    - "url"
    - "host"
    - "ip"
    """
    raw = (value or "").strip()
    if not raw:
        return None

    if "://" in raw:
        target = normalize_input_url(raw)
        return ("url", target.normalized_url)

    host_candidate = normalize_host(raw)
    if is_ip_address(host_candidate):
        return ("ip", host_candidate)

    # Accept bare hostnames from feeds.
    if "." in host_candidate:
        return ("host", host_candidate)

    return None

from __future__ import annotations

from typing import Any
from typing import Callable

from scanner.content import ContentScanner
from scanner.domain_age import DomainAgeScanner
from scanner.feed_ingest import ThreatFeedCache
from scanner.heuristics import URLHeuristics
from scanner.ml_features import extract_features
from scanner.ml_model import MLScanner
from scanner.normalization import normalize_input_url
from scanner.settings import ScannerSettings
from scanner.ssl_check import SSLValidator
from scanner.threat_intel import ThreatIntelScanner


class ScanService:
    def __init__(self, settings: ScannerSettings, feed_cache: ThreatFeedCache):
        self.settings = settings
        self.feed_cache = feed_cache
        self.ml_scanner = MLScanner(settings)

    def scan_combined(self, raw_url: str) -> dict[str, Any]:
        return self._scan_combined(raw_url)

    def scan_combined_with_progress(
        self,
        raw_url: str,
        progress_callback: Callable[[dict[str, Any]], None] | None = None,
    ) -> dict[str, Any]:
        return self._scan_combined(raw_url, progress_callback=progress_callback)

    def _scan_combined(
        self,
        raw_url: str,
        progress_callback: Callable[[dict[str, Any]], None] | None = None,
    ) -> dict[str, Any]:
        target = normalize_input_url(raw_url)
        details = self._run_combined_checks(target, progress_callback=progress_callback)
        ml_result = self._run_ml_check(
            target,
            details,
            progress_callback=progress_callback,
        )
        details["ml"] = ml_result
        brand_impersonation = self._brand_impersonation_summary(target, details)

        score, contributing_checks, unknown_checks = self._weighted_score(details)
        return {
            "url": target.normalized_url,
            "risk_score": round(score, 2),
            "contributing_checks": contributing_checks,
            "unknown_checks": unknown_checks,
            "feed_freshness": self.feed_cache.metadata(),
            "brand_impersonation": brand_impersonation,
            "details": details,
        }

    def scan_heuristics(self, raw_url: str) -> dict[str, Any]:
        return URLHeuristics(normalize_input_url(raw_url)).run_checks()

    def scan_content(self, raw_url: str) -> dict[str, Any]:
        return ContentScanner(normalize_input_url(raw_url), self.settings).run_checks()

    def scan_ssl(self, raw_url: str) -> dict[str, Any]:
        return SSLValidator(normalize_input_url(raw_url), self.settings).run_checks()

    def scan_whois(self, raw_url: str) -> dict[str, Any]:
        return DomainAgeScanner(normalize_input_url(raw_url)).run_checks()

    def scan_threats(self, raw_url: str) -> dict[str, Any]:
        return ThreatIntelScanner(normalize_input_url(raw_url), self.feed_cache).run_checks()

    def scan_ml(self, raw_url: str) -> dict[str, Any]:
        target = normalize_input_url(raw_url)
        details = self._run_combined_checks(target)
        features = extract_features(target, details)
        ml_result = self.ml_scanner.scan(features)
        return {
            "url": target.normalized_url,
            "ml": ml_result,
            "features": features,
            "details": details,
            "analytics": self.ml_scanner.analytics(),
        }

    def ml_overview(self) -> dict[str, Any]:
        return self.ml_scanner.analytics()

    def refresh_feeds(self) -> dict[str, Any]:
        self.feed_cache.refresh_now()
        return {"status": "ok", "feed_freshness": self.feed_cache.metadata()}

    def _run_combined_checks(
        self,
        target,
        progress_callback: Callable[[dict[str, Any]], None] | None = None,
    ) -> dict[str, dict[str, Any]]:
        check_runners: tuple[tuple[str, Callable[[], dict[str, Any]]], ...] = (
            ("heuristics", lambda: URLHeuristics(target).run_checks()),
            ("content", lambda: ContentScanner(target, self.settings).run_checks()),
            ("ssl", lambda: SSLValidator(target, self.settings).run_checks()),
            ("domain_age", lambda: DomainAgeScanner(target).run_checks()),
            ("threat_intel", lambda: ThreatIntelScanner(target, self.feed_cache).run_checks()),
        )
        details: dict[str, dict[str, Any]] = {}

        for name, runner in check_runners:
            if progress_callback:
                progress_callback({"type": "check_started", "check": name})
            result = runner()
            details[name] = result
            if progress_callback:
                progress_callback(
                    {
                        "type": "check_completed",
                        "check": name,
                        "status": result.get("status", "ok"),
                        "risk_score": result.get("risk_score", 0),
                    }
                )
        return details

    def _run_ml_check(
        self,
        target,
        details: dict[str, dict[str, Any]],
        progress_callback: Callable[[dict[str, Any]], None] | None = None,
    ) -> dict[str, Any]:
        if progress_callback:
            progress_callback({"type": "check_started", "check": "ml"})
        features = extract_features(target, details)
        result = self.ml_scanner.scan(features)
        if progress_callback:
            progress_callback(
                {
                    "type": "check_completed",
                    "check": "ml",
                    "status": result.get("status", "unknown"),
                    "risk_score": result.get("risk_score", 0),
                }
            )
        return result

    def _weighted_score(self, details: dict[str, dict[str, Any]]) -> tuple[float, list[str], list[str]]:
        weights = {
            "heuristics": self.settings.weights_heuristics,
            "content": self.settings.weights_content,
            "ssl": self.settings.weights_ssl,
            "domain_age": self.settings.weights_domain_age,
            "threat_intel": self.settings.weights_threat_intel,
            "ml": self.settings.weights_ml,
        }

        numerator = 0.0
        denominator = 0.0
        contributing: list[str] = []
        unknown: list[str] = []

        for name, result in details.items():
            status = result.get("status", "ok")
            if status != "ok":
                unknown.append(name)
                continue
            component = float(result.get("risk_score", 0))
            weight = float(weights.get(name, 0.0))
            if weight <= 0:
                continue
            numerator += component * weight
            denominator += weight
            contributing.append(name)

        if denominator == 0:
            return 0.0, contributing, unknown
        return numerator / denominator, contributing, unknown

    def _brand_impersonation_summary(
        self,
        target,
        details: dict[str, dict[str, Any]],
    ) -> dict[str, Any]:
        content = details.get("content") or {}
        candidates = list(content.get("brand_candidates") or [])
        detected_brand = content.get("detected_brand") or ""
        host_provider = content.get("host_provider") or ""
        reasons = list(content.get("impersonation_reasons") or [])
        return {
            "detected_brand": detected_brand,
            "free_host_provider": host_provider,
            "brand_mismatch": bool(content.get("brand_mismatch")),
            "brand_path_match": bool(content.get("brand_path_match")),
            "login_form_present": bool(content.get("login_form_present")),
            "password_field_count": int(content.get("password_field_count") or 0),
            "form_action_mismatch": bool(content.get("form_action_mismatch")),
            "suspicious_phrase_hits": list(content.get("suspicious_phrase_hits") or []),
            "brand_candidates": candidates[:3],
            "reasons": reasons[:8],
            "target_host": target.host,
        }

