def _bool_env(name: str, default: bool) -> bool: value = os.getenv(name) if value is None: return default return value.strip().lower() in {"1", "true", "yes", "on"}
def _int_env(name: str, default: int) -> int: value = os.getenv(name) if value is None: return default try: return int(value) except ValueError: return default
def _float_env(name: str, default: float) -> float: value = os.getenv(name) if value is None: return default try: return float(value) except ValueError: return default

import ssl
import socket
import datetime
from scanner.normalization import NormalizedTarget
from scanner.settings import ScannerSettings

class SSLValidator:
    def __init__(self, target: NormalizedTarget, settings: ScannerSettings):
        self.target = target
        self.settings = settings
        self.hostname = target.host
        self.port = target.port or 443

    def get_certificate_info(self):
        """Fetch and parse the SSL certificate."""
        context = ssl.create_default_context()
        try:
            with socket.create_connection(
                (self.hostname, self.port),
                timeout=self.settings.request_timeout_seconds,
            ) as sock:
                with context.wrap_socket(sock, server_hostname=self.hostname) as ssock:
                    cert = ssock.getpeercert()
                    return cert
        except Exception:
            return None

    def check_validity(self, cert) -> bool:
        """Check if the certificate is currently valid."""
        if not cert:
            return False

        not_after_str = cert.get('notAfter')
        if not not_after_str:
            return False

        not_after = datetime.datetime.strptime(not_after_str, '%b %d %H:%M:%S %Y %Z')
        return datetime.datetime.utcnow() < not_after

    def check_issuer(self, cert) -> bool:
        """A successful verified handshake implies trusted issuer chain."""
        if not cert:
            return False
        return True

    def _name_to_dict(self, name_tuple):
        return dict(item[0] for item in name_tuple)

    def check_self_signed(self, cert) -> bool:
        if not cert:
            return False
        issuer = self._name_to_dict(cert.get("issuer", ()))
        subject = self._name_to_dict(cert.get("subject", ()))
        return bool(issuer) and issuer == subject

    def check_protocol_version(self) -> str:
        """Check the SSL/TLS protocol version."""
        context = ssl.create_default_context()
        try:
            with socket.create_connection(
                (self.hostname, self.port),
                timeout=self.settings.request_timeout_seconds,
            ) as sock:
                with context.wrap_socket(sock, server_hostname=self.hostname) as ssock:
                    return ssock.version()
        except Exception:
            return "Unknown"

    def run_checks(self) -> dict:
        if self.target.scheme != "https":
            return {
                "status": "unknown",
                "unknown_reason": "ssl_check_skipped_for_non_https",
                "valid_cert": False,
                "trusted_issuer": False,
                "protocol_version": "Unknown",
                "risk_score": 0,
            }

        cert = self.get_certificate_info()

        if not cert:
            return {
                "status": "unknown",
                "unknown_reason": "certificate_unavailable",
                "valid_cert": False,
                "trusted_issuer": False,
                "protocol_version": "Unknown",
                "risk_score": 0,
            }

        valid = self.check_validity(cert)
        trusted = self.check_issuer(cert)
        protocol = self.check_protocol_version()
        self_signed = self.check_self_signed(cert)

        score = 0
        if not valid:
            score += 50
        if self_signed:
            score += 30
        # Check for old protocols (TLS 1.0, 1.1, SSLv3)
        if protocol in ["TLSv1", "TLSv1.1", "SSLv3"]:
            score += 30

        return {
            "status": "ok",
            "valid_cert": valid,
            "trusted_issuer": trusted,
            "self_signed": self_signed,
            "protocol_version": protocol,
            "risk_score": min(score, 100),
        }

from scanner.feed_ingest import ThreatFeedCache
from scanner.normalization import NormalizedTarget

class ThreatIntelScanner:
    def __init__(self, target: NormalizedTarget, feed_cache: ThreatFeedCache):
        self.target = target
        self.feed_cache = feed_cache

    def run_checks(self) -> dict:
        return self.feed_cache.lookup(self.target)

from __future__ import annotations
import csv from collections import Counter from dataclasses import dataclass from datetime import datetime, timezone import re from pathlib import Path import sys from typing import Any from urllib.parse import urlparse
ROOT = Path(__file__).resolve().parent.parent if str(ROOT) not in sys.path: sys.path.insert(0, str(ROOT))
from scanner.brand_profiles import guess_host_provider from scanner.brand_profiles import load_brand_profiles from scanner.brand_profiles import normalize_brand_token
PROJECT_ROOT = Path(__file__).resolve().parent.parent OLD_DATA_DIR = PROJECT_ROOT / "old-data" BASELINE_CSV = OLD_DATA_DIR / "baseline.csv" SCORED_CSV = OLD_DATA_DIR / "baseline_scored.csv" OUTPUT_MD = OLD_DATA_DIR / "14-brand-login-eda.md"
SUSPICIOUS_TOKENS = ( "login", "signin", "sign", "verify", "update", "secure", "account", "password", "confirm", "auth", "security", )
@dataclass(frozen=True) class EDAStats: total_rows: int phishing_rows: int legitimate_rows: int hostname_missing: int url_missing: int token_counts: Counter[str] brand_counts: Counter[str] free_host_counts: Counter[str] host_suffix_counts: Counter[str]
def read_rows(path: Path) -> list[dict[str, str]]: with path.open("r", newline="", encoding="utf-8") as handle: return list(csv.DictReader(handle))
def parse_bool(value: Any) -> bool | None: normalized = str(value or "").strip().lower() if normalized in {"1", "true", "t", "yes", "y"}: return True if normalized in {"0", "false", "f", "no", "n"}: return False return None
def normalize_host(value: str) -> str: candidate = str(value or "").strip().lower() if not candidate: return "" parsed = urlparse(candidate if "://" in candidate else f"http://{candidate}") host = parsed.netloc.lower() or parsed.path.lower() return host.split("@")[-1].split(":")[0]
def extract_path(url: str) -> str: parsed = urlparse(url if "://" in url else f"http://{url}") return f"{parsed.path} {parsed.query}".lower()
def token_counts(rows: list[dict[str, str]]) -> Counter[str]: counts: Counter[str] = Counter() for row in rows: corpus = f"{row.get('url', '')} {row.get('hostname', '')}".lower() for token in SUSPICIOUS_TOKENS: if token in corpus: counts[token] += 1 return counts
def brand_counts(rows: list[dict[str, str]]) -> Counter[str]: profiles = load_brand_profiles() counts: Counter[str] = Counter() for row in rows: corpus = normalize_brand_token(f"{row.get('url', '')} {row.get('hostname', '')}") for profile in profiles: tokens = profile.normalized_keywords() if any(token and token in corpus for token in tokens): counts[profile.name] += 1 return counts
def free_host_counts(rows: list[dict[str, str]]) -> Counter[str]: counts: Counter[str] = Counter() for row in rows: host = normalize_host(row.get("hostname") or row.get("url") or "") provider = guess_host_provider(host) if provider: counts[provider] += 1 return counts
def host_suffix_counts(rows: list[dict[str, str]]) -> Counter[str]: counts: Counter[str] = Counter() for row in rows: host = normalize_host(row.get("hostname") or row.get("url") or "") if not host: continue parts = host.split(".") suffix = ".".join(parts[-2:]) if len(parts) >= 2 else host counts[suffix] += 1 return counts
def summarize_baseline(rows: list[dict[str, str]]) -> EDAStats: total_rows = len(rows) phishing_rows = 0 legitimate_rows = 0 hostname_missing = 0 url_missing = 0 for row in rows: label = parse_bool(row.get("is_phishing")) if label is True: phishing_rows += 1 elif label is False: legitimate_rows += 1 if not str(row.get("hostname") or "").strip(): hostname_missing += 1 if not str(row.get("url") or "").strip(): url_missing += 1 return EDAStats( total_rows=total_rows, phishing_rows=phishing_rows, legitimate_rows=legitimate_rows, hostname_missing=hostname_missing, url_missing=url_missing, token_counts=token_counts(rows), brand_counts=brand_counts(rows), free_host_counts=free_host_counts(rows), host_suffix_counts=host_suffix_counts(rows), )
def count_missing(rows: list[dict[str, str]], columns: list[str]) -> dict[str, float]: if not rows: return {column: 0.0 for column in columns} result: dict[str, float] = {} total = len(rows) for column in columns: missing = sum(1 for row in rows if not str(row.get(column) or "").strip()) result[column] = round(missing / total, 4) return result
def evaluate_scored(rows: list[dict[str, str]]) -> dict[str, Any]: scored_rows: list[dict[str, Any]] = [] errors: list[dict[str, Any]] = [] tp = tn = fp = fn = 0 for row in rows: actual = parse_bool(row.get("is_phishing")) score = row.get("risk_score") predicted = parse_bool(row.get("predicted_is_phishing")) error = str(row.get("api_error") or "").strip() if error: errors.append({"url": row.get("url", ""), "error": error}) continue if actual is None or predicted is None or not str(score or "").strip(): continue scored_rows.append( { "url": row.get("url", ""), "hostname": row.get("hostname", ""), "risk_score": float(score), "actual": actual, "predicted": predicted, } ) if actual and predicted: tp += 1 elif not actual and not predicted: tn += 1 elif predicted and not actual: fp += 1 else: fn += 1
total = tp + tn + fp + fn precision = tp / (tp + fp) if tp + fp else 0.0 recall = tp / (tp + fn) if tp + fn else 0.0 f1 = (2 * precision * recall / (precision + recall)) if precision + recall else 0.0 accuracy = (tp + tn) / total if total else 0.0
false_positives = sorted( [row for row in scored_rows if row["predicted"] and not row["actual"]], key=lambda item: item["risk_score"], reverse=True, )[:5] false_negatives = sorted( [row for row in scored_rows if not row["predicted"] and row["actual"]], key=lambda item: item["risk_score"], reverse=True, )[:5] return { "total": total, "scored_rows": len(scored_rows), "errors": errors, "confusion_matrix": {"tp": tp, "tn": tn, "fp": fp, "fn": fn}, "accuracy": round(accuracy, 4), "precision": round(precision, 4), "recall": round(recall, 4), "f1": round(f1, 4), "false_positives": false_positives, "false_negatives": false_negatives, }
def markdown_table(rows: list[tuple[str, Any]], headers: tuple[str, str] = ("Metric", "Value")) -> str: lines = [f"| {headers[0]} | {headers[1]} |", "|---|---|"] for key, value in rows: lines.append(f"| {key} | {value} |") return "\n".join(lines)
def ranked_rows(counter: Counter[str], limit: int = 8) -> list[tuple[str, int]]: return counter.most_common(limit)
def format_list(items: list[str]) -> str: return "\n".join(f"- {item}" for item in items) if items else "- None"
def format_example_rows(rows: list[dict[str, Any]]) -> str: if not rows: return "- None" lines = [] for row in rows: lines.append( f"- `{row.get('url', '')}` | score `{float(row.get('risk_score', 0)):.2f}` | host `{row.get('hostname', '')}`" ) return "\n".join(lines)
def build_report(baseline_stats: EDAStats, scored_stats: dict[str, Any], baseline_rows: list[dict[str, str]], scored_rows: list[dict[str, str]]) -> str: missing_baseline = count_missing(baseline_rows, ["url", "is_phishing", "hostname"]) missing_scored = count_missing(scored_rows, ["url", "is_phishing", "hostname", "risk_score", "predicted_is_phishing", "api_error"]) brand_lines = [f"{brand} ({count})" for brand, count in ranked_rows(baseline_stats.brand_counts, 8)] host_lines = [f"{provider} ({count})" for provider, count in ranked_rows(baseline_stats.free_host_counts, 8)] token_lines = [f"{token} ({count})" for token, count in ranked_rows(baseline_stats.token_counts, 8)] suffix_lines = [f"{suffix} ({count})" for suffix, count in ranked_rows(baseline_stats.host_suffix_counts, 8)]
report = f"""# Brand Login EDA Summary
Generated on `{datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M UTC")}` from `old-data/baseline.csv` and `old-data/baseline_scored.csv`.
## Dataset Snapshot
{markdown_table([ ("Total rows", baseline_stats.total_rows), ("Phishing rows", baseline_stats.phishing_rows), ("Legitimate rows", baseline_stats.legitimate_rows), ("Phishing rate", f"{(baseline_stats.phishing_rows / baseline_stats.total_rows * 100):.1f}%" if baseline_stats.total_rows else "n/a"), ("Missing URL rate", f"{missing_baseline.get('url', 0.0) * 100:.1f}%"), ("Missing hostname rate", f"{missing_baseline.get('hostname', 0.0) * 100:.1f}%"), ])}
## Class Balance
- The dataset is intentionally close to a binary phishing-vs-legitimate setup. - The positive class is phishing pages that impersonate login flows. - The negative class is legitimate or non-impersonating pages.
## Brand Signals In URLs
{format_list(brand_lines)}
## Suspicious Path Tokens
{format_list(token_lines)}
## Host Pattern Signals
Free-host provider counts:
{format_list(host_lines)}
Common host suffixes:
{format_list(suffix_lines)}
## Missing Data
Baseline CSV:
{markdown_table([(key, f"{value * 100:.1f}%") for key, value in missing_baseline.items()], headers=("Column", "Missing"))}
Scored CSV:
{markdown_table([(key, f"{value * 100:.1f}%") for key, value in missing_scored.items()], headers=("Column", "Missing"))}
## Evaluation Snapshot
{markdown_table([ ("Scored rows", scored_stats["scored_rows"]), ("Accuracy", f"{scored_stats['accuracy']:.4f}"), ("Precision", f"{scored_stats['precision']:.4f}"), ("Recall", f"{scored_stats['recall']:.4f}"), ("F1", f"{scored_stats['f1']:.4f}"), ("TP", scored_stats["confusion_matrix"]["tp"]), ("TN", scored_stats["confusion_matrix"]["tn"]), ("FP", scored_stats["confusion_matrix"]["fp"]), ("FN", scored_stats["confusion_matrix"]["fn"]), ])}
## False Positives
{format_example_rows(scored_stats["false_positives"])}
## False Negatives
{format_example_rows(scored_stats["false_negatives"])}
## Takeaways
- Brand-bearing paths and free-host infrastructure are common phishing indicators in this dataset. - The evaluation snapshot is useful for threshold tuning and error analysis rather than as a final guarantee. - The strongest capstone story is the combination of label collection, feature engineering, and hybrid detection. """ return report
def main() -> int: baseline_rows = read_rows(BASELINE_CSV) scored_rows = read_rows(SCORED_CSV) baseline_stats = summarize_baseline(baseline_rows) scored_stats = evaluate_scored(scored_rows) report = build_report(baseline_stats, scored_stats, baseline_rows, scored_rows) OUTPUT_MD.write_text(report, encoding="utf-8") print(f"Wrote {OUTPUT_MD}") return 0
if __name__ == "__main__": raise SystemExit(main())

const form = document.getElementById("scan-form");
const statusEl = document.getElementById("status");
const statusMessageEl = document.getElementById("status-message");
const statusDetailEl = document.getElementById("status-detail");
const summaryEl = document.getElementById("summary");
const detailsEl = document.getElementById("details");
const urlInput = document.getElementById("url-input");
const scanBtn = form?.querySelector('button[type="submit"]');

const summaryUrl = document.getElementById("summary-url");
const summaryRisk = document.getElementById("summary-risk");
const summaryBand = document.getElementById("summary-band");
const summaryState = document.getElementById("summary-state");
const summaryGuidance = document.getElementById("summary-guidance");
const summaryAction = document.getElementById("summary-action");
const summaryContrib = document.getElementById("summary-contrib");
const summaryUnknown = document.getElementById("summary-unknown");
const summaryHybrid = document.getElementById("summary-hybrid");
const summaryVerdict = document.getElementById("summary-verdict");
const brandValue = document.getElementById("brand-value");
const hostValue = document.getElementById("host-value");
const formValue = document.getElementById("form-value");
const phrasesValue = document.getElementById("phrases-value");
const pathValue = document.getElementById("path-value");
const explanationValue = document.getElementById("summary-explanation");
const detailsJson = document.getElementById("details-json");
const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

const loadingDetailSteps = [
  "Normalizing the URL and preparing the page snapshot.",
  "Reading the visible text, forms, and login structure.",
  "Comparing the host, brand name, and suspicious phrases.",
  "Blending FastText, rules, and evidence into the final demo result.",
];

let loadingDetailTimer = null;
let statusSignature = "";
let scoreAnimationFrame = 0;

function defaultStatusDetail(tone) {
  if (tone === "danger") {
    return "The page needs manual review before anyone should trust it.";
  }
  if (tone === "warn") {
    return "The page looks suspicious enough to pause and inspect further.";
  }
  if (tone === "ok") {
    return "The page does not show strong impersonation signals in this pass.";
  }
  return "Paste a suspicious link to start the demo.";
}

function setStatus(message, tone = "muted", detail = defaultStatusDetail(tone)) {
  const signature = `${tone}::${message}::${detail}`;
  if (signature === statusSignature) {
    return;
  }
  statusSignature = signature;
  statusMessageEl.textContent = message;
  statusDetailEl.textContent = detail;
  statusEl.classList.remove("muted", "ok", "caution", "warn", "danger", "status-swap");
  statusEl.classList.add(tone);
  if (tone === "muted") {
    delete statusEl.dataset.tone;
  } else {
    statusEl.dataset.tone = tone;
  }
  requestAnimationFrame(() => statusEl.classList.add("status-swap"));
}

function startLoadingDetails() {
  stopLoadingDetails();
  let stepIndex = 0;
  statusDetailEl.textContent = loadingDetailSteps[stepIndex];
  if (prefersReducedMotion) {
    return;
  }
  loadingDetailTimer = window.setInterval(() => {
    stepIndex = (stepIndex + 1) % loadingDetailSteps.length;
    statusDetailEl.textContent = loadingDetailSteps[stepIndex];
  }, 1200);
}

function stopLoadingDetails() {
  if (loadingDetailTimer) {
    window.clearInterval(loadingDetailTimer);
    loadingDetailTimer = null;
  }
}

function setScanLoading(isLoading) {
  if (!form || !scanBtn || !urlInput) {
    return;
  }
  form.classList.toggle("is-scanning", isLoading);
  scanBtn.disabled = isLoading;
  scanBtn.setAttribute("aria-busy", String(isLoading));
  scanBtn.textContent = isLoading ? "Running Demo..." : "Run Demo";
  urlInput.readOnly = isLoading;
  statusEl.classList.toggle("status-loading", isLoading);
  if (isLoading) {
    startLoadingDetails();
  } else {
    stopLoadingDetails();
  }
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function renderTokenList(element, values, emptyLabel, tone = "neutral") {
  if (!element) return;
  element.textContent = "";
  const entries = Array.isArray(values) && values.length > 0 ? values : [emptyLabel];
  entries.forEach((value) => {
    const token = document.createElement("span");
    token.className = `token token-${tone}`;
    token.textContent = value;
    element.appendChild(token);
  });
}

function setStatusPill(element, value, yesLabel, noLabel, yesTone, noTone) {
  if (!element) return;
  const isYes = Boolean(value);
  element.textContent = isYes ? yesLabel : noLabel;
  element.className = `status-pill ${isYes ? yesTone : noTone}`;
}

function scoreTone(score) {
  if (score >= 75) return { tone: "danger", label: "High risk", band: "75-100: strong phishing indicators" };
  if (score >= 50) return { tone: "warn", label: "Suspicious", band: "50-74: suspicious enough to review" };
  if (score >= 25) return { tone: "caution", label: "Use caution", band: "25-49: mixed signals" };
  return { tone: "ok", label: "Low apparent risk", band: "0-24: no strong indicators" };
}

function animateScore(targetScore) {
  if (!summaryRisk) return;
  window.cancelAnimationFrame(scoreAnimationFrame);
  const startValue = Number(summaryRisk.dataset.value || 0);
  const endValue = Math.max(0, Math.min(100, Number(targetScore) || 0));
  if (prefersReducedMotion) {
    summaryRisk.textContent = `${Math.round(endValue)}`;
    summaryRisk.dataset.value = `${endValue}`;
    return;
  }
  const start = performance.now();
  const duration = 650;

  function tick(now) {
    const progress = Math.min((now - start) / duration, 1);
    const eased = 1 - Math.pow(1 - progress, 4);
    const nextValue = startValue + (endValue - startValue) * eased;
    summaryRisk.textContent = `${Math.round(nextValue)}`;
    summaryRisk.dataset.value = `${nextValue}`;
    if (progress < 1) {
      scoreAnimationFrame = window.requestAnimationFrame(tick);
    }
  }

  scoreAnimationFrame = window.requestAnimationFrame(tick);
}

function explanationFromResult(result) {
  const notes = [];
  const brandSummary = result.brand_impersonation || {};
  if (brandSummary.detected_brand && brandSummary.brand_mismatch) {
    notes.push(`Looks like a ${brandSummary.detected_brand} login clone.`);
  }
  if (brandSummary.free_host_provider) {
    notes.push(`Hosted on ${brandSummary.free_host_provider}-style free infrastructure.`);
  }
  if ((brandSummary.suspicious_phrase_hits || []).length > 0) {
    notes.push("Uses common phishing language.");
  }
  if (brandSummary.login_form_present) {
    notes.push("Contains a login form with password input.");
  }
  if (result.override_applied && result.override_reason) {
    notes.push(`Final decision overridden because of ${result.override_reason}.`);
  }
  return notes.join(" ");
}

function scoreText(block) {
  if (!block) return { score: 0, label: "n/a" };
  const rawScore = block.score ?? block.risk_score;
  const fallbackScore = Number.isFinite(Number(block.probability)) ? Number(block.probability) * 100 : 0;
  const score = Number.isFinite(Number(rawScore)) ? Number(rawScore) : fallbackScore;
  const label = block.label || block.prediction || "unknown";
  return { score, label };
}

function renderResult(result) {
  const fasttext = result.fasttext || {};
  const rules = result.rules || {};
  const hybridScore = Number(result.hybrid_score ?? 0);
  const fasttextScore = scoreText(fasttext).score || Number(result.risk_score || 0);
  const fasttextLabel = scoreText(fasttext).label;
  const rulesScore = Number(rules.risk_score ?? 0);
  const rulesLabel = rules.prediction || "unknown";
  const finalScore = Number(result.risk_score ?? hybridScore ?? rulesScore ?? 0);
  const tone = scoreTone(finalScore);
  const explanation = explanationFromResult(result);
  const brandSummary = result.brand_impersonation || {};
  const finalVerdict = result.prediction || fasttextLabel || "unknown";

  summaryEl.classList.remove("hidden");
  detailsEl.classList.remove("hidden");

  summaryUrl.textContent = result.url || "-";
  summaryRisk.textContent = `${Math.round(fasttextScore)}`;
  summaryRisk.dataset.value = `${fasttextScore}`;
  summaryBand.textContent = tone.band;
  summaryState.textContent = tone.label;
  summaryState.className = `summary-state ${tone.tone}`;
  summaryGuidance.textContent = result.override_applied
    ? `FastText predicts ${fasttextLabel} with a score of ${Math.round(fasttextScore)}, but the final verdict is overridden to clean because the site matches an official brand domain.`
    : `FastText predicts ${fasttextLabel} with a score of ${Math.round(fasttextScore)}.`;
  summaryAction.textContent = result.override_applied
    ? `Official domain override applied: ${result.override_reason}.`
    : (rulesScore > 0
      ? `Rules baseline score: ${Math.round(rulesScore)} (${rulesLabel}).`
      : "Rules baseline did not surface strong evidence in this pass.");
  summaryHybrid.textContent = `Hybrid score: ${Math.round(result.override_applied ? 0 : hybridScore)}`;
  summaryHybrid.className = `status-pill ${tone.tone}`;
  summaryVerdict.textContent = finalVerdict;
  summaryVerdict.className = `status-pill ${tone.tone}`;

  brandValue.textContent = brandSummary.detected_brand || "No brand identified";
  hostValue.textContent = brandSummary.free_host_provider
    ? `${brandSummary.free_host_provider} host`
    : (result.details?.host || "Unknown host");
  formValue.textContent = brandSummary.login_form_present
    ? `${brandSummary.password_field_count || 0} password field(s)`
    : "No login form detected";
  pathValue.textContent = brandSummary.brand_path_match
    ? "Brand token appears in the path"
    : "No obvious brand/path match";
  explanationValue.textContent = explanation || "No strong narrative evidence was extracted.";
  renderTokenList(
    phrasesValue,
    brandSummary.suspicious_phrase_hits || result.details?.suspicious_phrase_hits,
    "No suspicious phrases found",
    "warn",
  );
  renderTokenList(summaryContrib, result.contributing_checks, "No dominant signals", "neutral");
  renderTokenList(summaryUnknown, result.unknown_checks, "All checks returned", "warn");

  animateScore(fasttextScore);
  setStatus(
    `${tone.label}. ${result.override_applied ? "Official domain match overrode the model score." : ""} ${explanation || "Review the evidence cards for details."}`.trim(),
    tone.tone,
    explanation || (result.override_applied ? "Official brand domain match." : tone.band),
  );
  detailsJson.textContent = JSON.stringify(result, null, 2);
}

async function scanUrl(url) {
  const response = await fetch("/scan/combined", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ url }),
  });
  const payload = await response.json();
  if (!response.ok) {
    throw new Error(payload.detail || "Scan failed.");
  }
  return payload;
}

if (form) {
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const url = urlInput.value.trim();
    if (!url) {
      setStatus("Please provide a URL.", "warn", "Paste a full URL or a bare domain.");
      return;
    }
    setScanLoading(true);
    setStatus("Running the scan demo...", "muted", loadingDetailSteps[0]);
    const scanStart = performance.now();
    try {
      const result = await scanUrl(url);
      renderResult(result);
    } catch (error) {
      setStatus(
        error.message || "Scan failed.",
        "danger",
        "No trustworthy result was produced. Check connectivity and try again.",
      );
    } finally {
      const elapsed = performance.now() - scanStart;
      const minVisibleLoadingMs = 500;
      if (elapsed < minVisibleLoadingMs) {
        await sleep(minVisibleLoadingMs - elapsed);
      }
      setScanLoading(false);
    }
  });
}

const evaluationForm = document.getElementById("evaluation-form");
const csvFileInput = document.getElementById("csv-file-input");
const thresholdInput = document.getElementById("threshold-input");
const startButton = document.getElementById("start-evaluation");
const fileSummary = document.getElementById("file-summary");
const statusEl = document.getElementById("eval-status");
const statusMessageEl = document.getElementById("eval-status-message");
const statusDetailEl = document.getElementById("eval-status-detail");
const reportShell = document.getElementById("report-shell");
const downloadReport = document.getElementById("download-report");

const totalMetric = document.getElementById("metric-total");
const scoredMetric = document.getElementById("metric-scored");
const accuracyMetric = document.getElementById("metric-accuracy");
const precisionMetric = document.getElementById("metric-precision");
const recallMetric = document.getElementById("metric-recall");
const f1Metric = document.getElementById("metric-f1");
const tpMetric = document.getElementById("metric-tp");
const tnMetric = document.getElementById("metric-tn");
const fpMetric = document.getElementById("metric-fp");
const fnMetric = document.getElementById("metric-fn");
const falsePositiveList = document.getElementById("false-positive-list");
const falseNegativeList = document.getElementById("false-negative-list");
const evaluationNote = document.getElementById("evaluation-note");

let pendingCsvText = "";

function setStatus(message, tone = "muted", detail = "Upload a CSV to run the reviewer workflow.") {
  statusMessageEl.textContent = message;
  statusDetailEl.textContent = detail;
  statusEl.classList.remove("muted", "ok", "warn", "danger");
  statusEl.classList.add(tone);
}

function setBusy(isBusy) {
  if (!startButton || !csvFileInput) return;
  startButton.disabled = isBusy;
  startButton.textContent = isBusy ? "Running Evaluation..." : "Run Evaluation";
  csvFileInput.disabled = isBusy;
}

function formatMetric(value, digits = 4) {
  const number = Number(value);
  if (!Number.isFinite(number)) {
    return "n/a";
  }
  if (Math.abs(number) <= 1) {
    return number.toFixed(digits);
  }
  return String(Math.round(number * 100) / 100);
}

function setText(el, value) {
  if (!el) return;
  el.textContent = value;
}

function renderTokenList(target, items, emptyLabel) {
  if (!target) return;
  target.textContent = "";
  const list = Array.isArray(items) && items.length > 0 ? items : [emptyLabel];
  list.forEach((item) => {
    const token = document.createElement("span");
    token.className = "token";
    token.textContent = item;
    target.appendChild(token);
  });
}

function renderEvaluationReport(reportPayload) {
  const report = reportPayload.report || {};
  const summary = report.summary || {};
  const matrix = report.confusion_matrix || {};
  const falsePositives = report.false_positives || [];
  const falseNegatives = report.false_negatives || [];

  reportShell.classList.remove("hidden");
  setText(totalMetric, summary.total_rows ?? 0);
  setText(scoredMetric, summary.scored_rows ?? 0);
  setText(accuracyMetric, formatMetric(summary.accuracy));
  setText(precisionMetric, formatMetric(summary.precision));
  setText(recallMetric, formatMetric(summary.recall));
  setText(f1Metric, formatMetric(summary.f1));
  setText(tpMetric, matrix.tp ?? 0);
  setText(tnMetric, matrix.tn ?? 0);
  setText(fpMetric, matrix.fp ?? 0);
  setText(fnMetric, matrix.fn ?? 0);
  renderTokenList(
    falsePositiveList,
    falsePositives.map((item) => `${item.url} (${formatMetric(item.risk_score, 2)} · ${item.prediction || "unknown"})`),
    "No false positives",
  );
  renderTokenList(
    falseNegativeList,
    falseNegatives.map((item) => `${item.url} (${formatMetric(item.risk_score, 2)} · ${item.prediction || "unknown"})`),
    "No false negatives",
  );
  if (downloadReport && reportPayload.download_url) {
    downloadReport.href = reportPayload.download_url;
    downloadReport.textContent = "Download scored CSV";
  }
  evaluationNote.textContent = `Accuracy ${formatMetric(summary.accuracy)} | Precision ${formatMetric(summary.precision)} | Recall ${formatMetric(summary.recall)} | F1 ${formatMetric(summary.f1)}`;
  setStatus("Evaluation complete.", "ok", "Review the metrics and example mistakes below.");
}

async function fetchJson(url, options = {}) {
  const response = await fetch(url, options);
  const payload = await response.json();
  if (!response.ok) {
    throw new Error(payload.detail || "Request failed.");
  }
  return payload;
}

csvFileInput?.addEventListener("change", async () => {
  const [file] = csvFileInput.files || [];
  if (!file) {
    pendingCsvText = "";
    fileSummary.textContent = "Use a CSV with `url` and `is_phishing` columns.";
    return;
  }
  fileSummary.textContent = `Selected ${file.name}`;
  pendingCsvText = await file.text();
  const lineCount = pendingCsvText.trim() ? pendingCsvText.trim().split(/\r?\n/).length - 1 : 0;
  fileSummary.textContent = `${file.name} · ${lineCount} data rows ready`;
});

evaluationForm?.addEventListener("submit", async (event) => {
  event.preventDefault();
  const [file] = csvFileInput.files || [];
  if (!file) {
    setStatus("Choose a CSV file first.", "warn", "Use the capstone features CSV or another labeled dataset.");
    return;
  }
  setBusy(true);
  setStatus("Running evaluation...", "muted", "Scoring the uploaded CSV against the current detector.");
  try {
    const csvContent = pendingCsvText || (await file.text());
    const payload = await fetchJson("/evaluate", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        filename: file.name,
        csv_content: csvContent,
        threshold: Number(thresholdInput?.value || 50),
      }),
    });
    renderEvaluationReport(payload);
  } catch (error) {
    setStatus(error.message || "Evaluation failed.", "danger", "The upload could not be scored. Check the CSV format and try again.");
  } finally {
    setBusy(false);
  }
});

const evaluationForm = document.getElementById("evaluation-form");
const csvFileInput = document.getElementById("csv-file-input");
const thresholdInput = document.getElementById("threshold-input");
const startButton = document.getElementById("start-evaluation");
const fileSummary = document.getElementById("file-summary");
const statusEl = document.getElementById("eval-status");
const statusMessageEl = document.getElementById("eval-status-message");
const statusDetailEl = document.getElementById("eval-status-detail");
const jobBadge = document.getElementById("job-badge");
const progressFill = document.getElementById("progress-fill");
const progressText = document.getElementById("progress-text");
const progressPercent = document.getElementById("progress-percent");
const processedCount = document.getElementById("processed-count");
const scoredCount = document.getElementById("scored-count");
const errorCount = document.getElementById("error-count");
const currentUrl = document.getElementById("current-url");
const checkList = document.getElementById("check-list");
const recentRows = document.getElementById("recent-rows");
const reportShell = document.getElementById("report-shell");
const reportSummaryCards = document.getElementById("report-summary-cards");
const confusionMatrix = document.getElementById("confusion-matrix");
const scoreDistribution = document.getElementById("score-distribution");
const checkActivity = document.getElementById("check-activity");
const errorSummary = document.getElementById("error-summary");
const rowsTableBody = document.getElementById("rows-table-body");
const downloadReport = document.getElementById("download-report");
const tabButtons = Array.from(document.querySelectorAll(".tab-button"));
const tabPanels = Array.from(document.querySelectorAll(".tab-panel"));

const CHECK_ORDER = ["heuristics", "content", "ssl", "domain_age", "threat_intel", "ml"];
let activeJobId = null;
let pollTimer = null;
let loadingDetailTimer = null;
let pendingCsvText = "";
let lastStatusSignature = "";

const loadingDetails = [
  "Validating the uploaded baseline and counting labeled rows.",
  "Running each URL through the full check stack used in triage.",
  "Capturing mismatches, API errors, and score spread for the report.",
];

function defaultStatusDetail(tone) {
  if (tone === "danger") {
    return "The run needs attention before the report can be trusted.";
  }
  if (tone === "ok") {
    return "Use the finished report to inspect mismatches and edge cases before relying on the topline score.";
  }
  if (tone === "warn") {
    return "Live progress is still moving. Watch current checks, recent URLs, and error rows together.";
  }
  return "Once a run starts, this panel will call out progress, bottlenecks, and the next review step.";
}

function setStatus(message, tone = "muted", detail = defaultStatusDetail(tone)) {
  const signature = `${tone}::${message}::${detail}`;
  if (lastStatusSignature === signature) {
    return;
  }
  lastStatusSignature = signature;
  statusMessageEl.textContent = message;
  statusDetailEl.textContent = detail;
  statusEl.classList.remove("muted", "ok", "warn", "danger", "status-swap");
  statusEl.classList.add(tone);
  requestAnimationFrame(() => statusEl.classList.add("status-swap"));
}

function startLoadingDetails() {
  stopLoadingDetails();
  let index = 0;
  statusDetailEl.textContent = loadingDetails[index];
  loadingDetailTimer = window.setInterval(() => {
    index = (index + 1) % loadingDetails.length;
    statusDetailEl.textContent = loadingDetails[index];
  }, 1400);
}

function stopLoadingDetails() {
  if (loadingDetailTimer) {
    window.clearInterval(loadingDetailTimer);
    loadingDetailTimer = null;
  }
}

function replayEntrance(element) {
  element.classList.remove("panel-enter");
  void element.offsetWidth;
  element.classList.add("panel-enter");
}

function setBusy(isBusy, label = isBusy ? "Starting evaluation..." : "Start Evaluation") {
  startButton.disabled = isBusy;
  startButton.setAttribute("aria-busy", String(isBusy));
  startButton.textContent = label;
}

function setEvaluationControlsDisabled(isDisabled) {
  csvFileInput.disabled = isDisabled;
  thresholdInput.disabled = isDisabled;
}

function formatPercent(value) {
  return `${Number(value || 0).toFixed(1)}%`;
}

function predictionLabel(value) {
  if (value === true) return "Phishing";
  if (value === false) return "Legitimate";
  return "Unknown";
}

function truthLabel(value) {
  if (value === true) return "Phishing";
  if (value === false) return "Legitimate";
  return "Unknown";
}

function resultLabel(row) {
  if (row.api_error) return "Error";
  if (row.matched_ground_truth === true) return "Correct";
  if (row.matched_ground_truth === false) return "Mismatch";
  return "Pending";
}

function toneForJob(status) {
  if (status === "completed") return "ok";
  if (status === "failed") return "danger";
  if (status === "running" || status === "queued") return "warn";
  return "muted";
}

function checkStateLabel(state) {
  if (state === "running") return "Running";
  if (state === "completed") return "Completed";
  if (state === "unknown") return "Unknown";
  return "Queued";
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function renderCheckList(states = {}) {
  checkList.innerHTML = "";
  CHECK_ORDER.forEach((check) => {
    const state = states[check] || "pending";
    const item = document.createElement("article");
    item.className = `check-item state-${state}`;
    item.innerHTML = `
      <div class="check-dot" aria-hidden="true"></div>
      <div class="check-copy">
        <strong>${escapeHtml(check.replaceAll("_", " "))}</strong>
        <span>${checkStateLabel(state)}</span>
      </div>
    `;
    checkList.appendChild(item);
  });
}

function renderRecentRows(rows) {
  if (!rows || rows.length === 0) {
    recentRows.className = "recent-stream empty-state";
    recentRows.textContent = "No websites processed yet.";
    return;
  }

  recentRows.className = "recent-stream";
  recentRows.innerHTML = rows
    .map((row) => {
      const score = row.risk_score == null ? "n/a" : Number(row.risk_score).toFixed(2);
      const tone = row.api_error ? "danger" : row.matched_ground_truth ? "ok" : "warn";
      return `
        <article class="recent-row">
          <div>
            <strong>${escapeHtml(row.url || row.scanned_url || "Unknown URL")}</strong>
            <span>${escapeHtml(resultLabel(row))}</span>
          </div>
          <span class="status-pill ${tone}">Score ${score}</span>
        </article>
      `;
    })
    .join("");
}

function renderJobState(job) {
  const tone = toneForJob(job.status);
  jobBadge.textContent = job.status === "completed" ? "Report Ready" : job.status;
  jobBadge.className = `summary-state ${tone}`;
  progressFill.style.width = `${job.progress_percent || 0}%`;
  progressText.textContent = `${job.processed_rows} of ${job.total_rows} websites processed`;
  progressPercent.textContent = formatPercent(job.progress_percent || 0);
  processedCount.textContent = String(job.processed_rows || 0);
  scoredCount.textContent = String(job.scored_rows || 0);
  errorCount.textContent = String(job.error_rows || 0);
  currentUrl.textContent = job.current_url || "Waiting for the next website...";
  renderCheckList(job.check_states);
  renderRecentRows(job.recent_rows);

  if (job.status === "failed") {
    setEvaluationControlsDisabled(false);
    setBusy(false);
    stopLoadingDetails();
    setStatus(job.message || "Evaluation failed.", "danger", "Review the upload, row-level errors, and any unavailable checks before retrying.");
  } else if (job.status === "completed") {
    setEvaluationControlsDisabled(false);
    setBusy(false);
    stopLoadingDetails();
    setStatus(job.message || "Evaluation finished.", "ok", "The report is ready. Start with mismatches and errors before drawing conclusions from accuracy alone.");
  } else {
    setEvaluationControlsDisabled(true);
    setBusy(true, "Evaluation in progress...");
    setStatus(job.message || "Evaluation in progress...", "warn", loadingDetails[1]);
  }
}

function renderSummaryCards(summary) {
  const cards = [
    ["Accuracy", summary.accuracy],
    ["Precision", summary.precision],
    ["Recall", summary.recall],
    ["F1", summary.f1],
    ["Scored Rows", summary.scored_rows],
    ["Error Rows", summary.error_rows],
  ];

  reportSummaryCards.innerHTML = cards
    .map(([label, value]) => {
      const text = typeof value === "number" && value <= 1 ? value.toFixed(4) : String(value);
      return `
        <article class="summary-metric-card">
          <span class="metric-label">${escapeHtml(label)}</span>
          <strong class="summary-metric-value">${escapeHtml(text)}</strong>
        </article>
      `;
    })
    .join("");
}

function renderConfusionMatrix(matrix) {
  const cells = [
    ["True Positives", matrix.tp, "danger"],
    ["False Positives", matrix.fp, "warn"],
    ["False Negatives", matrix.fn, "warn"],
    ["True Negatives", matrix.tn, "ok"],
  ];

  confusionMatrix.innerHTML = cells
    .map(
      ([label, value, tone]) => `
        <article class="matrix-cell tone-${tone}">
          <span>${escapeHtml(label)}</span>
          <strong>${escapeHtml(String(value))}</strong>
        </article>
      `,
    )
    .join("");
}

function renderHistogram(bins) {
  if (!bins || bins.length === 0) {
    scoreDistribution.className = "histogram empty-state";
    scoreDistribution.textContent = "No score data yet.";
    return;
  }

  const maxTotal = Math.max(...bins.map((bin) => bin.total), 1);
  scoreDistribution.className = "histogram";
  scoreDistribution.innerHTML = bins
    .map((bin) => {
      const phishingHeight = Math.max((bin.phishing / maxTotal) * 100, bin.phishing ? 6 : 0);
      const legitHeight = Math.max((bin.legitimate / maxTotal) * 100, bin.legitimate ? 6 : 0);
      return `
        <div class="histogram-bar-group">
          <div class="histogram-bar-stack">
            <span class="histogram-segment legit" style="height:${legitHeight}%"></span>
            <span class="histogram-segment phish" style="height:${phishingHeight}%"></span>
          </div>
          <span class="histogram-label">${escapeHtml(bin.label)}</span>
        </div>
      `;
    })
    .join("");
}

function renderMiniBars(target, items, emptyLabel, toneClass) {
  if (!items || items.length === 0) {
    target.className = "mini-bars empty-state";
    target.textContent = emptyLabel;
    return;
  }

  const max = Math.max(...items.map((item) => item.count), 1);
  target.className = "mini-bars";
  target.innerHTML = items
    .slice(0, 8)
    .map(
      (item) => `
        <div class="mini-bar-row">
          <span>${escapeHtml(item.check)}</span>
          <div class="mini-bar-track">
            <span class="mini-bar-fill ${toneClass}" style="width:${(item.count / max) * 100}%"></span>
          </div>
          <strong>${escapeHtml(String(item.count))}</strong>
        </div>
      `,
    )
    .join("");
}

function renderErrorSummary(items) {
  if (!items || items.length === 0) {
    errorSummary.className = "error-summary empty-state";
    errorSummary.textContent = "No errors recorded.";
    return;
  }

  errorSummary.className = "error-summary";
  errorSummary.innerHTML = items
    .map(
      (item) => `
        <article class="error-row">
          <strong>${escapeHtml(item.message)}</strong>
          <span class="status-pill warn">${escapeHtml(String(item.count))}</span>
        </article>
      `,
    )
    .join("");
}

function renderRowsTable(rows) {
  if (!rows || rows.length === 0) {
    rowsTableBody.innerHTML = `
      <tr>
        <td colspan="6" class="table-empty">No interesting rows returned for this run.</td>
      </tr>
    `;
    return;
  }

  rowsTableBody.innerHTML = rows
    .map((row) => {
      const score = row.risk_score == null ? "n/a" : Number(row.risk_score).toFixed(2);
      const result = resultLabel(row);
      const resultTone = row.api_error ? "danger" : row.matched_ground_truth ? "ok" : "warn";
      return `
        <tr>
          <td>${escapeHtml(String(row.index))}</td>
          <td class="table-url">
            <div>${escapeHtml(row.url || row.scanned_url || "Unknown URL")}</div>
            ${row.api_error ? `<small>${escapeHtml(row.api_error)}</small>` : ""}
          </td>
          <td>${escapeHtml(score)}</td>
          <td>${escapeHtml(predictionLabel(row.predicted_is_phishing))}</td>
          <td>${escapeHtml(truthLabel(row.actual_is_phishing))}</td>
          <td><span class="status-pill ${resultTone}">${escapeHtml(result)}</span></td>
        </tr>
      `;
    })
    .join("");
}

function renderReport(reportPayload, downloadUrl) {
  const report = reportPayload.report;
  reportShell.classList.remove("hidden");
  replayEntrance(reportShell);
  renderSummaryCards(report.summary);
  renderConfusionMatrix(report.confusion_matrix);
  renderHistogram(report.score_distribution);
  renderMiniBars(checkActivity, report.check_activity.contributing, "No contributing check data yet.", "primary");
  renderErrorSummary(report.errors);
  renderRowsTable(report.rows);

  if (downloadUrl) {
    downloadReport.href = downloadUrl;
    downloadReport.classList.remove("hidden");
  } else {
    downloadReport.classList.add("hidden");
  }
}

async function fetchJson(url, options = {}) {
  const response = await fetch(url, options);
  const payload = await response.json();
  if (!response.ok) {
    throw new Error(payload.detail || "Request failed.");
  }
  return payload;
}

async function loadReport(job) {
  if (!job.report_url) return;
  const reportPayload = await fetchJson(job.report_url);
  renderReport(reportPayload, job.download_url);
}

function schedulePoll(delay = 1200) {
  window.clearTimeout(pollTimer);
  pollTimer = window.setTimeout(pollJob, delay);
}

async function pollJob() {
  if (!activeJobId) return;
  try {
    const job = await fetchJson(`/evaluate/jobs/${activeJobId}`);
    renderJobState(job);
    if (job.status === "completed") {
      await loadReport(job);
      return;
    }
    if (job.status === "failed") {
      return;
    }
    schedulePoll();
  } catch (error) {
    stopLoadingDetails();
    setEvaluationControlsDisabled(false);
    setBusy(false);
    setStatus(error.message || "Unable to refresh evaluation progress.", "danger", "The run state may be stale until the next successful refresh.");
  }
}

csvFileInput.addEventListener("change", async () => {
  const [file] = csvFileInput.files || [];
  if (!file) {
    pendingCsvText = "";
    fileSummary.textContent = "No file selected yet.";
    return;
  }

  pendingCsvText = await file.text();
  const lineCount = pendingCsvText.trim() ? pendingCsvText.trim().split(/\r?\n/).length - 1 : 0;
  fileSummary.textContent = `${file.name} • ${lineCount} rows detected • ${(file.size / 1024).toFixed(1)} KB`;
  setStatus("Baseline file loaded.", "muted", "Threshold and row count look ready. Start the run when you want a live benchmark.");
});

evaluationForm.addEventListener("submit", async (event) => {
  event.preventDefault();
  const [file] = csvFileInput.files || [];
  if (!file) {
    setStatus("Choose a CSV file before starting.", "warn", "The evaluator expects labeled rows with url and is_phishing columns.");
    return;
  }

  try {
    setEvaluationControlsDisabled(true);
    setBusy(true, "Starting evaluation...");
    startLoadingDetails();
    const csvContent = pendingCsvText || (await file.text());
    const payload = await fetchJson("/evaluate/jobs", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        filename: file.name,
        csv_content: csvContent,
        threshold: Number(thresholdInput.value || 50),
      }),
    });

    activeJobId = payload.job_id;
    reportShell.classList.add("hidden");
    renderJobState(payload);
    setStatus("Evaluation started. Progress will update automatically.", "warn", loadingDetails[0]);
    schedulePoll(600);
  } catch (error) {
    stopLoadingDetails();
    setEvaluationControlsDisabled(false);
    setBusy(false);
    setStatus(error.message || "Unable to start evaluation.", "danger", "The run did not start cleanly. Check the file format and try again.");
  }
});

tabButtons.forEach((button) => {
  button.addEventListener("click", () => {
    const tabId = button.dataset.tab;
    tabButtons.forEach((candidate) => candidate.classList.toggle("is-active", candidate === button));
    tabPanels.forEach((panel) => panel.classList.toggle("is-active", panel.dataset.panel === tabId));
  });
});

renderCheckList();

