function renderHyperparameters(params) {
  const items = Object.entries(params || {}).map(([key, value]) => ({
    feature: key.replaceAll("_", " "),
    importance: typeof value === "boolean" ? (value ? 1 : 0) : Number(value || 0),
    rawValue: value,
  }));
  if (items.length === 0) {
    mlHyperparameters.className = "mini-bars empty-state";
    mlHyperparameters.textContent = "No completed run yet.";
    return;
  }
  mlHyperparameters.className = "mini-bars";
  mlHyperparameters.innerHTML = Object.entries(params)
    .map(
      ([key, value]) => `
        <div class="mini-bar-row">
          <span>${escapeHtml(key.replaceAll("_", " "))}</span>
          <div class="mini-bar-track">
            <span class="mini-bar-fill primary" style="width:${typeof value === "number" ? Math.min(Math.abs(value) * 10, 100) : 45}%"></span>
          </div>
          <strong>${escapeHtml(String(value))}</strong>
        </div>
      `,
    )
    .join("");
}

function renderMlReport(payload) {
  const report = payload.report;
  const modelSummary = report?.model_summary || {};
  mlReportShell.classList.remove("hidden");
  replayEntrance(mlReportShell);
  renderMetricCards(mlSummaryCards, [
    ["Accuracy", report.summary.accuracy],
    ["Precision", report.summary.precision],
    ["Recall", report.summary.recall],
    ["F1", report.summary.f1],
    ["ROC AUC", report.summary.roc_auc],
    ["Epochs", modelSummary.epochs_trained],
    ["Validation Rows", report.summary.validation_rows],
    ["Test Rows", report.summary.test_rows],
  ]);
  renderConfusionMatrix(mlConfusionMatrix, report.confusion_matrix);
  renderMetricCards(mlTreeSummary, [
    ["Hidden Layers", (modelSummary.hidden_units || []).join(" / ") || "n/a"],
    ["Parameters", modelSummary.total_params],
    ["Device", modelSummary.resolved_device || modelSummary.device || "n/a"],
    ["Activated", report.summary.activated ? "yes" : "no"],
  ]);
  renderHyperparameters(report.hyperparameters);
  renderLossChart(report);
  renderAccuracyChart(report);
  renderMetricsChart(report);
  renderDistributionChart(report);
  renderFeatureChart(report);
  renderErrorAnalysis(report);
  renderArtifactLinks(report);
}

async function loadOverview({ autoloadLatestReport = false } = {}) {
  const payload = await fetchJson("/ml/overview");
  renderActiveModel(payload.active_model);
  renderRuntime(payload);
  const recentJobs = payload.recent_jobs || [];
  const modelRegistry = payload.model_registry || [];
  renderRecentRuns(recentJobs);
  renderRegistryHighlights(modelRegistry);
  renderModelRegistry(modelRegistry);
  if (!autoloadLatestReport) {
    return;
  }

  const latestCompletedJob = recentJobs.find((job) => job.report_ready && job.report_url);
  if (!latestCompletedJob) {
    return;
  }

  if (latestCompletedJob.report_url) {
    await loadReport(latestCompletedJob, { refreshOverview: false, activeTab: "metrics" });
    setStatus("Loaded the most recent completed ML report.", "ok", "This gives you the latest experiment state without starting a new run.");
  }
}

async function loadReport(job, { refreshOverview = true, activeTab = "overview" } = {}) {
  if (!job.report_url) return;
  const payload = await fetchJson(job.report_url);
  renderMlReport(payload);
  setMlActiveTab(activeTab);
  if (refreshOverview) {
    await loadOverview();
  }
}

function schedulePoll(delay = 1200) {
  window.clearTimeout(pollTimer);
  pollTimer = window.setTimeout(pollJob, delay);
}

async function pollJob() {
  if (!activeJobId) return;
  try {
    const job = await fetchJson(`/ml/jobs/${activeJobId}`);
    renderMlJob(job);
    if (job.status === "completed") {
      await loadReport(job, { activeTab: "metrics" });
      return;
    }
    if (job.status === "failed") {
      await loadOverview();
      return;
    }
    schedulePoll();
  } catch (error) {
    stopLoadingDetails();
    setTrainingControlsDisabled(false);
    setBusy(false);
    setStatus(error.message || "Unable to refresh ML job progress.", "danger", "The lab state may be stale until the next successful refresh.");
  }
}

function renderProbeResult(payload) {
  const ml = payload.ml || {};
  const topFeatures = (ml.top_features || [])
    .map((item) => `${item.feature}: ${Number(item.importance || 0).toFixed(3)}`)
    .join(" • ");
  mlProbeResult.className = "probe-result";
  mlProbeResult.innerHTML = `
    <div class="probe-result-header">
      <strong>${escapeHtml(payload.url || "Unknown URL")}</strong>
      <span class="summary-state ${ml.status === "ok" ? (ml.prediction === "phishing" ? "danger" : "ok") : "warn"}">
        ${escapeHtml(ml.prediction || ml.status || "unknown")}
      </span>
    </div>
    <div class="summary-metric-grid compact-grid">
      <article class="summary-metric-card">
        <span class="metric-label">Risk Score</span>
        <strong class="summary-metric-value">${escapeHtml(formatMetric(ml.risk_score || 0))}</strong>
      </article>
      <article class="summary-metric-card">
        <span class="metric-label">Probability</span>
        <strong class="summary-metric-value">${escapeHtml(formatMetric(ml.probability || 0))}</strong>
      </article>
      <article class="summary-metric-card">
        <span class="metric-label">Version</span>
        <strong class="summary-metric-value">${escapeHtml(ml.model_version || "n/a")}</strong>
      </article>
    </div>
    <p class="hint">${escapeHtml(topFeatures || "No model-specific feature importance is available for this probe.")}</p>
    <details class="feature-details">
      <summary>Show extracted features</summary>
      <pre>${escapeHtml(JSON.stringify(payload.features || {}, null, 2))}</pre>
    </details>
  `;
}

mlCsvFileInput.addEventListener("change", async () => {
  const [file] = mlCsvFileInput.files || [];
  if (!file) {
    pendingCsvText = "";
    mlFileSummary.textContent = "Upload a CSV with url and is_phishing.";
    return;
  }
  pendingCsvText = await file.text();
  const lineCount = pendingCsvText.trim() ? pendingCsvText.trim().split(/\r?\n/).length - 1 : 0;
  mlFileSummary.textContent = `${file.name} • ${lineCount} labeled rows • ${(file.size / 1024).toFixed(1)} KB`;
  setStatus("Training dataset loaded.", "muted", "Core settings are ready. Open advanced controls only if you need to shape validation, regularization, or threshold behavior.");
});

mlForm.addEventListener("submit", async (event) => {
  event.preventDefault();
  const [file] = mlCsvFileInput.files || [];
  if (!file) {
    setStatus("Choose a labeled CSV before starting a run.", "warn", "The lab expects url and is_phishing columns so it can build features and labels correctly.");
    return;
  }
  try {
    setTrainingControlsDisabled(true);
    setBusy(true, "Starting run...");
    startLoadingDetails();
    const csvContent = pendingCsvText || (await file.text());
    const payload = await fetchJson("/ml/jobs", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        filename: file.name,
        csv_content: csvContent,
        device: deviceInput?.value || "auto",
        epochs: Number(epochsInput.value || 0) || null,
        batch_size: Number(batchSizeInput.value || 0) || null,
        learning_rate: Number(learningRateInput.value || 0) || null,
        test_size: Number(testSizeInput.value || 0) || null,
        validation_split: Number(validationSplitInput.value || 0) || null,
        dropout_rate: Number(dropoutRateInput.value || 0) || null,
        hidden_units: hiddenUnitsInput.value
          .split(",")
          .map((value) => Number(value.trim()))
          .filter((value) => Number.isFinite(value) && value > 0),
        early_stopping_patience: Number(earlyStoppingInput.value || 0),
        classification_threshold: Number(thresholdInput.value || 0) || null,
        random_state: Number(randomStateInput.value || 0) || null,
        activate_after_training: activateModelInput.checked,
      }),
    });
    activeJobId = payload.job_id;
    mlReportShell.classList.add("hidden");
    renderMlJob(payload);
    setStatus("TensorFlow run started. Progress will update automatically.", "warn", loadingDetails[0]);
    schedulePoll(500);
  } catch (error) {
    setTrainingControlsDisabled(false);
    setBusy(false);
    stopLoadingDetails();
    setStatus(error.message || "Unable to start ML run.", "danger", "The TensorFlow run did not start cleanly. Review the file, device selection, and training settings, then try again.");
  }
});

mlProbeForm.addEventListener("submit", async (event) => {
  event.preventDefault();
  const url = mlProbeUrl.value.trim();
  if (!url) {
    setStatus("Provide a URL to probe the active model.", "warn", "A single probe is useful when you want to inspect how the current model reacts to one suspicious destination.");
    return;
  }
  try {
    setProbeBusy(true);
    setStatus("Running ML-only scan...", "warn", "The probe will return the model verdict, probability, and the strongest extracted features.");
    const payload = await fetchJson("/scan/ml", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url }),
    });
    renderProbeResult(payload);
    await loadOverview();
    setStatus("ML probe finished.", "ok", "Use the extracted features to see whether the model is reacting to meaningful phishing cues.");
  } catch (error) {
    setStatus(error.message || "ML probe failed.", "danger", "No trustworthy ML-only result was produced for this URL.");
  } finally {
    setProbeBusy(false);
  }
});

mlTabButtons.forEach((button) => {
  button.addEventListener("click", () => {
    setMlActiveTab(button.dataset.mlTab);
  });
});

renderCheckList();
loadOverview({ autoloadLatestReport: true }).catch((error) => {
  setStatus(error.message || "Unable to load ML overview.", "danger", "The lab could not load its latest model snapshot or recent run history.");
});

:root {
  --ease-out-quart: cubic-bezier(0.25, 1, 0.5, 1);
  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
  --bg: oklch(0.97 0.01 240);
  --bg-strong: oklch(0.93 0.025 235);
  --surface: oklch(0.995 0.004 240);
  --surface-2: oklch(0.975 0.01 235);
  --surface-3: oklch(0.95 0.015 235);
  --text: oklch(0.25 0.03 255);
  --text-soft: oklch(0.48 0.025 248);
  --text-subtle: oklch(0.58 0.018 245);
  --line: oklch(0.87 0.02 238);
  --line-strong: oklch(0.76 0.03 236);
  --primary: oklch(0.39 0.09 255);
  --primary-strong: oklch(0.32 0.08 255);
  --accent: oklch(0.62 0.12 172);
  --accent-deep: oklch(0.45 0.09 175);
  --caution: oklch(0.8 0.1 92);
  --caution-ink: oklch(0.48 0.07 88);
  --warn: oklch(0.72 0.14 72);
  --warn-ink: oklch(0.42 0.08 72);
  --danger: oklch(0.6 0.2 28);
  --danger-ink: oklch(0.38 0.1 26);
  --shadow-soft: 0 24px 60px rgba(18, 33, 66, 0.08);
  --shadow-strong: 0 24px 70px rgba(18, 33, 66, 0.14);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: "Source Sans 3", "Segoe UI", sans-serif;
  background:
    radial-gradient(circle at top left, rgba(30, 64, 175, 0.12), transparent 28%),
    radial-gradient(circle at top right, rgba(16, 185, 129, 0.08), transparent 24%),
    linear-gradient(180deg, var(--bg-strong) 0%, var(--bg) 42%, oklch(0.985 0.008 235) 100%);
  color: var(--text);
}

.container {
  max-width: 1080px;
  margin: 0 auto;
  padding: clamp(28px, 5vw, 56px) 16px 64px;
}

h1,
h2 {
  font-family: "Sora", "Segoe UI", sans-serif;
  letter-spacing: -0.04em;
}

h1 {
  margin: 0 0 10px;
  font-size: clamp(2.3rem, 4vw, 4rem);
  font-weight: 800;
  line-height: 0.95;
  color: var(--primary-strong);
}

h2 {
  margin: 0;
  font-size: clamp(1.4rem, 2vw, 1.8rem);
  font-weight: 700;
}

.hint {
  max-width: 68ch;
  margin: 0 0 8px;
  font-size: 1.05rem;
  color: var(--text-soft);
}

form {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto;
  gap: 10px;
  align-items: stretch;
  margin: 26px 0 18px;
  padding: 12px;
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(128, 150, 190, 0.18);
  border-radius: 22px;
  box-shadow: var(--shadow-soft);
  backdrop-filter: blur(10px);
}

input {
  min-height: 48px;
  padding: 0 16px;
  font: inherit;
  color: var(--text);
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 16px;
  outline: none;
  transition:
    border-color 180ms var(--ease-out-quart),
    box-shadow 180ms var(--ease-out-quart),
    background-color 180ms var(--ease-out-quart);
}

input::placeholder {
  color: var(--text-subtle);
}

input:focus {
  border-color: rgba(30, 64, 175, 0.45);
  box-shadow: 0 0 0 4px rgba(30, 64, 175, 0.12);
}

select {
  min-height: 48px;
  padding: 0 16px;
  font: inherit;
  color: var(--text);
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 16px;
  outline: none;
  transition:
    border-color 180ms var(--ease-out-quart),
    box-shadow 180ms var(--ease-out-quart),
    background-color 180ms var(--ease-out-quart);
}

select:focus {
  border-color: rgba(30, 64, 175, 0.45);
  box-shadow: 0 0 0 4px rgba(30, 64, 175, 0.12);
}

button {
  min-height: 48px;
  padding: 0 18px;
  border: 0;
  border-radius: 16px;
  font: inherit;
  font-weight: 700;
  letter-spacing: 0.01em;
  cursor: pointer;
  position: relative;
  overflow: hidden;
  color: oklch(0.99 0.003 250);
  background: linear-gradient(135deg, var(--primary) 0%, oklch(0.46 0.11 248) 100%);
  box-shadow: 0 14px 30px rgba(30, 64, 175, 0.2);
  transition:
    transform 180ms var(--ease-out-quart),
    box-shadow 220ms var(--ease-out-quart),
    opacity 180ms var(--ease-out-quart),
    filter 220ms var(--ease-out-quart);
}

#refresh-feeds {
  color: var(--primary-strong);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.96), rgba(233, 240, 251, 0.95));
  box-shadow: 0 10px 22px rgba(15, 23, 42, 0.08);
}

button:hover {
  transform: translateY(-1px);
  box-shadow: 0 18px 34px rgba(30, 64, 175, 0.24);
  filter: saturate(1.05);
}

button:active {
  transform: translateY(0) scale(0.98);
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.88;
}

form.is-scanning button[type="submit"] {
  animation: scan-pulse 1.1s var(--ease-out-expo) infinite;
}

form button[type="submit"]::after {
  content: "";
  position: absolute;
  inset: 0;
  opacity: 0;
  background: linear-gradient(105deg, transparent 22%, rgba(255, 255, 255, 0.22) 50%, transparent 78%);
  transform: translateX(-130%);
}

form.is-scanning button[type="submit"]::after {
  opacity: 1;
  animation: scan-sheen 1.35s linear infinite;
}

.card {
  position: relative;
  margin-top: 16px;
  padding: 18px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.96), rgba(245, 248, 252, 0.98));
  border: 1px solid rgba(128, 150, 190, 0.18);
  border-radius: 24px;
  box-shadow: var(--shadow-soft);
  transition:
    color 220ms var(--ease-out-quart),
    border-color 220ms var(--ease-out-quart),
    background-color 220ms var(--ease-out-quart),
    transform 220ms var(--ease-out-quart),
    box-shadow 220ms var(--ease-out-quart);
}

.hidden {
  display: none;
}

.muted {
  color: var(--text-soft);
}

.ok {
  color: var(--accent-deep);
}

.caution {
  color: var(--caution-ink);
}

.warn {
  color: var(--warn-ink);
}

.danger {
  color: var(--danger-ink);
}

#status {
  overflow: hidden;
  font-size: 1.05rem;
  font-weight: 600;
}

#status::before {
  content: "";
  position: absolute;
  top: 0;
  left: 18px;
  height: 3px;
  width: 20%;
  border-radius: 999px;
  opacity: 0;
  background: linear-gradient(90deg, var(--primary), var(--accent));
  transform: translateX(-130%);
}

#status.status-loading {
  background: linear-gradient(180deg, rgba(235, 243, 255, 0.96), rgba(247, 251, 255, 0.98));
  border-color: rgba(63, 99, 192, 0.22);
}

#status.status-loading::before {
  opacity: 1;
  animation: status-scan 1.4s linear infinite;
}

#status[data-tone="ok"] {
  border-color: rgba(16, 185, 129, 0.18);
  background: linear-gradient(180deg, rgba(244, 253, 249, 0.98), rgba(237, 249, 244, 0.98));
}

#status[data-tone="caution"] {
  border-color: rgba(214, 158, 46, 0.22);
  background: linear-gradient(180deg, rgba(255, 251, 240, 0.98), rgba(252, 246, 229, 0.98));
}

#status[data-tone="warn"] {
  border-color: rgba(245, 158, 11, 0.22);
  background: linear-gradient(180deg, rgba(255, 248, 238, 0.98), rgba(252, 243, 227, 0.98));
}

#status[data-tone="danger"] {
  border-color: rgba(220, 38, 38, 0.18);
  background: linear-gradient(180deg, rgba(255, 243, 243, 0.98), rgba(251, 236, 236, 0.98));
}

#status.status-swap {
  animation: status-in 220ms var(--ease-out-quart);
}

.summary-panel {
  padding: clamp(22px, 4vw, 30px);
  background:
    radial-gradient(circle at top right, rgba(16, 185, 129, 0.08), transparent 28%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.99), rgba(240, 246, 253, 0.98));
}

.summary-header {
  display: flex;
  align-items: start;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 18px;
}

.eyebrow {
  margin: 0 0 8px;
  font-size: 0.82rem;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--text-subtle);
}

.summary-state {
  align-self: center;
  padding: 9px 14px;
  border-radius: 999px;
  font-size: 0.94rem;
  font-weight: 700;
  letter-spacing: 0.01em;
  color: var(--primary-strong);
  background: rgba(30, 64, 175, 0.08);
  border: 1px solid rgba(30, 64, 175, 0.14);
}

.summary-state.ok {
  color: var(--accent-deep);
  background: rgba(16, 185, 129, 0.1);
  border-color: rgba(16, 185, 129, 0.16);
}

.summary-state.caution {
  color: var(--caution-ink);
  background: rgba(214, 158, 46, 0.14);
  border-color: rgba(214, 158, 46, 0.2);
}

.summary-state.warn {
  color: var(--warn-ink);
  background: rgba(245, 158, 11, 0.12);
  border-color: rgba(245, 158, 11, 0.2);
}

.summary-state.danger {
  color: var(--danger-ink);
  background: rgba(220, 38, 38, 0.1);
  border-color: rgba(220, 38, 38, 0.18);
}

.summary-grid {
  display: grid;
  grid-template-columns: minmax(240px, 0.95fr) minmax(0, 1.35fr);
  gap: 18px;
}

.risk-hero {
  display: grid;
  align-content: start;
  gap: 10px;
  min-height: 100%;
  padding: 22px;
  border-radius: 24px;
  color: oklch(0.985 0.005 245);
  background:
    radial-gradient(circle at top right, rgba(255, 255, 255, 0.12), transparent 24%),
    linear-gradient(160deg, var(--primary-strong) 0%, oklch(0.28 0.045 258) 100%);
  box-shadow: var(--shadow-strong);
}

.summary-panel[data-tone="ok"] .risk-hero {
  background:
    radial-gradient(circle at top right, rgba(255, 255, 255, 0.12), transparent 24%),
    linear-gradient(160deg, oklch(0.4 0.08 185) 0%, oklch(0.31 0.05 215) 100%);
}

.summary-panel[data-tone="caution"] .risk-hero {
  background:
    radial-gradient(circle at top right, rgba(255, 255, 255, 0.1), transparent 24%),
    linear-gradient(160deg, oklch(0.67 0.1 94) 0%, oklch(0.4 0.06 76) 100%);
}

.summary-panel[data-tone="warn"] .risk-hero {
  background:
    radial-gradient(circle at top right, rgba(255, 255, 255, 0.1), transparent 24%),
    linear-gradient(160deg, oklch(0.55 0.12 74) 0%, oklch(0.38 0.07 52) 100%);
}

.summary-panel[data-tone="danger"] .risk-hero {
  background:
    radial-gradient(circle at top right, rgba(255, 255, 255, 0.09), transparent 24%),
    linear-gradient(160deg, oklch(0.54 0.18 28) 0%, oklch(0.35 0.08 22) 100%);
}

.metric-label {
  font-size: 0.82rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: inherit;
  opacity: 0.72;
}

.risk-value {
  font-family: "Sora", "Segoe UI", sans-serif;
  font-size: clamp(4.1rem, 9vw, 6.4rem);
  font-weight: 800;
  line-height: 0.88;
  letter-spacing: -0.07em;
}

.risk-url {
  display: block;
  max-width: 100%;
  word-break: break-word;
  font-size: 1rem;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.82);
}

.risk-band {
  display: inline-flex;
  width: fit-content;
  min-height: 32px;
  align-items: center;
  padding: 6px 12px;
  border-radius: 999px;
  font-size: 0.92rem;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.88);
  background: rgba(255, 255, 255, 0.12);
  border: 1px solid rgba(255, 255, 255, 0.14);
}

.signal-grid,
.meta-grid {
  display: grid;
  gap: 14px;
}

.signal-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.meta-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  margin-top: 16px;
}

.signal-card,
.meta-card {
  padding: 18px;
  border-radius: 20px;
  background: linear-gradient(180deg, rgba(252, 254, 255, 0.98), rgba(239, 245, 251, 0.96));
  border: 1px solid rgba(108, 133, 170, 0.18);
}

.signal-card {
  min-height: 138px;
}

.analysis-card {
  position: relative;
  overflow: hidden;
}

.analysis-card::before {
  content: "";
  position: absolute;
  inset: 0 auto 0 0;
  width: 4px;
  border-radius: 999px;
  background: rgba(30, 64, 175, 0.24);
}

.summary-panel[data-tone="ok"] .analysis-card::before {
  background: rgba(16, 185, 129, 0.5);
}

.summary-panel[data-tone="caution"] .analysis-card::before {
  background: rgba(214, 158, 46, 0.55);
}

.summary-panel[data-tone="warn"] .analysis-card::before {
  background: rgba(245, 158, 11, 0.6);
}

.summary-panel[data-tone="danger"] .analysis-card::before {
  background: rgba(220, 38, 38, 0.58);
}

.signal-copy {
  margin: 14px 0 0;
  font-size: 1.02rem;
  line-height: 1.45;
  color: var(--text);
}

.token-list {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 14px;
}

.token,
.status-pill {
  display: inline-flex;
  align-items: center;
  min-height: 36px;
  padding: 7px 12px;
  border-radius: 999px;
  font-size: 0.95rem;
  font-weight: 700;
  line-height: 1.1;
}

.token-neutral {
  color: var(--primary-strong);
  background: rgba(30, 64, 175, 0.08);
}

.token-warn {
  color: var(--warn-ink);
  background: rgba(245, 158, 11, 0.12);
}

.status-pill {
  margin-top: 14px;
  width: fit-content;
}

.status-pill.ok {
  color: var(--accent-deep);
  background: rgba(16, 185, 129, 0.12);
}

.status-pill.caution {
  color: var(--caution-ink);
  background: rgba(214, 158, 46, 0.16);
}

.status-pill.warn {
  color: var(--warn-ink);
  background: rgba(245, 158, 11, 0.14);
}

.status-pill.muted {
  color: var(--primary-strong);
  background: rgba(30, 64, 175, 0.09);
}

.meta-value {
  display: block;
  margin-top: 12px;
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text);
}

#details {
  background: linear-gradient(180deg, rgba(244, 248, 253, 0.98), rgba(235, 242, 250, 0.98));
}

#details[data-tone="ok"] {
  border-color: rgba(16, 185, 129, 0.14);
  background: linear-gradient(180deg, rgba(244, 250, 247, 0.98), rgba(236, 246, 241, 0.98));
}

#details[data-tone="caution"] {
  border-color: rgba(214, 158, 46, 0.18);
  background: linear-gradient(180deg, rgba(255, 250, 241, 0.98), rgba(249, 243, 227, 0.98));
}

#details[data-tone="warn"] {
  border-color: rgba(245, 158, 11, 0.18);
  background: linear-gradient(180deg, rgba(255, 247, 238, 0.98), rgba(248, 239, 226, 0.98));
}

#details[data-tone="danger"] {
  border-color: rgba(220, 38, 38, 0.16);
  background: linear-gradient(180deg, rgba(255, 244, 244, 0.98), rgba(248, 235, 235, 0.98));
}

pre {
  overflow-x: auto;
  margin: 0;
  padding: 18px;
  border-radius: 18px;
  background: linear-gradient(180deg, oklch(0.23 0.02 255), oklch(0.18 0.02 252));
  color: oklch(0.94 0.01 240);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.03);
}

.page-header {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 18px;
  align-items: start;
}

.page-header-wide {
  margin-bottom: 12px;
}

.topnav {
  display: inline-flex;
  flex-wrap: wrap;
  justify-content: end;
  gap: 10px;
}

.nav-link,
.button-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 46px;
  padding: 0 16px;
  border-radius: 16px;
  font-weight: 700;
  text-decoration: none;
  color: var(--primary-strong);
  background: rgba(255, 255, 255, 0.84);
  border: 1px solid rgba(108, 133, 170, 0.2);
  box-shadow: 0 12px 24px rgba(18, 33, 66, 0.08);
  transition:
    transform 180ms var(--ease-out-quart),
    box-shadow 220ms var(--ease-out-quart),
    background-color 220ms var(--ease-out-quart);
}

.nav-link:hover,
.button-link:hover {
  transform: translateY(-1px);
  box-shadow: 0 18px 28px rgba(18, 33, 66, 0.12);
}

.nav-link.is-active {
  color: oklch(0.985 0.005 245);
  background: linear-gradient(135deg, var(--primary) 0%, oklch(0.46 0.11 248) 100%);
}

.evaluation-stage {
  display: grid;
  grid-template-columns: minmax(0, 1.15fr) minmax(320px, 0.95fr);
  gap: 20px;
  align-items: stretch;
}

.evaluation-stage-copy {
  display: grid;
  align-content: start;
  gap: 10px;
}

.evaluation-form {
  grid-template-columns: minmax(0, 1fr) minmax(180px, 220px) auto;
  align-items: end;
  margin: 0;
}

.ml-stage,
.ml-overview-grid {
  display: grid;
  gap: 20px;
}

.ml-stage {
  grid-template-columns: minmax(0, 0.95fr) minmax(380px, 1.2fr);
}

.ml-stage-copy {
  display: grid;
  align-content: start;
  gap: 10px;
}

.ml-form {
  grid-template-columns: minmax(0, 1fr);
  align-items: start;
  margin: 0;
  gap: 16px;
  background:
    radial-gradient(circle at top right, rgba(30, 64, 175, 0.08), transparent 24%),
    linear-gradient(180deg, rgba(248, 251, 255, 0.98), rgba(239, 245, 253, 0.98));
}

.ml-form-section,
.ml-form-section-copy {
  display: grid;
}

.ml-form-section {
  gap: 12px;
}

.ml-form-section-copy {
  gap: 6px;
}

.ml-settings-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.advanced-settings {
  display: grid;
  gap: 12px;
  padding: 14px 16px;
  border-radius: 20px;
  border: 1px solid rgba(108, 133, 170, 0.16);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.82), rgba(241, 246, 252, 0.84));
}

.advanced-settings summary {
  cursor: pointer;
  list-style: none;
  font-weight: 700;
  color: var(--primary-strong);
}

.advanced-settings summary::-webkit-details-marker {
  display: none;
}

.advanced-settings summary::after {
  content: "+";
  float: right;
  color: var(--primary);
}

.advanced-settings[open] summary::after {
  content: "−";
}

.toggle-row {
  display: flex;
  gap: 12px;
  align-items: center;
  font-weight: 600;
  color: var(--text-soft);
}

.toggle-row input[type="checkbox"] {
  width: 18px;
  height: 18px;
  accent-color: rgba(49, 104, 215, 0.95);
}

.ml-overview-grid {
  grid-template-columns: minmax(0, 1.15fr) minmax(320px, 0.85fr);
  align-items: start;
}

.ml-grid {
  grid-template-columns: minmax(320px, 0.95fr) minmax(0, 1.15fr);
}

.compact-card {
  min-height: 100%;
}

.compact-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.probe-card,
.active-model-card {
  padding: clamp(20px, 3vw, 28px);
}

.probe-form {
  grid-template-columns: minmax(0, 1fr) auto;
  margin: 0;
}

.probe-hint {
  margin: 10px 0 0;
}

.probe-result {
  display: grid;
  gap: 14px;
}

.probe-result-header {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: start;
}

.feature-details {
  border-top: 1px solid rgba(108, 133, 170, 0.16);
  padding-top: 12px;
}

.feature-details summary {
  cursor: pointer;
  font-weight: 700;
  color: var(--primary-strong);
}

.chart-card {
  min-height: 320px;
}

.chart-card canvas {
  display: block;
  width: 100%;
  height: 260px !important;
}

.file-drop-zone {
  position: relative;
  display: grid;
  gap: 8px;
  min-height: 132px;
  padding: 18px;
  border-radius: 18px;
  border: 1px dashed rgba(63, 99, 192, 0.28);
  background:
    radial-gradient(circle at top right, rgba(30, 64, 175, 0.08), transparent 28%),
    linear-gradient(180deg, rgba(251, 253, 255, 0.98), rgba(239, 245, 253, 0.98));
  cursor: pointer;
}

.file-drop-zone input[type="file"] {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
}

.file-drop-title {
  font-family: "Sora", "Segoe UI", sans-serif;
  font-size: 1.05rem;
  font-weight: 700;
}

.file-drop-subtitle {
  color: var(--text-soft);
}

.field-block {
  display: grid;
  gap: 8px;
}

.field-label {
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--text-soft);
}

.evaluation-grid {
  display: grid;
  grid-template-columns: minmax(320px, 0.95fr) minmax(0, 1.15fr);
  gap: 16px;
  align-items: start;
}

.panel-header,
.panel-subheader {
  display: flex;
  align-items: start;
  justify-content: space-between;
  gap: 14px;
}

.panel-header {
  margin-bottom: 16px;
}

.panel-subheader {
  margin-bottom: 14px;
}

.panel-subheader h3 {
  margin: 0;
  font-family: "Sora", "Segoe UI", sans-serif;
  font-size: 1.05rem;
}

.progress-panel,
.report-shell {
  padding: clamp(20px, 3vw, 28px);
}

.progress-meter {
  overflow: hidden;
  height: 14px;
  border-radius: 999px;
  background: rgba(30, 64, 175, 0.08);
  border: 1px solid rgba(63, 99, 192, 0.12);
}

.progress-fill {
  height: 100%;
  width: 0;
  border-radius: inherit;
  background: linear-gradient(90deg, var(--primary) 0%, var(--accent) 100%);
  transition: width 280ms var(--ease-out-quart);
}

.progress-meta {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  margin-top: 10px;
  font-weight: 700;
  color: var(--text-soft);
}

.kpi-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 12px;
  margin-top: 18px;
}

.kpi-card,
.summary-metric-card {
  display: grid;
  gap: 10px;
  padding: 16px 18px;
  border-radius: 18px;
  background: linear-gradient(180deg, rgba(252, 254, 255, 0.98), rgba(239, 245, 251, 0.96));
  border: 1px solid rgba(108, 133, 170, 0.16);
}

.kpi-value,
.summary-metric-value {
  font-family: "Sora", "Segoe UI", sans-serif;
  font-size: clamp(1.6rem, 3vw, 2.3rem);
  font-weight: 800;
  line-height: 0.95;
  letter-spacing: -0.05em;
}

.current-url-card,
.check-runner-card,
.recent-stream-card,
.report-card {
  margin-top: 16px;
  padding: 18px;
  border-radius: 20px;
  background: linear-gradient(180deg, rgba(252, 254, 255, 0.98), rgba(239, 245, 251, 0.96));
  border: 1px solid rgba(108, 133, 170, 0.18);
}

.current-url-card strong {
  display: block;
  margin-top: 10px;
  font-size: 1rem;
  line-height: 1.35;
  word-break: break-word;
}

.check-list {
  display: grid;
  gap: 10px;
}

.check-item {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  gap: 12px;
  align-items: center;
  padding: 12px 14px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(108, 133, 170, 0.14);
}

.check-dot {
  width: 12px;
  height: 12px;
  border-radius: 999px;
  background: rgba(30, 64, 175, 0.18);
  box-shadow: 0 0 0 6px rgba(30, 64, 175, 0.05);
}

.check-copy {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  align-items: center;
}

.check-copy strong {
  text-transform: capitalize;
}

.check-copy span {
  color: var(--text-soft);
  font-weight: 700;
}

.check-item.state-running .check-dot {
  background: var(--warn);
  box-shadow: 0 0 0 6px rgba(245, 158, 11, 0.12);
}

.check-item.state-completed .check-dot {
  background: var(--accent);
  box-shadow: 0 0 0 6px rgba(16, 185, 129, 0.12);
}

.check-item.state-unknown .check-dot {
  background: var(--danger);
  box-shadow: 0 0 0 6px rgba(220, 38, 38, 0.08);
}

.recent-stream {
  display: grid;
  gap: 10px;
}

.recent-row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: start;
  padding: 12px 14px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(108, 133, 170, 0.12);
}

.recent-row strong,
.error-row strong {
  display: block;
  margin-bottom: 4px;
  word-break: break-word;
}

.recent-row span:not(.status-pill) {
  color: var(--text-soft);
}

.tab-row {
  display: inline-flex;
  flex-wrap: nowrap;
  gap: 10px;
  margin: 4px 0 18px;
  overflow-x: auto;
  padding-bottom: 4px;
  scrollbar-width: thin;
}

.tab-button {
  min-height: 42px;
  padding: 0 14px;
  color: var(--primary-strong);
  background: rgba(255, 255, 255, 0.92);
  box-shadow: none;
  flex: 0 0 auto;
}

.tab-button.is-active {
  color: oklch(0.985 0.005 245);
  background: linear-gradient(135deg, var(--primary) 0%, oklch(0.46 0.11 248) 100%);
}

.tab-panel {
  display: none;
}

.tab-panel.is-active {
  display: block;
}

.summary-metric-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 12px;
}

.report-two-up {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
  margin-top: 16px;
}

.confusion-matrix {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.matrix-cell {
  display: grid;
  gap: 8px;
  padding: 16px;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.74);
  border: 1px solid rgba(108, 133, 170, 0.14);
}

.matrix-cell strong {
  font-family: "Sora", "Segoe UI", sans-serif;
  font-size: clamp(1.7rem, 3vw, 2.4rem);
  line-height: 0.95;
  letter-spacing: -0.05em;
}

.matrix-cell.tone-ok {
  color: var(--accent-deep);
}

.matrix-cell.tone-warn {
  color: var(--warn-ink);
}

.matrix-cell.tone-danger {
  color: var(--danger-ink);
}

.histogram {
  display: grid;
  grid-template-columns: repeat(10, minmax(0, 1fr));
  gap: 10px;
  align-items: end;
  min-height: 280px;
}

.histogram-bar-group {
  display: grid;
  gap: 10px;
  align-items: end;
  justify-items: center;
}

.histogram-bar-stack {
  display: flex;
  flex-direction: column-reverse;
  justify-content: end;
  width: 100%;
  height: 220px;
  overflow: hidden;
  border-radius: 14px;
  background: rgba(30, 64, 175, 0.06);
}

.histogram-segment {
  display: block;
  width: 100%;
  min-height: 0;
  transition: height 220ms var(--ease-out-quart);
}

.histogram-segment.legit {
  background: rgba(16, 185, 129, 0.65);
}

.histogram-segment.phish {
  background: rgba(220, 38, 38, 0.72);
}

.histogram-label {
  font-size: 0.82rem;
  font-weight: 700;
  color: var(--text-soft);
}

.mini-bars,
.error-summary {
  display: grid;
  gap: 12px;
}

.mini-bar-row {
  display: grid;
  grid-template-columns: minmax(92px, 120px) minmax(0, 1fr) auto;
  gap: 12px;
  align-items: center;
}

.mini-bar-track {
  overflow: hidden;
  height: 10px;
  border-radius: 999px;
  background: rgba(30, 64, 175, 0.07);
}

.mini-bar-fill {
  display: block;
  height: 100%;
  border-radius: inherit;
}

.mini-bar-fill.primary {
  background: linear-gradient(90deg, var(--primary), oklch(0.46 0.11 248));
}

.error-row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: start;
  padding: 12px 14px;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.74);
  border: 1px solid rgba(108, 133, 170, 0.12);
}

.table-wrap {
  overflow-x: auto;
}

.report-table {
  width: 100%;
  border-collapse: collapse;
}

.report-table th,
.report-table td {
  padding: 12px 10px;
  text-align: left;
  border-bottom: 1px solid rgba(108, 133, 170, 0.14);
  vertical-align: top;
}

.report-table th {
  color: var(--text-soft);
  font-size: 0.86rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.table-url {
  min-width: 260px;
  word-break: break-word;
}

.table-url small,
.table-empty {
  color: var(--text-soft);
}

.empty-state {
  padding: 14px 0;
  color: var(--text-soft);
}

@keyframes scan-pulse {
  0%,
  100% {
    transform: translateY(0) scale(1);
  }
  50% {
    transform: translateY(0) scale(1.015);
  }
}

@keyframes scan-sheen {
  from {
    transform: translateX(-130%);
  }
  to {
    transform: translateX(130%);
  }
}

@keyframes status-scan {
  from {
    transform: translateX(-130%);
  }
  to {
    transform: translateX(430%);
  }
}

@keyframes status-in {
  from {
    transform: translateY(2px);
    opacity: 0.75;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

@media (max-width: 860px) {
  .page-header,
  .evaluation-stage,
  .ml-stage,
  .ml-overview-grid,
  .evaluation-grid,
  .ml-grid,
  .report-two-up,
  .summary-metric-grid,
  .kpi-grid,
  .ml-settings-grid,
  .compact-grid {
    grid-template-columns: 1fr;
  }

  .topnav {
    justify-content: start;
  }

  form {
    grid-template-columns: 1fr;
  }

  .evaluation-form {
    grid-template-columns: 1fr;
  }

  .probe-form {
    grid-template-columns: 1fr;
  }

  .summary-header,
  .summary-grid,
  .signal-grid,
  .meta-grid {
    grid-template-columns: 1fr;
  }

  .progress-meta,
  .check-copy,
  .recent-row,
  .error-row {
    grid-template-columns: 1fr;
    flex-direction: column;
    align-items: start;
  }

  .histogram {
    grid-template-columns: repeat(5, minmax(0, 1fr));
  }

  .mini-bar-row {
    grid-template-columns: 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  form.is-scanning button[type="submit"],
  form.is-scanning button[type="submit"]::after,
  #status.status-loading::before,
  #status.status-swap {
    animation: none;
  }

  button:hover,
  button:active {
    transform: none;
  }

  .nav-link:hover,
  .button-link:hover {
    transform: none;
  }

  button,
  .card,
  input,
  .progress-fill,
  .histogram-segment {
    transition-duration: 120ms;
  }
}

/* Mission Control refresh */

:root {
  --bg: oklch(0.978 0.006 240);
  --bg-strong: oklch(0.948 0.018 237);
  --surface: rgba(255, 255, 255, 0.84);
  --surface-2: rgba(244, 247, 251, 0.94);
  --surface-3: rgba(232, 238, 246, 0.96);
  --text: oklch(0.24 0.024 250);
  --text-soft: oklch(0.42 0.022 245);
  --text-subtle: oklch(0.56 0.018 242);
  --line: rgba(112, 132, 163, 0.18);
  --line-strong: rgba(87, 112, 148, 0.3);
  --primary: oklch(0.42 0.08 253);
  --primary-strong: oklch(0.3 0.055 252);
  --accent: oklch(0.62 0.11 171);
  --accent-deep: oklch(0.42 0.08 176);
  --signal: oklch(0.71 0.07 42);
  --signal-ink: oklch(0.41 0.05 34);
  --signal-soft: oklch(0.95 0.02 42);
  --danger: oklch(0.58 0.16 28);
  --danger-ink: oklch(0.37 0.08 24);
  --shadow-soft: 0 14px 34px rgba(29, 51, 84, 0.08);
  --shadow-strong: 0 20px 48px rgba(17, 32, 61, 0.14);
  --chart-primary: rgba(34, 96, 201, 0.84);
  --chart-success: rgba(23, 156, 107, 0.78);
  --chart-danger: rgba(201, 69, 69, 0.76);
  --chart-text: #334155;
  --chart-text-soft: #64748b;
  --chart-grid: rgba(133, 153, 186, 0.18);
}

body {
  position: relative;
  font-family: "Instrument Sans", "Segoe UI", sans-serif;
  background:
    radial-gradient(circle at top left, rgba(43, 91, 187, 0.11), transparent 30%),
    radial-gradient(circle at 85% 10%, rgba(31, 151, 114, 0.08), transparent 24%),
    linear-gradient(180deg, rgba(235, 242, 250, 0.98) 0%, rgba(246, 249, 252, 0.98) 48%, rgba(240, 245, 250, 0.98) 100%);
}

body::before,
body::after {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
}

body::before {
  background-image:
    linear-gradient(rgba(87, 112, 148, 0.045) 1px, transparent 1px),
    linear-gradient(90deg, rgba(87, 112, 148, 0.045) 1px, transparent 1px);
  background-size: 120px 120px;
  mask-image: linear-gradient(180deg, rgba(0, 0, 0, 0.8), transparent 85%);
}

body::after {
  inset: 18px;
  border: 1px solid rgba(255, 255, 255, 0.5);
  border-radius: 28px;
}

.container {
  position: relative;
  z-index: 1;
  max-width: 1240px;
  padding: clamp(24px, 4vw, 44px) 20px 72px;
}

h1,
h2,
.file-drop-title,
.panel-subheader h3,
.kpi-value,
.summary-metric-value,
.matrix-cell strong,
.risk-value {
  font-family: "Archivo", "Segoe UI", sans-serif;
}

h1 {
  max-width: 11ch;
  margin-bottom: 12px;
  font-size: clamp(3rem, 6vw, 5.15rem);
  line-height: 0.92;
  color: var(--primary-strong);
}

h2 {
  font-size: clamp(1.45rem, 2vw, 2rem);
}

.hint {
  max-width: 62ch;
  margin-bottom: 0;
  line-height: 1.55;
}

.page-header {
  position: relative;
  grid-template-columns: minmax(0, 1.2fr) minmax(280px, auto);
  gap: 24px;
  margin-bottom: 22px;
  padding: clamp(22px, 3vw, 34px);
  border-radius: 28px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.56), rgba(255, 255, 255, 0.18)),
    radial-gradient(circle at top right, rgba(43, 91, 187, 0.08), transparent 28%);
  border: 1px solid rgba(255, 255, 255, 0.44);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.35);
}

.page-header::after {
  content: "";
  position: absolute;
  left: clamp(22px, 3vw, 34px);
  right: clamp(22px, 3vw, 34px);
  bottom: 0;
  height: 1px;
  background: linear-gradient(90deg, rgba(58, 88, 142, 0.28), rgba(58, 88, 142, 0.02));
}

.eyebrow {
  margin-bottom: 10px;
  color: color-mix(in oklab, var(--text-subtle) 80%, var(--primary) 20%);
}

.topnav {
  display: grid;
  align-content: start;
  justify-content: end;
  gap: 12px;
  padding-top: 6px;
}

.nav-link,
.button-link {
  min-height: 44px;
  padding: 0 18px;
  border-radius: 999px;
  color: var(--primary-strong);
  background: rgba(255, 255, 255, 0.76);
  border: 1px solid rgba(109, 130, 162, 0.18);
  box-shadow: none;
}

.nav-link:hover,
.button-link:hover {
  background: rgba(255, 255, 255, 0.96);
  box-shadow: 0 10px 18px rgba(22, 38, 68, 0.06);
}

.nav-link.is-active,
.tab-button.is-active {
  color: oklch(0.98 0.004 250);
  background: linear-gradient(135deg, var(--primary-strong) 0%, var(--primary) 100%);
  box-shadow: 0 14px 28px rgba(32, 60, 112, 0.18);
}

.card,
.current-url-card,
.check-runner-card,
.recent-stream-card,
.report-card,
.kpi-card,
.summary-metric-card,
.signal-card,
.meta-card,
.matrix-cell {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.86), rgba(247, 249, 252, 0.92));
  border: 1px solid var(--line);
  box-shadow: var(--shadow-soft);
}

.card {
  border-radius: 26px;
}

#scan-form.command-bar,
.evaluation-form,
.ml-form,
.probe-form {
  position: relative;
  margin: 0 0 18px;
  padding: 14px;
  border-radius: 28px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.82), rgba(245, 248, 252, 0.94));
  border: 1px solid rgba(110, 131, 163, 0.16);
  backdrop-filter: blur(10px);
  box-shadow: var(--shadow-soft);
}

#scan-form.command-bar {
  grid-template-columns: minmax(0, 1fr) auto auto;
}

input,
select {
  min-height: 52px;
  border-radius: 18px;
  border-color: rgba(109, 130, 162, 0.22);
  background: rgba(255, 255, 255, 0.88);
}

input:focus,
select:focus {
  border-color: rgba(54, 94, 180, 0.38);
  box-shadow: 0 0 0 4px rgba(54, 94, 180, 0.1);
}

button {
  min-height: 52px;
  border-radius: 18px;
  background: linear-gradient(135deg, var(--primary-strong) 0%, var(--primary) 100%);
  box-shadow: 0 14px 28px rgba(32, 60, 112, 0.18);
}

#refresh-feeds,
.tab-button {
  color: var(--primary-strong);
  background: rgba(255, 255, 255, 0.92);
  box-shadow: none;
}

#status,
#eval-status,
#ml-status {
  position: relative;
  min-height: 72px;
  display: flex;
  align-items: center;
  padding: 18px 22px;
  border-radius: 22px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.8), rgba(243, 247, 251, 0.92));
}

#status::before,
#eval-status::before,
#ml-status::before {
  left: 22px;
  width: 120px;
  opacity: 0.8;
}

.summary-panel {
  --risk-angle: 0deg;
  --hero-start: oklch(0.31 0.04 252);
  --hero-end: oklch(0.22 0.025 247);
  --hero-ink: oklch(0.98 0.004 250);
  padding: clamp(24px, 3vw, 34px);
  border-radius: 30px;
  background:
    linear-gradient(180deg, rgba(246, 249, 253, 0.92), rgba(239, 244, 250, 0.96));
}

.summary-panel[data-tone="ok"] {
  --hero-start: oklch(0.34 0.055 191);
  --hero-end: oklch(0.25 0.03 218);
}

.summary-panel[data-tone="caution"] {
  --hero-start: oklch(0.62 0.09 95);
  --hero-end: oklch(0.35 0.05 75);
}

.summary-panel[data-tone="warn"] {
  --hero-start: oklch(0.55 0.12 73);
  --hero-end: oklch(0.34 0.055 54);
}

.summary-panel[data-tone="danger"] {
  --hero-start: oklch(0.53 0.15 28);
  --hero-end: oklch(0.31 0.06 22);
}

.summary-header {
  margin-bottom: 22px;
}

.summary-grid {
  align-items: stretch;
  grid-template-columns: minmax(320px, 0.92fr) minmax(0, 1.08fr);
  gap: 20px;
}

.risk-hero {
  gap: 18px;
  padding: clamp(22px, 3vw, 30px);
  border-radius: 28px;
  background:
    radial-gradient(circle at top left, rgba(255, 255, 255, 0.14), transparent 30%),
    linear-gradient(160deg, var(--hero-start) 0%, var(--hero-end) 100%);
}

.risk-meter {
  position: relative;
  display: grid;
  place-items: center;
  width: min(100%, 260px);
  aspect-ratio: 1;
}

.risk-meter::before {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: 50%;
  background:
    conic-gradient(from -90deg, rgba(255, 255, 255, 0.92) 0deg, rgba(255, 255, 255, 0.92) var(--risk-angle), rgba(255, 255, 255, 0.14) var(--risk-angle), rgba(255, 255, 255, 0.14) 360deg);
  mask: radial-gradient(circle, transparent 61%, black 63%);
}

.risk-meter::after {
  content: "";
  position: absolute;
  inset: 12%;
  border-radius: 50%;
  background:
    radial-gradient(circle at top, rgba(255, 255, 255, 0.16), transparent 52%),
    rgba(7, 14, 29, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.16);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.16);
}

.risk-meter-core {
  position: relative;
  z-index: 1;
  display: grid;
  justify-items: center;
  gap: 10px;
  text-align: center;
}

.risk-hero .metric-label,
.risk-hero .risk-value,
.risk-hero .risk-band,
.risk-hero .risk-url {
  color: var(--hero-ink);
}

.risk-hero .metric-label {
  opacity: 0.72;
}

.risk-value {
  font-size: clamp(4rem, 8vw, 5.9rem);
}

.risk-hero-copy {
  display: grid;
  gap: 10px;
}

.risk-band {
  min-height: 36px;
  padding-inline: 14px;
  background: rgba(255, 255, 255, 0.12);
}

.signal-grid,
.meta-grid,
.summary-metric-grid {
  gap: 12px;
}

.signal-card,
.meta-card,
.report-card,
.current-url-card,
.check-runner-card,
.recent-stream-card {
  border-radius: 20px;
  padding: 18px;
}

.signal-card,
.meta-card {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.66), rgba(245, 248, 252, 0.84));
}

.analysis-card::before {
  width: 3px;
  background: rgba(54, 94, 180, 0.28);
}

.token,
.status-pill {
  min-height: 34px;
  border: 1px solid rgba(111, 132, 163, 0.14);
}

.meta-grid {
  margin-top: 18px;
}

.evaluation-stage,
.ml-stage {
  position: relative;
  align-items: start;
  padding: clamp(24px, 3vw, 34px);
  border-radius: 30px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.82), rgba(242, 247, 251, 0.94));
}

.evaluation-stage {
  grid-template-columns: minmax(0, 0.95fr) minmax(430px, 1.05fr);
}

.ml-stage {
  grid-template-columns: minmax(0, 0.9fr) minmax(420px, 1.1fr);
}

.file-drop-zone {
  min-height: 148px;
  border-radius: 22px;
  border-color: rgba(54, 94, 180, 0.18);
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.7), rgba(242, 247, 251, 0.86)),
    radial-gradient(circle at top right, rgba(54, 94, 180, 0.05), transparent 26%);
}

.kpi-grid,
.summary-metric-grid,
.report-two-up,
.ml-overview-grid,
.evaluation-grid,
.ml-grid {
  gap: 16px;
}

.kpi-card,
.summary-metric-card {
  border-radius: 18px;
}

.tab-row {
  padding: 6px;
  border-radius: 999px;
  background: rgba(227, 234, 242, 0.78);
}

.tab-button {
  min-height: 40px;
  border-radius: 999px;
}

.progress-meter,
.mini-bar-track {
  background: rgba(44, 73, 126, 0.08);
}

.progress-fill,
.mini-bar-fill.primary {
  background: linear-gradient(90deg, var(--primary-strong), var(--accent));
}

.active-model-card,
.probe-card,
.progress-panel,
.report-shell {
  border-radius: 28px;
  padding: clamp(22px, 3vw, 30px);
}

.probe-form {
  margin-top: 0;
}

.recent-row,
.error-row,
.check-item {
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.72);
}

.chart-card {
  min-height: 340px;
}

#details {
  padding: 22px;
  border-radius: 28px;
}

pre {
  border-radius: 22px;
  background:
    linear-gradient(180deg, rgba(23, 31, 48, 0.98), rgba(15, 23, 39, 0.98));
}

@media (min-width: 981px) {
  .progress-panel {
    position: sticky;
    top: 24px;
  }
}

@media (max-width: 980px) {
  body::after {
    inset: 12px;
    border-radius: 22px;
  }

  .page-header,
  .evaluation-stage,
  .ml-stage,
  .ml-overview-grid,
  .evaluation-grid,
  .ml-grid,
  .report-two-up,
  .summary-grid {
    grid-template-columns: 1fr;
  }

  .topnav {
    justify-content: start;
  }

  .summary-grid {
    gap: 16px;
  }

  .risk-meter {
    width: min(100%, 220px);
  }
}

@media (max-width: 720px) {
  .container {
    padding-inline: 14px;
  }

  .page-header,
  .evaluation-stage,
  .ml-stage,
  .summary-panel,
  .active-model-card,
  .probe-card,
  .progress-panel,
  .report-shell,
  .card {
    border-radius: 22px;
  }

  .topnav {
    grid-auto-flow: row;
  }

  .nav-link,
  .button-link,
  .tab-button {
    width: 100%;
  }

  #scan-form.command-bar,
  .evaluation-form,
  .ml-form,
  .probe-form,
  .summary-header,
  .signal-grid,
  .meta-grid,
  .summary-metric-grid,
  .kpi-grid,
  .compact-grid,
  .ml-settings-grid {
    grid-template-columns: 1fr;
  }

  .tab-row {
    display: grid;
    border-radius: 20px;
  }

  .risk-value {
    font-size: clamp(3.1rem, 18vw, 4.5rem);
  }
}

@media (prefers-reduced-motion: reduce) {
  body::before {
    display: none;
  }

  .page-header,
  .card,
  .nav-link,
  .button-link,
  .signal-card,
  .meta-card,
  .report-card,
  .current-url-card,
  .check-runner-card,
  .recent-stream-card {
    transition: none;
  }
}

body.page-scan,
body.page-eval,
body.page-ml {
  --scan-accent: var(--signal);
  --scan-accent-soft: var(--signal-soft);
}

body.page-scan[data-risk-tone="ok"],
body.page-eval[data-risk-tone="ok"],
body.page-ml[data-risk-tone="ok"] {
  --scan-accent: var(--accent);
  --scan-accent-soft: color-mix(in oklab, var(--accent) 16%, white 84%);
}

body.page-scan[data-risk-tone="caution"],
body.page-eval[data-risk-tone="caution"],
body.page-ml[data-risk-tone="caution"] {
  --scan-accent: var(--caution);
  --scan-accent-soft: color-mix(in oklab, var(--caution) 18%, white 82%);
}

body.page-scan[data-risk-tone="warn"],
body.page-eval[data-risk-tone="warn"],
body.page-ml[data-risk-tone="warn"] {
  --scan-accent: var(--warn);
  --scan-accent-soft: color-mix(in oklab, var(--warn) 18%, white 82%);
}

body.page-scan[data-risk-tone="danger"],
body.page-eval[data-risk-tone="danger"],
body.page-ml[data-risk-tone="danger"] {
  --scan-accent: var(--danger);
  --scan-accent-soft: color-mix(in oklab, var(--danger) 14%, white 86%);
}

.page-scan .page-scan-hero,
.page-eval .page-eval-hero,
.page-ml .page-ml-hero {
  grid-template-columns: minmax(0, 1.14fr) minmax(300px, 0.86fr);
  overflow: hidden;
}

.page-scan .page-scan-hero::before,
.page-eval .page-eval-hero::before,
.page-ml .page-ml-hero::before {
  content: "";
  position: absolute;
  inset: auto -7% -18% 48%;
  height: 260px;
  border-radius: 50%;
  background: radial-gradient(circle, color-mix(in oklab, var(--scan-accent) 22%, white 78%) 0%, transparent 68%);
  transform: rotate(-10deg);
  pointer-events: none;
}

.page-scan .page-header-copy,
.page-scan .page-header-aside,
.page-eval .page-header-copy,
.page-eval .page-header-aside,
.page-ml .page-header-copy,
.page-ml .page-header-aside {
  position: relative;
  z-index: 1;
}

.page-scan .page-header-copy,
.page-eval .page-header-copy,
.page-ml .page-header-copy {
  max-width: 70ch;
}

.page-scan .page-header-copy .hint + .hint,
.page-eval .page-header-copy .hint + .hint,
.page-ml .page-header-copy .hint + .hint {
  margin-top: 8px;
}

.page-scan .page-header-aside,
.page-eval .page-header-aside,
.page-ml .page-header-aside {
  display: grid;
  gap: 14px;
  align-content: start;
}

.page-scan .topnav,
.page-eval .topnav,
.page-ml .topnav {
  display: inline-flex;
  flex-wrap: wrap;
  justify-content: flex-start;
  gap: 10px;
  padding-top: 0;
}

.page-scan .nav-link,
.page-eval .nav-link,
.page-ml .nav-link {
  min-height: 42px;
}

.hero-chip-row,
.scan-lens-grid,
.quick-intel-row {
  display: flex;
  flex-wrap: wrap;
}

.hero-chip-row {
  gap: 10px;
  margin-top: 22px;
}

.hero-chip,
.lens-pill,
.quick-intel-pill {
  display: inline-flex;
  align-items: center;
  min-height: 34px;
  padding: 0 12px;
  border-radius: 999px;
  font-size: 0.9rem;
  font-weight: 700;
  letter-spacing: 0.01em;
}

.hero-chip {
  color: var(--primary-strong);
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(109, 130, 162, 0.16);
}

.hero-chip-signal {
  color: var(--signal-ink);
  background: color-mix(in oklab, var(--scan-accent) 14%, white 86%);
  border-color: color-mix(in oklab, var(--scan-accent) 28%, white 72%);
}

.scan-lens {
  display: grid;
  gap: 12px;
  padding: 18px;
  border-radius: 22px;
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.78), rgba(246, 249, 252, 0.9)),
    radial-gradient(circle at top right, color-mix(in oklab, var(--scan-accent) 10%, white 90%), transparent 32%);
  border: 1px solid rgba(109, 130, 162, 0.16);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.42);
}

.scan-lens-label {
  margin: 0;
  font-size: 0.78rem;
  font-weight: 800;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: color-mix(in oklab, var(--text-soft) 82%, var(--scan-accent) 18%);
}

.scan-lens-grid {
  gap: 8px;
}

.lens-pill {
  color: var(--text);
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(109, 130, 162, 0.14);
}

.scan-lens-note {
  margin: 0;
  font-size: 0.93rem;
  line-height: 1.5;
  color: var(--text-soft);
}

.page-scan #scan-form.command-bar {
  grid-template-columns: minmax(0, 1fr) auto auto;
  gap: 12px;
  margin-bottom: 12px;
}

.command-input-shell {
  display: grid;
  gap: 8px;
  align-content: start;
}

.command-input-shell input {
  width: 100%;
}

.command-footnote {
  font-size: 0.88rem;
  line-height: 1.45;
  color: var(--text-soft);
}

.quick-intel-row {
  gap: 10px;
  align-items: center;
  margin: 0 0 18px;
  padding: 0 2px;
}

.scan-helper-row {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
  margin: 0 0 18px;
  padding: 0 2px;
}

.quick-intel-label {
  font-size: 0.88rem;
  font-weight: 800;
  letter-spacing: 0.01em;
  color: var(--text-soft);
}

.quick-intel-pill {
  color: color-mix(in oklab, var(--text) 82%, var(--scan-accent) 18%);
  background: rgba(255, 255, 255, 0.62);
  border: 1px solid rgba(109, 130, 162, 0.16);
}

.helper-link {
  display: inline-flex;
  align-items: center;
  min-height: 36px;
  padding: 0 14px;
  border-radius: 999px;
  color: var(--primary-strong);
  text-decoration: none;
  font-weight: 700;
  background: rgba(255, 255, 255, 0.74);
  border: 1px solid rgba(109, 130, 162, 0.18);
  transition:
    transform 180ms var(--ease-out-quart),
    border-color 180ms var(--ease-out-quart),
    background-color 180ms var(--ease-out-quart),
    box-shadow 180ms var(--ease-out-quart);
}

.helper-link:hover {
  transform: translateY(-1px);
  border-color: rgba(54, 94, 180, 0.26);
  background: rgba(255, 255, 255, 0.9);
  box-shadow: 0 10px 24px rgba(32, 60, 112, 0.08);
}

.helper-link:focus-visible {
  outline: none;
  box-shadow:
    0 0 0 4px rgba(54, 94, 180, 0.1),
    0 10px 24px rgba(32, 60, 112, 0.08);
}

input:disabled,
select:disabled {
  color: var(--text-soft);
  background: rgba(238, 243, 249, 0.88);
}

button[aria-busy="true"] {
  filter: saturate(0.95);
}

.status-panel {
  min-height: 0;
}

.status-shell {
  display: grid;
  gap: 6px;
}

.status-eyebrow {
  margin-bottom: 0;
}

.status-message {
  margin: 0;
  font-family: "Archivo", "Segoe UI", sans-serif;
  font-size: clamp(1.18rem, 2vw, 1.42rem);
  line-height: 1.02;
  letter-spacing: -0.03em;
}

.status-detail {
  max-width: 72ch;
  margin: 0;
  line-height: 1.5;
  color: var(--text-soft);
}

.runtime-note {
  display: block;
  margin-top: 6px;
  color: var(--text-soft);
  line-height: 1.45;
}

.page-scan #status::before,
.page-eval #eval-status::before,
.page-ml #ml-status::before {
  width: 150px;
  opacity: 0.9;
  background: linear-gradient(90deg, var(--primary), var(--scan-accent), var(--accent));
}

.page-scan .summary-panel,
.page-scan #details,
.page-eval .progress-panel,
.page-eval .report-shell,
.page-ml .active-model-card,
.page-ml .probe-card,
.page-ml .progress-panel,
.page-ml .report-shell {
  position: relative;
  overflow: hidden;
}

.page-scan .summary-panel::after,
.page-scan #details::after,
.page-eval .progress-panel::after,
.page-eval .report-shell::after,
.page-ml .active-model-card::after,
.page-ml .probe-card::after,
.page-ml .progress-panel::after,
.page-ml .report-shell::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: radial-gradient(circle at top right, color-mix(in oklab, var(--scan-accent) 10%, transparent 90%), transparent 32%);
}

.panel-enter {
  animation: panel-enter 420ms var(--ease-out-expo);
}

@keyframes panel-enter {
  from {
    opacity: 0.7;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (max-width: 980px) {
  .page-scan .page-scan-hero,
  .page-eval .page-eval-hero,
  .page-ml .page-ml-hero {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 720px) {
  .page-scan .hero-chip-row,
  .page-scan .scan-lens-grid,
  .page-scan .quick-intel-row,
  .page-scan .scan-helper-row,
  .page-eval .hero-chip-row,
  .page-eval .scan-lens-grid,
  .page-eval .quick-intel-row,
  .page-eval .scan-helper-row,
  .page-ml .hero-chip-row,
  .page-ml .scan-lens-grid,
  .page-ml .quick-intel-row {
    gap: 8px;
  }

  .page-scan .page-header-aside,
  .page-eval .page-header-aside,
  .page-ml .page-header-aside {
    gap: 12px;
  }

  .page-scan #scan-form.command-bar {
    grid-template-columns: 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  .panel-enter {
    animation: none;
  }
}

.page-ml {
  font-family: "Instrument Sans", "Segoe UI", sans-serif;
}

.page-ml h1,
.page-ml h2,
.page-ml .panel-subheader h3,
.page-ml .file-drop-title,
.page-ml .kpi-value,
.page-ml .summary-metric-value,
.page-ml .matrix-cell strong {
  font-family: "Work Sans", "Segoe UI", sans-serif;
}

.page-ml .container {
  max-width: 1320px;
}

.page-ml .page-header {
  grid-template-columns: minmax(0, 1.25fr) auto;
  align-items: start;
  gap: 20px;
  margin-bottom: 18px;
  padding: clamp(18px, 2.5vw, 28px) clamp(20px, 3vw, 34px);
}

.page-ml .page-header > div:first-child {
  max-width: 78ch;
}

.page-ml h1 {
  max-width: none;
  margin: 0 0 8px;
  font-size: clamp(2.35rem, 3.9vw, 3.7rem);
  line-height: 0.96;
  letter-spacing: -0.055em;
}

.page-ml h2 {
  font-size: clamp(1.3rem, 1.9vw, 1.72rem);
  line-height: 1.05;
  letter-spacing: -0.04em;
}

.page-ml .hint {
  max-width: 72ch;
  font-size: 0.98rem;
  line-height: 1.6;
  color: color-mix(in oklab, var(--text-soft) 90%, white 10%);
}

.page-ml .eyebrow {
  margin-bottom: 8px;
  font-size: 0.76rem;
  letter-spacing: 0.16em;
}

.page-ml .topnav {
  display: inline-flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 10px;
  padding-top: 2px;
}

.page-ml .nav-link {
  min-height: 40px;
  padding: 0 15px;
  font-size: 0.96rem;
}

.page-ml .ml-stage,
.page-ml .active-model-card,
.page-ml .probe-card,
.page-ml .progress-panel,
.page-ml .report-shell {
  padding: clamp(20px, 2.4vw, 28px);
}

.page-ml .ml-stage {
  grid-template-columns: minmax(320px, 0.8fr) minmax(0, 1.2fr);
  gap: 18px;
}

.page-ml .ml-stage-copy {
  gap: 8px;
  max-width: 48ch;
}

.page-ml .ml-form {
  gap: 14px;
  padding: 16px;
  border-radius: 24px;
}

.page-ml .ml-form-section {
  gap: 10px;
}

.page-ml .file-drop-zone {
  min-height: 124px;
  padding: 16px;
}

.page-ml .file-drop-title {
  font-size: 0.98rem;
  letter-spacing: -0.02em;
}

.page-ml .file-drop-subtitle,
.page-ml .field-label,
.page-ml .toggle-row {
  font-size: 0.92rem;
}

.page-ml .field-label {
  color: var(--text-soft);
}

.page-ml .advanced-settings {
  gap: 12px;
  padding: 14px 16px;
}

.page-ml .advanced-settings .hint {
  margin: 0;
}

.page-ml input,
.page-ml select,
.page-ml button {
  font-size: 0.97rem;
}

.page-ml .toggle-row {
  line-height: 1.4;
}

.page-ml .summary-state,
.page-ml .status-pill,
.page-ml .token {
  font-size: 0.86rem;
  letter-spacing: 0.01em;
}

.page-ml .panel-header {
  margin-bottom: 14px;
}

.page-ml .panel-subheader {
  align-items: baseline;
  margin-bottom: 12px;
}

.page-ml .panel-subheader h3 {
  font-size: 0.98rem;
  line-height: 1.15;
  letter-spacing: -0.02em;
}

.page-ml .summary-metric-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.page-ml .ml-overview-grid {
  grid-template-columns: minmax(0, 1.22fr) minmax(300px, 0.78fr);
}

.page-ml .summary-metric-card,
.page-ml .kpi-card {
  gap: 8px;
  padding: 14px 16px;
}

.page-ml .metric-label {
  font-size: 0.72rem;
  letter-spacing: 0.14em;
}

.page-ml .summary-metric-value {
  font-size: clamp(1.35rem, 2.2vw, 2rem);
  letter-spacing: -0.045em;
}

.page-ml .metric-meta {
  font-size: 0.8rem;
  line-height: 1.45;
  color: var(--text-soft);
}

.page-ml .metric-card-text,
.page-ml .metric-card-time {
  align-content: start;
  min-height: 110px;
}

.page-ml .metric-card-text .summary-metric-value {
  font-size: clamp(1rem, 1.25vw, 1.22rem);
  line-height: 1.15;
  letter-spacing: -0.03em;
  overflow-wrap: anywhere;
}

.page-ml .metric-card-time .summary-metric-value {
  font-size: clamp(0.96rem, 1.14vw, 1.12rem);
  line-height: 1.18;
  letter-spacing: -0.025em;
  overflow-wrap: anywhere;
}

.page-ml .kpi-value {
  font-size: clamp(1.5rem, 2.5vw, 2.15rem);
}

.page-ml #active-model-metrics {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.page-ml #active-model-analytics {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.page-ml #active-model-analytics .summary-metric-card:last-child {
  grid-column: 1 / -1;
}

.page-ml .progress-meta,
.page-ml .recent-row span:not(.status-pill),
.page-ml .check-copy span {
  font-size: 0.9rem;
}

.page-ml .current-url-card strong {
  margin-top: 8px;
  font-size: 0.96rem;
  line-height: 1.45;
}

.page-ml .check-item,
.page-ml .recent-row,
.page-ml .error-row {
  padding: 11px 13px;
}

.page-ml .check-copy strong {
  font-size: 0.94rem;
}

.page-ml .tab-row {
  display: inline-flex;
  flex-wrap: nowrap;
  margin: 2px 0 16px;
  overflow-x: auto;
  overscroll-behavior-x: contain;
  padding-bottom: 4px;
}

.page-ml .tab-button {
  min-height: 38px;
  padding: 0 13px;
  font-size: 0.9rem;
  flex: 0 0 auto;
}

.page-ml .mini-bar-row {
  grid-template-columns: minmax(110px, 132px) minmax(0, 1fr) auto;
}

.page-ml .mini-bar-row span,
.page-ml .mini-bar-row strong {
  font-size: 0.9rem;
}

.page-ml .probe-form {
  margin-top: 0;
}

.page-ml .probe-result .hint {
  font-size: 0.92rem;
}

.page-ml .chart-card {
  min-height: 300px;
}

.page-ml .report-chart-grid {
  margin-bottom: 14px;
}

.page-ml .chart-card canvas {
  height: 240px !important;
}

.page-ml .artifact-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.page-ml .artifact-card {
  display: grid;
  gap: 6px;
  padding: 14px 15px;
  border: 1px solid color-mix(in srgb, var(--border) 78%, var(--brand-primary) 22%);
  border-radius: 18px;
  background:
    linear-gradient(180deg, color-mix(in srgb, var(--surface) 92%, var(--brand-primary) 8%), var(--surface-raised)),
    var(--surface);
}

.page-ml .artifact-card strong {
  font-size: 0.96rem;
  line-height: 1.45;
  overflow-wrap: anywhere;
}

.page-ml .report-card,
.page-ml .current-url-card,
.page-ml .check-runner-card,
.page-ml .recent-stream-card {
  padding: 16px;
}

.page-ml .empty-state {
  font-size: 0.94rem;
}

.page-ml .compare-table td strong {
  display: block;
  font-size: 0.96rem;
  line-height: 1.3;
}

.page-ml .compare-table td small {
  display: block;
  margin-top: 4px;
  color: var(--text-soft);
  line-height: 1.4;
}

.page-ml .compare-feature-cell {
  min-width: 220px;
}

@media (min-width: 981px) {
  .page-ml .progress-panel {
    top: 16px;
  }
}

@media (max-width: 980px) {
  .page-ml .page-header,
  .page-ml .ml-stage,
  .page-ml .ml-overview-grid,
  .page-ml .ml-grid,
  .page-ml .report-two-up,
  .page-ml .artifact-grid,
  .page-ml .summary-metric-grid,
  .page-ml .kpi-grid,
  .page-ml .compact-grid,
  .page-ml .ml-settings-grid {
    grid-template-columns: 1fr;
  }

  .page-ml .topnav {
    justify-content: flex-start;
  }

  .page-ml #active-model-analytics .summary-metric-card:last-child {
    grid-column: auto;
  }
}

@media (max-width: 720px) {
  .page-ml .page-header {
    padding: 18px;
  }

  .page-ml h1 {
    font-size: clamp(2rem, 11vw, 2.7rem);
  }

  .page-ml .hint {
    font-size: 0.94rem;
  }

  .page-ml .nav-link,
  .page-ml .tab-button {
    width: auto;
    min-width: max-content;
  }

  .page-ml .topnav,
  .page-ml .tab-row {
    display: flex;
  }
}

.summary-grid-secondary {
  margin-top: 14px;
}

.two-column-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
  margin-top: 16px;
}

.inner-card {
  margin-top: 0;
  padding: 16px;
}

.table-shell {
  overflow-x: auto;
  border: 1px solid rgba(128, 150, 190, 0.15);
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.72);
}

.data-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.95rem;
}

.data-table th,
.data-table td {
  padding: 12px 14px;
  border-bottom: 1px solid rgba(128, 150, 190, 0.12);
  text-align: left;
  vertical-align: top;
}

.data-table th {
  font-size: 0.82rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-subtle);
  background: rgba(245, 248, 252, 0.92);
}

.data-table tr:last-child td {
  border-bottom: 0;
}

.table-url {
  max-width: 42ch;
  word-break: break-word;
}

.command-bar-stack {
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr) auto;
  align-items: end;
}

.command-bar-stack .command-input-shell {
  min-width: 0;
}

.command-bar-stack input[type="number"] {
  width: 100%;
}

.panel-footer {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 12px;
  margin-top: 16px;
}

.two-column-grid .token-list {
  min-height: 72px;
}

@media (max-width: 900px) {
  .two-column-grid,
  .command-bar-stack {
    grid-template-columns: 1fr;
  }
}

