def test_fasttext_serializer_uses_plain_text_only(): snapshot = { "content": { "page_title": "Netflix Sign In", "visible_text": "Verify your account", "brand_candidates": [{"matched_phrases": ["sign in"]}], "detected_brand": "Netflix", "host_provider": "vercel", "free_host": True, "login_form_present": True, "password_field_count": 1, "input_field_count": 2, "nav_link_count": 0, "brand_mismatch": True, "brand_path_match": True, "form_action_mismatch": False, "no_navigation_menu": True, "suspicious_phrase_hits": ["verify your account"], } } text = serialize_snapshot(snapshot) assert "Netflix Sign In" in text assert "Verify your account" in text assert "sign in" in text.lower() assert "host_provider=" not in text assert "free_host=" not in text assert "verify your account" in text.lower()
