def test_evaluation_report_includes_threshold_sweep(tmp_path): input_csv = tmp_path / "eval.csv" output_csv = tmp_path / "scored.csv" input_csv.write_text( "url,is_phishing\nhttps://phish.example,1\nhttps://clean.example,0\n", encoding="utf-8", )
def scorer(url, progress_callback=None): del progress_callback score = 40.0 if "phish" in url else 10.0 return { "url": url, "risk_score": score, "prediction": "phishing" if score >= 30.0 else "clean", "verdict": {"status": "ok", "label": "phishing" if score >= 30.0 else "clean", "final_score": score}, "scores": {"final": score, "rules": score, "fasttext": score, "legacy": 0.0, "structured_ml": None}, }
result = evaluate_csv(input_csv=input_csv, output_csv=output_csv, scorer=scorer, threshold=30.0) report = build_report_payload(result)
assert report["summary"]["total_rows"] == 2 assert any(item["threshold"] == 30.0 for item in report["threshold_sweep"]) assert any(item["recall"] >= 0.5 for item in report["threshold_sweep"])
